(function() {
var jdg_ch_1_Verses = [
  {num:1,words:[["Ua mavae le oti o Iosua,", "Now after the death of Joshua it came to pass,"], ["ona fesili ai lea o le fanauga a Isaraelu ia Ieova,", "that the children of Israel asked the LORD,"], ["ua faapea atu,", "saying,"], ["Po o ai e muamua ona alu ae i sa Kananā mo i matou,", "Who shall go up for us against the Canaanites first,"], ["e tau ma i latou?", "to fight against them?"]]},
  {num:2,words:[["Ua fetalai mai Ieova,", "And the LORD said,"], ["E alu ae Iuta;", "Judah shall go up:"], ["faauta,", "behold,"], ["ua ou tuuina atu le nuu i lona lima.", "I have delivered the land into his hand."]]},
  {num:3,words:[["Ona fai atu ai lea o Iuta ia Simeona lona uso,", "And Judah said unto Simeon his brother,"], ["Ia ta o ae ma a'u i lo'u tofi,", "Come up with me into my lot,"], ["ina ia tatou tau ma sa Kanana; o a'u foi,", "that we may fight against the Canaanites;"], ["ta te o ae ma oe i lou tofi.", "and I likewise will go with thee into thy lot."], ["Ona la o ae ai lea ma Simeona.", "So Simeon went with him."]]},
  {num:4,words:[["Ua alu ae foi Iuta,", "And Judah went up;"], ["ona tuuina atu ai lea e Ieova o sa Kananā ma sa Perisē i o latou lima;", "and the LORD delivered the Canaanites and the Perizzites into their hand:"], ["ua latou fasia foi o latou i Piseka e sefulu afe o tagata.", "and they slew of them in Bezek ten thousand men."]]},
  {num:5,words:[["Ua latou maua foi Atonipiseka i Piseka;", "And they found Adoni-bezek in Bezek:"], ["ona latou tau ai lea ma ia;", "and they fought against him,"], ["ua latou fasia foi sa Kananā ma sa Perisē.", "and they slew the Canaanites and the Perizzites."]]},
  {num:6,words:[["A ua sola Atonipiseka;", "But Adoni-bezek fled;"], ["ua latou tuliloa ia te ia,", "and they pursued after him,"], ["ua maua,", "and caught him,"], ["ona latou tipiesea ai lea ona lima matua ma ona vae matua.", "and cut off his thumbs and his great toes."]]},
  {num:7,words:[["Ona fai ane ai lea o Atonipiseka,", "And Adoni-bezek said,"], ["E toafitugafulu tupu ua tipieseina o latou lima matua ma o latou vae matua,", "Threescore and ten kings,"], ["na latou samusamu i lalo o la'u laoai;", "having their thumbs and their great toes cut off, gathered their meat under my table:"], ["e pei ona ou faia,", "as I have done,"], ["e faapea lava ona tauia mai au e le Atua.", "so God hath requited me."], ["Ua latou avea o ia i Ierusalema,", "And they brought him to Jerusalem,"], ["ona oti lea o ia i lea mea.", "and there he died."]]},
  {num:8,words:[["Ua sii foi le taua e le fanauga a Iuta i Ierusalema,", "Now the children of Judah had fought against Jerusalem,"], ["ma ua latou aea,", "and had taken it,"], ["ua latou fasia ai i le pelu,", "and smitten it with the edge of the sword,"], ["ma latou susunuina le aai i le afi.", "and set the city on fire."]]},
  {num:9,words:[["E mulimuli ane foi ua o ifo le fanauga a Iuta e tau ai le taua ma sa Kananā,", "And afterward the children of Judah went down to fight against the Canaanites,"], ["o e sa nonofo i le atu mauga,", "that dwelt in the mountain,"], ["ma le itu i toga,", "and in the south,"], ["ma le nuu maulalo.", "and in the valley."]]},
  {num:10,words:[["Ua alu foi Iuta e tau ma sa Kananā,", "And Judah went against the Canaanites that dwelt in Hebron:"], ["o e sa nonofo i Heperona; (o Kiriata-arapa,", "(now the name of Hebron before was Kirjath-arba:"], ["o le igoa lea anamua o Heperona;", ") and they slew Sheshai,"], [") ua latou fasia foi o Sesai, ma Aimano,", "and Ahiman,"], ["ma Talemai.", "and Talmai."]]},
  {num:11,words:[["Ona o atu lea o i latou ai lea mea e tau ma e sa nonofo i Tiperi; (o Kiriata-sapera,", "And from thence he went against the inhabitants of Debir:"], ["o le igoa lea anamua o Tiperi.)", "and the name of Debir before was Kirjath-sepher:"]]},
  {num:12,words:[["Ona fai atu lea o Kalepo,", "And Caleb said,"], ["O se na te fasia Kiriata-sapera,", "He that smiteth Kirjath-sepher,"], ["ma aea ai,", "and taketh it,"], ["ou te avatu ia te ia o Akesa lo'u afafine e fai mana avā.", "to him will I give Achsah my daughter to wife."]]},
  {num:13,words:[["Ona aea ai lea e Otinielu le atalii o Kinasa,", "And Othniel the son of Kenaz,"], ["o le uso itiiti lea o Kalepo;", "Caleb's younger brother, took it:"], ["ona avatu ai lea e ia o Akesa lona afafine ia te ia e fai mana avā.", "and he gave him Achsah his daughter to wife."]]},
  {num:14,words:[["Ua alu atu ia,", "And it came to pass,"], ["ona faaoso ai lea o ia ia te ia,", "when she came to him,"], ["na te ole atu i se fanua mai lona tamā;", "that she moved him to ask of her father a field:"], ["ua alu ifo ia nai le asini,", "and she lighted from off her ass;"], ["ona fai mai ai lea o Kalepo ia te ia,", "and Caleb said unto her,"], ["Se a ea lou manao?", "What wilt thou?"]]},
  {num:15,words:[["Ona fai atu lea o ia ia te ia,", "And she said unto him,"], ["Ia e alofa mai ia te au;", "Give me a blessing:"], ["auā na e avane ia te au le fanua i le itu i toga;", "for thou hast given me a south land;"], ["ia e foai mai foi ma ni vaipuna. Ona avatu ai lea e Kalepo ia te ia o vaipuna o i luga atoa ma vaipuna o i lalo.", "give me also springs of water. And Caleb gave her the upper springs and the nether springs."]]},
  {num:16,words:[["O le fanau a le sa Kenī,", "And the children of the Kenite,"], ["o le tamā lea o le avā a Mose,", "Moses' father in law,"], ["ua latou o ae nai le aai o pama faatasi ma le fanauga a Iuta,", "went up out of the city of palm trees with the children of Judah into the wilderness of Judah,"], ["i le vao o Iuta i lona itu i toga o Arata;", "which lieth in the south of Arad;"], ["ua latou o foi ma nonofo faatasi ma le nuu.", "and they went and dwelt among the people."]]},
  {num:17,words:[["Ona o lea o Iuta ma Simeona lona uso, ua latou fasia sa Kananā,", "And Judah went with Simeon his brother,"], ["e sa nonofo i Sefata,", "and they slew the Canaanites that inhabited Zephath,"], ["ua latou faaumatia ai lava; ona faaigoa ai lea o le igoa o le aai o Horema.", "and utterly destroyed it. And the name of the city was called Hormah."]]},
  {num:18,words:[["Ua maua foi e Iuta o Kasa ma ona fanua,", "Also Judah took Gaza with the coast thereof,"], ["ma Asekelona ma ona fanua,", "and Askelon with the coast thereof,"], ["o Ekerona foi ma ona fanua.", "and Ekron with the coast thereof."]]},
  {num:19,words:[["Na i ai Ieova ia Iuta;", "And the LORD was with Judah;"], ["ua na tulia e sa nonofo i le mauga,", "and he drave out the inhabitants of the mountain;"], ["a ua le tulia e sa nonofo i le vanu,", "but could not drive out the inhabitants of the valley,"], ["auā sa ia te i latou kariota uamea.", "because they had chariots of iron."]]},
  {num:20,words:[["Ua latou faatoina atu o Heperona mo Kalepo,", "And they gave Hebron unto Caleb,"], ["pei ona fai mai ai o Mose;", "as Moses said:"], ["ua ia tulia foi ai lea mea atalii o Anaki e toatolu.", "and he expelled thence the three sons of Anak."]]},
  {num:21,words:[["A o sa Iepusē, e ua nonofo i Ierusalema,", "And the children of Benjamin did not drive out the Jebusites that inhabited Jerusalem;"], ["e lei tulia i latou e le fanauga a Peniamina; a ua nonofo faatasi o sa Iepusē ma le fanauga a Peniamina i Ierusalema, ua oo mai i ona po nei.", "but the Jebusites dwell with the children of Benjamin in Jerusalem unto this day."]]},
  {num:22,words:[["Ua o ae foi le aiga o Iosefa i Peteli;", "And the house of Joseph, they also went up against Beth-el:"], ["na ia te i latou foi o Ieova.", "and the LORD was with them."]]},
  {num:23,words:[["Na auina nisi e le aiga o Iosefa e asiasi i Peteli; (o Lusa, o le igoa lea o le aai anamua.)", "And the house of Joseph sent to descry Beth-el. (Now the name of the city before was Luz.)"]]},
  {num:24,words:[["Ua iloa atu e na lamalama o le tasi tagata ua sau mai le aai,", "And the spies saw a man come forth out of the city, and they said unto him,"], ["ona latou fai atu ai lea ia te ia,", "Shew us,"], ["Ina e faasino mai ia te i matou le ala i le aai,", "we pray thee,"], ["ona matou agalelei atu ai lea ia te oe.", "the entrance into the city, and we will shew thee mercy."]]},
  {num:25,words:[["Ua faasino atu e ia ia te i latou le ala i le aai,", "And when he shewed them the entrance into the city,"], ["ona latou fasia ai lea o le aai i le pelu;", "they smote the city with the edge of the sword;"], ["a ua latou tuu atu le tagata ma lona aiga uma e o.", "but they let go the man and all his family."]]},
  {num:26,words:[["Ua alu atu foi le tagata i le nuu o sa Hetī,", "And the man went into the land of the Hittites,"], ["ona faia lea e ia le aai,", "and built a city,"], ["ma na faaigoa atu ai o Lusa;", "and called the name thereof Luz:"], ["o lona igoa lea ua oo mai i ona po nei.", "which is the name thereof unto this day."]]},
  {num:27,words:[["E lei maua foi e Manase o Peteseana atoa ma ona faoa aai,", "Neither did Manasseh drive out the inhabitants of Beth-shean and her towns,"], ["o Tanaka foi atoa ma ona faoa aai,", "nor Taanach and her towns,"], ["ma e nonofo i Toro atoa ma ona faoa aai,", "nor the inhabitants of Dor and her towns,"], ["o e nonofo foi i Ipelamo atoa ma ona faoa aai,", "nor the inhabitants of Ibleam and her towns,"], ["o e nonofo foi i Mekito atoa ma ona faoa aai;", "nor the inhabitants of Megiddo and her towns:"], ["a ua finau sa Kananā e nonofo i lea nuu.", "but the Canaanites would dwell in that land."]]},
  {num:28,words:[["Ua oo ina malosi o Isaraelu,", "And it came to pass,"], ["ona totogi atu ai lea o taulaga i sa Kananā,", "when Israel was strong, that they put the Canaanites to tribute,"], ["a e lei matuā tulia i latou.", "and did not utterly drive them out."]]},
  {num:29,words:[["E lei tulia foi e Efaraima sa Kananā o e nonofo i Kasera;", "Neither did Ephraim drive out the Canaanites that dwelt in Gezer;"], ["a ua nonofo sa Kananā faatasi ma i latou i Kasera.", "but the Canaanites dwelt in Gezer among them."]]},
  {num:30,words:[["E lei tulia foi e Sepulona o e nonofo i Kiterona,", "Neither did Zebulun drive out the inhabitants of Kitron,"], ["o e nonofo foi i Naalolo;", "nor the inhabitants of Nahalol;"], ["a ua nonofo sa Kananā faatasi ma i latou,", "but the Canaanites dwelt among them,"], ["ma latou fai taulaga mai.", "and became tributaries."]]},
  {num:31,words:[["E lei tulia foi e Asera o e nonofo i Ako,", "Neither did Asher drive out the inhabitants of Accho,"], ["o e nonofo foi i Saitonu,", "nor the inhabitants of Zidon,"], ["ma e o i Ailava,", "nor of Ahlab,"], ["ma e o i Akasepa,", "nor of Achzib,"], ["ma e o i Helipa,", "nor of Helbah,"], ["ma e o i Afeka,", "nor of Aphik,"], ["ma e o i Reopa.", "nor of Rehob:"]]},
  {num:32,words:[["A ua nonofo sa Aserā faatasi ma sa Kananā o e nonofo i le nuu;", "But the Asherites dwelt among the Canaanites, the inhabitants of the land:"], ["auā ua latou le tulia i latou.", "for they did not drive them out."]]},
  {num:33,words:[["E lei tulia foi e Nafatali o e nonofo i Petesemesa,", "Neither did Naphtali drive out the inhabitants of Beth-shemesh,"], ["ma e nonofo i Peteanata;", "nor the inhabitants of Beth-anath;"], ["a ua latou nonofo faatasi ma sa Kananā e ua nonofo i le nuu;", "but he dwelt among the Canaanites,"], ["a o e nonofo i Petesemesa ma Peteanata,", "the inhabitants of the land:"], ["ua fai taulaga mai ia te i latou.", "nevertheless the inhabitants of Beth-shemesh and of Beth-anath became tributaries unto them."]]},
  {num:34,words:[["O sa Amorī ua latou tetee atu i le fanauga a Tanu ia nonofo i le mauga;", "And the Amorites forced the children of Dan into the mountain:"], ["auā na latou le mafafai ona ia o ifo o i latou i le vanu.", "for they would not suffer them to come down to the valley:"]]},
  {num:35,words:[["A ua finau sa Amorī e nonofo i le mauga o Heresa i Ailona ma Salapima;", "But the Amorites would dwell in mount Heres in Aijalon,"], ["a ua lima malosi le aiga o Iosefa,", "and in Shaalbim: yet the hand of the house of Joseph prevailed,"], ["ona latou fai taulaga mai ai lea.", "so that they became tributaries."]]},
  {num:36,words:[["O le tuaoi foi o sa Amorī,", "And the coast of the Amorites was from the going up to Akrabbim,"], ["e pau mai i le aega o Akarava i Sela,", "from the rock,"], ["ma ona tala atu i luga.", "and upward."]]},
];
renderVerseSet(jdg_ch_1_Verses, 'jdg-ch1-verses');

var jdg_ch_2_Verses = [
  {num:1,words:[["Ua alu ae le agelu a Ieova mai Kilikala i Pokima,", "And an angel of the LORD came up from Gilgal to Bochim,"], ["ua faapea atu,", "and said,"], ["Na ou aveina ae outou mai Aikupito,", "I made you to go up out of Egypt,"], ["na ou faaooina foi outou i le nuu na ou tauto ai i o outou tamā;", "and have brought you unto the land which I sware unto your fathers;"], ["na ou faapea ane foi,", "and I said,"], ["Ou te le tuumavaega lava i la'u feagaiga ma outou e faavavau.", "I will never break my covenant with you."]]},
  {num:2,words:[["O outou foi,", "And ye shall make no league with the inhabitants of this land;"], ["aua ne'i outou fai se feagaiga ma e o nonofo i lenei nuu;", "ye shall throw down their altars:"], ["ia outou sofaia o latou fata faitaulaga a ua outou le faalogo i la'u upu;", "but ye have not obeyed my voice:"], ["se a le mea ua outou fai ai lenei mea?", "why have ye done this?"]]},
  {num:3,words:[["O le mea lea na ou fai atu ai,", "Wherefore I also said,"], ["Ou te le tulia i latou i o outou luma;", "I will not drive them out from before you;"], ["a e avea i latou ma sasa i o outou itu,", "but they shall be as thorns in your sides,"], ["e avea foi o latou atua ma mailei ia te outou.", "and their gods shall be a snare unto you."]]},
  {num:4,words:[["Ua fai atu le agelu a Ieova i nei upu i le fanauga a Isaraelu uma,", "And it came to pass, when the angel of the LORD spake these words unto all the children of Israel,"], ["ona matuā taufaitagi ai lea o le nuu.", "that the people lifted up their voice, and wept."]]},
  {num:5,words:[["Ua latou faaigoa lea mea o Pokima;", "And they called the name of that place Bochim:"], ["ona latou fai taulaga lea ia Ieova i lea mea.", "and they sacrificed there unto the LORD."]]},
  {num:6,words:[["Sa tuu atu e Iosua le nuu e o, ona o ai lea o le fanauga a Isaraelu e taitasi i lona tofi,", "And when Joshua had let the people go,"], ["e fai mo latou le nuu.", "the children of Israel went every man unto his inheritance to possess the land."]]},
  {num:7,words:[["Sa auauna le nuu ia Ieova i aso uma o Iosua,", "And the people served the LORD all the days of Joshua,"], ["ma aso uma o toeaina e na ola mai a ua mavae Iosua,", "and all the days of the elders that outlived Joshua, who had seen all the great works of the LORD,"], ["o e na iloa galuega tetele uma a Ieova na ia faia mo Isaraelu.", "that he did for Israel."]]},
  {num:8,words:[["Ua oti Iosua le atalii o Nuno,", "And Joshua the son of Nun,"], ["le auauna a Ieova;", "the servant of the LORD, died,"], ["ua tasi le selau ma le sefulu o tausaga o lona ola.", "being an hundred and ten years old."]]},
  {num:9,words:[["Ua latou tanu foi ia te ia i le fanua o lona tofi i Timenata-heresa i le mauga o Efaraima,", "And they buried him in the border of his inheritance in Timnath-heres, in the mount of Ephraim,"], ["i le itu i matu o le mauga o Kaasa.", "on the north side of the hill Gaash."]]},
  {num:10,words:[["Ua faaopoopoina atu foi o lea tupulaga uma i o latou tamā;", "And also all that generation were gathered unto their fathers:"], ["ua mavae i latou,", "and there arose another generation after them, which knew not the LORD,"], ["ona tupu ai lea o le tasi tupulaga o e na le iloa Ieova ma ana galuega na ia faia mo Isaraelu.", "nor yet the works which he had done for Israel."]]},
  {num:11,words:[["Ona amio leaga lea o le fanauga a Isaraelu i luma o Ieova,", "And the children of Israel did evil in the sight of the LORD,"], ["ua latou auauna foi ia Paala.", "and served Baalim:"]]},
  {num:12,words:[["Ua latou tuua Ieova le Atua o latou tamā,", "And they forsook the LORD God of their fathers,"], ["o le na aumaia i latou mai le nuu o Aikupito,", "which brought them out of the land of Egypt,"], ["a ua latou mulimuli atu i atua ese,", "and followed other gods,"], ["o atua o nuu ua vagavagai ia te i latou,", "of the gods of the people that were round about them,"], ["ua latou ifo foi i ai,", "and bowed themselves unto them,"], ["ma latou faaonoono ai ia Ieova.", "and provoked the LORD to anger."]]},
  {num:13,words:[["Ua latou tuua Ieova,", "And they forsook the LORD,"], ["ma auauna ia Paala ma Asaira.", "and served Baal and Ashtaroth."]]},
  {num:14,words:[["Ona tupu tele ai lea o le toasa o Ieova ia Isaraleu,", "And the anger of the LORD was hot against Israel,"], ["ua ia tuuina atu i latou i lima o e vete mea,", "and he delivered them into the hands of spoilers that spoiled them,"], ["o e na vetea a latou mea; ua tuuina atu foi i latou i lima o e vagavagai mai ua ita ia te i latou;", "and he sold them into the hands of their enemies round about,"], ["ua latou le toe mafai ai ona tutū atu i luma o e ua ita ia te i latou.", "so that they could not any longer stand before their enemies."]]},
  {num:15,words:[["O mea uma foi na latou o i ai,", "Whithersoever they went out,"], ["sa i ai le aao o Ieova ia leaga ai i latou,", "the hand of the LORD was against them for evil,"], ["e pei ona fetalai mai ai o Ieova,", "as the LORD had said,"], ["e pei ona tauto foi o Ieova ia te i latou;", "and as the LORD had sworn unto them:"], ["na puapuagateleina ai i latou.", "and they were greatly distressed."]]},
  {num:16,words:[["A ua faatuina e Ieova o faamasino,", "Nevertheless the LORD raised up judges,"], ["ua latou faaola ia te i latou ai lima o e vetea a latou mea.", "which delivered them out of the hand of those that spoiled them."]]},
  {num:17,words:[["A e lei faalogo i latou i o latou faamasino,", "And yet they would not hearken unto their judges,"], ["a ua mulimuli atu i atua ese e mulilulua ai,", "but they went a whoring after other gods,"], ["ua latou ifo foi i ai;", "and bowed themselves unto them:"], ["ua vave ona latou o ese i le ala na savavali ai o latou tamā,", "they turned quickly out of the way which their fathers walked in,"], ["ē sa anaana i poloaiga a Ieova;", "obeying the commandments of the LORD;"], ["ua le faapea ona latou faia.", "but they did not so."]]},
  {num:18,words:[["Ua faatuina e Ieova o faamasino mo i latou,", "And when the LORD raised them up judges,"], ["ona i ai lea o Ieova ma le faamasino,", "then the LORD was with the judge,"], ["ma ua faaolaina i latou ai lima o e ua ita ia te i latou i aso uma o le faamasino; auā ua salamo Ieova i o latou feoi,", "and delivered them out of the hand of their enemies all the days of the judge:"], ["ona o e ua faasaua ma faatiga ia te i latou.", "for it repented the LORD because of their groanings by reason of them that oppressed them and vexed them."]]},
  {num:19,words:[["A ua oo ina oti o le faamasino,", "And it came to pass, when the judge was dead,"], ["ona latou liliu ai lea,", "that they returned,"], ["ua sili foi lo latou leaga i o latou tamā,", "and corrupted themselves more than their fathers, in following other gods to serve them,"], ["ina ua latou mulimuli atu i atua ese e auauna i ai,", "and to bow down unto them;"], ["ma ifo i ai. Ua latou le tuua a latou amio ma lo latou faalogogatā.", "they ceased not from their own doings, nor from their stubborn way."]]},
  {num:20,words:[["O le mea lea ua tupu tele ai le toasa o Ieova ia Isaraelu,", "And the anger of the LORD was hot against Israel;"], ["ua fetalai mai foi o ia,", "and he said,"], ["Ua tuumavaega lenei nuu i la'u feagaiga na ou poloai atu ai i o latou tamā,", "Because that this people hath transgressed my covenant which I commanded their fathers,"], ["e lei faalogo foi i latou i la'u upu.", "and have not hearkened unto my voice;"]]},
  {num:21,words:[["O le mea lea ou te le toe tulia ai ai ia te i latou so ia nuu na tuua e Iosua ina ua oti o ia.", "I also will not henceforth drive out any from before them of the nations which Joshua left when he died:"]]},
  {num:22,words:[["Ina ia tofotofoina o Isaraelu e i latou,", "That through them I may prove Israel,"], ["pe latou te tausiusi i le ala o Ieova e savavali ai,", "whether they will keep the way of the LORD to walk therein,"], ["pei ona tausiusi ai e o latou tamā,", "as their fathers did keep it,"], ["pe leai.", "or not."]]},
  {num:23,words:[["O le mea lea na tuuina atu ai e Ieova o ia nuu,", "Therefore the LORD left those nations,"], ["ua le vave tulia i latou;", "without driving them out hastily;"], ["e lei tuuina atu foi e ia i latou i le lima o Iosua.", "neither delivered he them into the hand of Joshua."]]},
];
renderVerseSet(jdg_ch_2_Verses, 'jdg-ch2-verses');

var jdg_ch_3_Verses = [
  {num:1,words:[["O nuu foi ia na tuua e Ieova e tofotofoina e i latou o Isaraelu,", "Now these are the nations which the LORD left, to prove Israel by them,"], ["o i latou uma e na le iloa taua uma o Kanana.", "even as many of Israel as had not known all the wars of Canaan;"]]},
  {num:2,words:[["Tau ina ia iloa e tupulaga o le fanauga a Isaraelu e a'oa'o ia te i latou i le taua,", "Only that the generations of the children of Israel might know, to teach them war,"], ["o i latou foi lava na le iloa anamua;", "at the least such as before knew nothing thereof;"]]},
  {num:3,words:[["o alii e toalima o Filisitia,", "Namely,"], ["ma sa Kananā uma,", "five lords of the Philistines,"], ["ma sa Saitonū,", "and all the Canaanites, and the Sidonians,"], ["ma sa Hevī o e nonofo i le mauga o Lepanona,", "and the Hivites that dwelt in mount Lebanon,"], ["e pau atu i le mauga o Paala-heremone e oo i le ala o Amato.", "from mount Baal-hermon unto the entering in of Hamath."]]},
  {num:4,words:[["Na i ai i latou ina ia tofotofoina Isaraelu e i latou,", "And they were to prove Israel by them, to know whether they would hearken unto the commandments of the LORD,"], ["ina ia iloa pe latou te faalogo i poloaiga a Ieova na ia poloai atu ai i o latou tamā na oo mai ia Mose.", "which he commanded their fathers by the hand of Moses."]]},
  {num:5,words:[["Ua nonofo le fanauga a Isaraelu faatasi ma sa Kananā,", "And the children of Israel dwelt among the Canaanites,"], ["o sa Hetī,", "Hittites,"], ["ma sa Amorī,", "and Amorites,"], ["ma sa Perisē,", "and Perizzites,"], ["ma sa Hevī,", "and Hivites,"], ["ma sa Iepusē.", "and Jebusites:"]]},
  {num:6,words:[["Ona latou fai avā lea i o latou afafine;", "And they took their daughters to be their wives,"], ["ua latou avatu foi o latou afafine i o latou atalii,", "and gave their daughters to their sons,"], ["ma latou auauna atu i o latou atua.", "and served their gods."]]},
  {num:7,words:[["Ua amio leaga le fanauga a Isaraelu i luma o Ieova;", "And the children of Israel did evil in the sight of the LORD,"], ["ua latou faagalogalo foi ia Ieova lo latou Atua,", "and forgat the LORD their God,"], ["a ua latou auauna atu ia Paala ma Asaira.", "and served Baalim and the groves."]]},
  {num:8,words:[["O le mea lea na tupu tele ai le toasa o Ieova ia Isaraelu,", "Therefore the anger of the LORD was hot against Israel,"], ["na ia tuuina atu i latou i le lima o Kusa-risatima, o le tupu lea o Mesopotamia;", "and he sold them into the hand of Chushan-rishathaim king of Mesopotamia:"], ["ona auauna lea o le fanauga a Isaraelu ia Kusa-risatima i tausaga e valu.", "and the children of Israel served Chushan-rishathaim eight years."]]},
  {num:9,words:[["Ua alalaga atu le fanauga a Isaraelu ia Ieova,", "And when the children of Israel cried unto the LORD,"], ["ona faatuina ai lea e Ieova o le faaola mo le fanauga a Isaraelu,", "the LORD raised up a deliverer to the children of Israel,"], ["na ia faaolaina i latou, o Otinielu lea,", "who delivered them,"], ["o le atalii o Kinasa,", "even Othniel the son of Kenaz,"], ["o le uso itiiti o Kalepo.", "Caleb's younger brother."]]},
  {num:10,words:[["Ua oo ia te ia le Agaga o Ieova,", "And the Spirit of the LORD came upon him,"], ["ona faamasino lea e ia o Isaraelu;", "and he judged Israel,"], ["ua alu atu foi o ia i le taua,", "and went out to war:"], ["ona tuuina mai lea e Ieova i lona lima o Kusa-risatima le tupu o Mesopotamia;", "and the LORD delivered Chushan-rishathaim king of Mesopotamia into his hand;"], ["ua manumalo foi o ia ia Kusa-risatima.", "and his hand prevailed against Chushan-rishathaim."]]},
  {num:11,words:[["Ona filemu ai lea o le nuu i tausaga e fagafulu. Ona oti lea o Otinielu le atalii o Kinasa.", "And the land had rest forty years. And Othniel the son of Kenaz died."]]},
  {num:12,words:[["Ua toe amio leaga le fanauga a Isaraelu i luma o Ieova,", "And the children of Israel did evil again in the sight of the LORD:"], ["ona faamalosi ai lea e Ieova ia Ekelona le tupu o Moapi e tau ma Isaraelu,", "and the LORD strengthened Eglon the king of Moab against Israel,"], ["ina ua latou amio leaga i luma o Ieova.", "because they had done evil in the sight of the LORD."]]},
  {num:13,words:[["Ua ia faapotopoto ane ia te ia le fanauga a Amoni ma Amaleka;", "And he gathered unto him the children of Ammon and Amalek,"], ["ona alu atu lea o ia, mana fasia Isaraelu,", "and went and smote Israel,"], ["ua latou maua foi le aai o pama.", "and possessed the city of palm trees."]]},
  {num:14,words:[["Ona auauna ai lea o le fanauga a Isaraelu ia Ekelona le tupu o Moapi i tausaga e sefulu ma le valu.", "So the children of Israel served Eglon the king of Moab eighteen years."]]},
  {num:15,words:[["A ua alalaga atu le fanauga a Isaraelu ia Ieova,", "But when the children of Israel cried unto the LORD,"], ["ona faatuina ai lea e Ieova o le faaola mo i latou,", "the LORD raised them up a deliverer,"], ["o Euta lea le atalii o Kira o le sa Peniaminā,", "Ehud the son of Gera, a Benjamite,"], ["o le tagata tauagavale ia;", "a man lefthanded:"], ["ua auina o ia e le fanauga a Isaraelu e momoli le taulaga ia Ekelona le tupu o Moapi.", "and by him the children of Israel sent a present unto Eglon the king of Moab."]]},
  {num:16,words:[["Ua gaosia e Euta māna se pelu e faataumaai itu o lona umi o le kupita e tasi;", "But Ehud made him a dagger which had two edges, of a cubit length;"], ["ua ia fusia ai foi i lalo i ona ofu i lona vae taumatau.", "and he did gird it under his raiment upon his right thigh."]]},
  {num:17,words:[["Ua ia avatua le taulaga ia Ekelona le tupu o Moapi;", "And he brought the present unto Eglon king of Moab:"], ["o le tagata ua matuā puta lava Ekelona.", "and Eglon was a very fat man."]]},
  {num:18,words:[["Ua uma ona avatua le taulaga,", "And when he had made an end to offer the present,"], ["ona aauina atu ai lea e ia o le nuu na au mai le taulaga,", "he sent away the people that bare the present."]]},
  {num:19,words:[["a ua foi mai o ia i le mea o i ai tupua ua ta ua i Kilikala. Ona fai atu ai lea o ia,", "But he himself turned again from the quarries that were by Gilgal, and said,"], ["Le tupu e,", "I have a secret errand unto thee,"], ["ua ia te au le feau faalilolilo ia te oe. Ona fai mai ai lea o ia,", "O king:"], ["Ina fāalologo ia. Ona o uma atu ai lea nai ia te ia o e na tutū atu ia te ia.", "who said, Keep silence. And all that stood by him went out from him."]]},
  {num:20,words:[["Ua alu atu foi Euta ia te ia, sa nofo o ia i lona afeafe faasavili,", "And Ehud came unto him;"], ["e gata ia te ia lava;", "and he was sitting in a summer parlour,"], ["ona fai atu ai lea o Euta,", "which he had for himself alone. And Ehud said,"], ["Ua ia te au le feau mai le Atua ia te oe; ona tulai ai lea o ia nai le nofoa.", "I have a message from God unto thee. And he arose out of his seat."]]},
  {num:21,words:[["Ua tuu ane e Euta lona lima tauagavale,", "And Ehud put forth his left hand,"], ["ma tago i le pelu na i lona vae taumatau,", "and took the dagger from his right thigh,"], ["ona tutu'i atu ai lea e ia i lona manava.", "and thrust it into his belly:"]]},
  {num:22,words:[["Ua gālo atoa ma le 'au o le pelu,", "And the haft also went in after the blade;"], ["ua lilo foi le pelu i le tino ua puta,", "and the fat closed upon the blade,"], ["ua ia le ma toso ai le pelu nai lona manava,", "so that he could not draw the dagger out of his belly;"], ["ua ati loa i nofoaga.", "and the dirt came out."]]},
  {num:23,words:[["Ua alu atu Euta i le faapaologa,", "Then Ehud went forth through the porch,"], ["ua ia pupuni foi i ona tua o puipui o le afeafe,", "and shut the doors of the parlour upon him,"], ["ma faamau ai.", "and locked them."]]},
  {num:24,words:[["Ua alu atu o ia,", "When he was gone out,"], ["ona o mai ai lea o ana auauna;", "his servants came;"], ["ua latou iloa atu,", "and when they saw that,"], ["faauta,", "behold,"], ["ua faamauina o puipui o le afeafe;", "the doors of the parlour were locked,"], ["ona latou fai ane ai lea,", "they said,"], ["Ai lava o loo ufiufi e ia ona aao i le afeafe faasavili.", "Surely he covereth his feet in his summer chamber."]]},
  {num:25,words:[["Ua latou faatali faatali ua mamā i latou;", "And they tarried till they were ashamed:"], ["faauta foi,", "and,"], ["e lei tatalaina lava e ia o puipui o le afeafe;", "behold,"], ["ona latou ave ai lea o se ki,", "he opened not the doors of the parlour;"], ["ma tatala a'i;", "therefore they took a key, and opened them:"], ["faauta foi,", "and,"], ["ua paū i le eleele lo latou alii,", "behold,"], ["ua oti.", "their lord was fallen down dead on the earth."]]},
  {num:26,words:[["Ua sola Euta a o faatali i latou,", "And Ehud escaped while they tarried,"], ["na tuana'i atu e ia o tupua ua ta,", "and passed beyond the quarries,"], ["ua sao atu foi i Seirata.", "and escaped unto Seirath."]]},
  {num:27,words:[["Ua oo atu ia,", "And it came to pass,"], ["ona ili ai lea e ia o le pu i le mauga o Efaraima;", "when he was come,"], ["ua o ifo foi ma ia o le fanauga a Isaraelu mai le mauga,", "that he blew a trumpet in the mountain of Ephraim, and the children of Israel went down with him from the mount,"], ["na muamua o ia ia te i latou.", "and he before them."]]},
  {num:28,words:[["Ua ia fai atu foi ia te i latou,", "And he said unto them,"], ["Ia outou mulimuli mai ia te au;", "Follow after me:"], ["auā ua tuuina mai e Ieova o outou fili o Moapi i o outou lima. Ua latou mulimuli ifo ia te ia,", "for the LORD hath delivered your enemies the Moabites into your hand. And they went down after him,"], ["ona latou maua ai lea o asaga o Ioritana e ui atu ai i Moapi;", "and took the fords of Jordan toward Moab,"], ["ua le mafafai i latou ona ui atu ai o se tasi.", "and suffered not a man to pass over."]]},
  {num:29,words:[["Na fasia e i latou o Moapi i lea aso pe sefulu ni afe o tagata,", "And they slew of Moab at that time about ten thousand men,"], ["ua malolosi ma totoa i latou uma lava,", "all lusty, and all men of valour;"], ["e leai foi se tasi na sao.", "and there escaped not a man."]]},
  {num:30,words:[["Ua toilalo Moapi i lea aso i le lima o Isaraelu. Ona filemu ai lea o le nuu i tausaga e valugafulu.", "So Moab was subdued that day under the hand of Israel. And the land had rest fourscore years."]]},
  {num:31,words:[["Ua mavae o ia,", "And after him was Shamgar the son of Anath,"], ["ona nofo mai lea o Samekara o le atalii o Anato, na fasia e ia o Filisitia e toaono selau i le tui povi;", "which slew of the Philistines six hundred men with an ox goad:"], ["o ia foi na ia faaolaina Isaraelu.", "and he also delivered Israel."]]},
];
renderVerseSet(jdg_ch_3_Verses, 'jdg-ch3-verses');

var jdg_ch_4_Verses = [
  {num:1,words:[["Ua oti Euta;", "And the children of Israel again did evil in the sight of the LORD,"], ["ona toe amio leaga ai lea o le fanauga a Isaraelu i luma o Ieova.", "when Ehud was dead."]]},
  {num:2,words:[["Ona tuuina atu ai lea o i latou e Ieova i le lima o Iapino le tupu o Kanana o le na pule i Hasora;", "And the LORD sold them into the hand of Jabin king of Canaan,"], ["a o le na pule i lana itu taua,", "that reigned in Hazor;"], ["o Sesera lea,", "the captain of whose host was Sisera,"], ["sa nofo i Haroseta o nuu ese.", "which dwelt in Harosheth of the Gentiles."]]},
  {num:3,words:[["Ona alalaga atu lea o le fanauga a Isaraelu ia Ieova;", "And the children of Israel cried unto the LORD:"], ["auā na ia te ia o kariota uamea e iva selau;", "for he had nine hundred chariots of iron;"], ["na ia matuā faasaua i le fanauga a Isaraelu i tausaga e luafulu.", "and twenty years he mightily oppressed the children of Israel."]]},
  {num:4,words:[["O ona po ia na faamasinoina ai Isaraelu e Tepora,", "And Deborah,"], ["o le perofeta fafine,", "a prophetess, the wife of Lapidoth,"], ["o le avā lea a Lapitota.", "she judged Israel at that time."]]},
  {num:5,words:[["Sa nofo o ia i lalo o le pama o Tepora i le va o Rama ma Peteli, i le mauga o Efaraima;", "And she dwelt under the palm tree of Deborah between Ramah and Beth-el in mount Ephraim:"], ["na o ae ai ia te ia le fanauga a Isaraelu ia faamasinoina.", "and the children of Israel came up to her for judgment."]]},
  {num:6,words:[["Ona aauina atu ai lea e ia nisi e aami ia Parako le atalii o Apinoamo mai Katesanafatali;", "And she sent and called Barak the son of Abinoam out of Kedesh-naphtali,"], ["ua ia fai atu foi ia te ia,", "and said unto him,"], ["E lei poloai mai ea Ieova le Atua o Isaraelu,", "Hath not the LORD God of Israel commanded, saying,"], ["e te alu ma e ta'i 'au i le mauga o Tapora,", "Go and draw toward mount Tabor,"], ["tou te o ma tagata e sefulu afe o le fanauga a Nafatali ma le fanauga a Sepulona?", "and take with thee ten thousand men of the children of Naphtali and of the children of Zebulun?"]]},
  {num:7,words:[["Ou te tosina atu foi Sesera lē pule i le itu taua a Iapino,", "And I will draw unto thee to the river Kishon Sisera,"], ["ma ona kariota,", "the captain of Jabin's army,"], ["atoa ma ana 'au ia te oe i le alia o Kisona;", "with his chariots and his multitude;"], ["ou te tuuina atu foi o ia i lou lima.", "and I will deliver him into thine hand."]]},
  {num:8,words:[["Ona fai mai ai lea o Parako ia te ia,", "And Barak said unto her,"], ["Afai ta te o ma a'u,", "If thou wilt go with me,"], ["ona ou alu lea;", "then I will go:"], ["a e afai ta te le o ma a'u,", "but if thou wilt not go with me,"], ["ou te le alu.", "then I will not go."]]},
  {num:9,words:[["Ua fai atu o ia,", "And she said,"], ["Ta te o lava ma oe;", "I will surely go with thee:"], ["a e peitai e leai sou viiga i lenei mea e te alu ai oe;", "notwithstanding the journey that thou takest shall not be for thine honour;"], ["auā e tuuina atu e Ieova o Sesera i le lima o le fafine. Ua tu i luga Tepora,", "for the LORD shall sell Sisera into the hand of a woman. And Deborah arose,"], ["ona la o ai lea ma Parako i Katesa.", "and went with Barak to Kedesh."]]},
  {num:10,words:[["Ona faapotopoto ai lea e Parako o Sepulona ma Nafatali i Katesa;", "And Barak called Zebulun and Naphtali to Kedesh;"], ["ua alu ae foi ia atoa ma le sefulu o afe o tagata ua mulimuli atu ia te ia;", "and he went up with ten thousand men at his feet:"], ["ua la o ae foi ma Tepora.", "and Deborah went up with him."]]},
  {num:11,words:[["O Kaveru foi o le sa Kenī,", "Now Heber the Kenite,"], ["o so le fanau a Opapo,", "which was of the children of Hobab the father in law of Moses,"], ["o le tamā lea o le avā a Mose, na vavae mai o ia i sa Kenī,", "had severed himself from the Kenites,"], ["ua na to foi lona fale ie e latalata ane i le aluna i Saanaima,", "and pitched his tent unto the plain of Zaanaim,"], ["ua i Katesa lea.", "which is by Kedesh."]]},
  {num:12,words:[["Ua latou faailoa foi ia Sesera, ua alu ae Parako le atalii o Apinoamo i le mauga o Tapora.", "And they shewed Sisera that Barak the son of Abinoam was gone up to mount Tabor."]]},
  {num:13,words:[["Ona faapotopoto ai lea e Sesera o ona kariota uma,", "And Sisera gathered together all his chariots,"], ["o kariota uamea e iva selau,", "even nine hundred chariots of iron,"], ["atoa ma le nuu uma o e na ia te ia,", "and all the people that were with him,"], ["mai Haroseta o nuu ese e ō i le alia o Kisona.", "from Harosheth of the Gentiles unto the river of Kishon."]]},
  {num:14,words:[["Ona fai atu ai lea o Tepora ia Parako,", "And Deborah said unto Barak,"], ["Tulai ia,", "Up;"], ["auā o le aso lenei e tuuina atu ai e Ieova o Sesera i lou lima;", "for this is the day in which the LORD hath delivered Sisera into thine hand:"], ["e lei afio atu ea o Ieova i ou luma? Ona alu ifo lea o Parako nai le mauga o Tapora,", "is not the LORD gone out before thee? So Barak went down from mount Tabor,"], ["atoa ma le sefulu o afe o tagata ua mulimuli atu ia te ia.", "and ten thousand men after him."]]},
  {num:15,words:[["Ua faataapeapeina e Ieova o Sesera,", "And the LORD discomfited Sisera,"], ["ma ona kariota uma,", "and all his chariots,"], ["ma lana itu taua uma i le pelu i luma o Parako;", "and all his host, with the edge of the sword before Barak;"], ["ona alu ifo ai lea o Sesera nai lona kariota,", "so that Sisera lighted down off his chariot,"], ["ma sola i ona vae.", "and fled away on his feet."]]},
  {num:16,words:[["A ua tuliloa atu e Parako i kariota ma le itu taua,", "But Barak pursued after the chariots,"], ["ua oo lava i Haroseta o nuu ese;", "and after the host,"], ["ua oti le itu taua uma a Sesera i le pelu;", "unto Harosheth of the Gentiles: and all the host of Sisera fell upon the edge of the sword;"], ["e leai lava se tasi na toe.", "and there was not a man left."]]},
  {num:17,words:[["A o Sesera, ua sola o ia i ona vae i le fale ie o Iaeli le avā a Kaveru o le sa Kenī;", "Howbeit Sisera fled away on his feet to the tent of Jael the wife of Heber the Kenite:"], ["auā ua nofo lelei Iapino le tupu o Hasora ma le aiga o Kaveru o le sa Kenī.", "for there was peace between Jabin the king of Hazor and the house of Heber the Kenite."]]},
  {num:18,words:[["Ona alu atu lea o Iaeli e faafetaiai ia Sesera,", "And Jael went out to meet Sisera,"], ["ua fai atu ia te ia,", "and said unto him,"], ["Le alii e,", "Turn in,"], ["afe mai ia,", "my lord,"], ["ina afe mai ia te au,", "turn in to me;"], ["aua e te mata'u. Ona afe ane ai lea o ia ia te ia i le fale ie,", "fear not. And when he had turned in unto her into the tent,"], ["ona ufiufi ai lea e le fafine ia te ia i le ie afu.", "she covered him with a mantle."]]},
  {num:19,words:[["Ua fai mai foi o ia ia te ia,", "And he said unto her, Give me,"], ["Se'i e au mai sina vai ou te inu ai;", "I pray thee,"], ["auā ua ou fia inu lava.", "a little water to drink; for I am thirsty."], ["Ona tatala ai lea e ia o le fagu pa'u o suāsusu,", "And she opened a bottle of milk,"], ["ua avatu ia te ia e inu ai;", "and gave him drink,"], ["ona ufiufi ai lea ia te ia.", "and covered him."]]},
  {num:20,words:[["Ona fai mai lea o ia ia te ia,", "Again he said unto her,"], ["Ina tu ia oe i le faitotoa o le faleie;", "Stand in the door of the tent,"], ["a sau se tasi e fesili ia te oe,", "and it shall be, when any man doth come and enquire of thee,"], ["ma faapea mai,", "and say,"], ["O iina ea se isi? Ia e faapea atu,", "Is there any man here? that thou shalt say,"], ["E leai lava.", "No."]]},
  {num:21,words:[["Ona tago ai lea o Iaeli le avā a Kaveru i se fao o le fale ie,", "Then Jael Heber's wife took a nail of the tent,"], ["ua ave foi ma le samala i lona lima,", "and took an hammer in her hand,"], ["ona alu lemu atu lea ia te ia, ua ia tutu'i ai le fao i lona manifinifi,", "and went softly unto him,"], ["ua ati ifo i le eleele,", "and smote the nail into his temples,"], ["auā na moegase ina ua lailoa;", "and fastened it into the ground:"], ["ona oti ai lea o ia.", "for he was fast asleep and weary. So he died."]]},
  {num:22,words:[["Faauta foi,", "And,"], ["ua tuliloa mai Parako ia Sesera,", "behold,"], ["ona alu atu lea o Iaeli e faafetaiai ia te ia,", "as Barak pursued Sisera,"], ["ua fai atu o ia ia te ia,", "Jael came out to meet him,"], ["Ina maliu mai ia,", "and said unto him,"], ["ou te faaaliina atu ia te oe le tagata ua e sailia. Ona alu ane lea o ia ia te ia,", "Come,"], ["faauta,", "and I will shew thee the man whom thou seekest. And when he came into her tent,"], ["ua taatia Sesera,", "behold,"], ["na oti,", "Sisera lay dead,"], ["ua i ai foi le fao i ona manifinifi.", "and the nail was in his temples."]]},
  {num:23,words:[["O le aso lava lea na faatoilaloina ai e le Atua o Iapino le tupu o Kanana i luma o le fanauga a Isaraelu.", "So God subdued on that day Jabin the king of Canaan before the children of Israel."]]},
  {num:24,words:[["Ua manumalo pea lima o le fanauga a Isaraelu,", "And the hand of the children of Israel prospered,"], ["ua mamafa lava ia Iapino le tupu o Kanana,", "and prevailed against Jabin the king of Canaan,"], ["ua oo lava ona latou faaumatia o Iapino le tupu o Kanana.", "until they had destroyed Jabin king of Canaan."]]},
];
renderVerseSet(jdg_ch_4_Verses, 'jdg-ch4-verses');

var jdg_ch_5_Verses = [
  {num:1,words:[["Ona pepese ai lea o Tepora ma Parako le atalii o Apinoamo i lea lava aso,", "Then sang Deborah and Barak the son of Abinoam on that day,"], ["ua faapea atu,", "saying,"]]},
  {num:2,words:[["Auā o le ta'ita'iina o Isaraelu e alii ta'i 'au ma le ofo fua mai o le nuu,", "Praise ye the LORD for the avenging of Israel,"], ["ia outou faamanu ia Ieova.", "when the people willingly offered themselves."]]},
  {num:3,words:[["Ina faafofoga mai ia outou tupu;", "Hear,"], ["alii e,", "O ye kings; give ear,"], ["ina liliu mai ia o outou fofoga;", "O ye princes;"], ["o a'u,", "I,"], ["ou te pese lava a'u ia Ieova,", "even I, will sing unto the LORD;"], ["ou te fai pesega ia Ieova le Atua o Isaraelu.", "I will sing praise to the LORD God of Israel."]]},
  {num:4,words:[["Ieova e,", "LORD,"], ["na e afio atu nai Seira,", "when thou wentest out of Seir,"], ["na e afio atu ai le laueleele o Etoma,", "when thou marchedst out of the field of Edom,"], ["ona luluina ai lea o le lalolagi,", "the earth trembled,"], ["na tautulu ifo le lagi,", "and the heavens dropped,"], ["o ao foi ua tautulu ifo ai le vai.", "the clouds also dropped water."]]},
  {num:5,words:[["Na tafe ifo mauga i luma o Ieova,", "The mountains melted from before the LORD,"], ["o lea lava Sinai i luma o Ieova le Atua o Isaraelu.", "even that Sinai from before the LORD God of Israel."]]},
  {num:6,words:[["O ona po o Samekara le atalii o Anato;", "In the days of Shamgar the son of Anath,"], ["o ona po o Iaeli na gase ai ala tele,", "in the days of Jael, the highways were unoccupied,"], ["na ui atu ai malaga i ala 'alo.", "and the travellers walked through byways."]]},
  {num:7,words:[["Ua leai ni ta'ita'i ia Isaraelu;", "The inhabitants of the villages ceased,"], ["ua leai lava;", "they ceased in Israel,"], ["ua oo i ona po na tulai atu ai a'u o Tepora; na tulai atu ai a'u,", "until that I Deborah arose,"], ["o le tinā i Isaraelu.", "that I arose a mother in Israel."]]},
  {num:8,words:[["Na latou filifilia atua fou;", "They chose new gods;"], ["ona oo ai lea o le taua i faitotoa;", "then was war in the gates:"], ["na iloa ea se talita po o se tao i le fagafulu o afe o Isaraelu?", "was there a shield or spear seen among forty thousand in Israel?"]]},
  {num:9,words:[["Ua uai atu lo'u loto i faipule o Isaraelu, o e na ofo fua i le nuu;", "My heart is toward the governors of Israel,"], ["ia outou faamanu atu ia Ieova.", "that offered themselves willingly among the people. Bless ye the LORD."]]},
  {num:10,words:[["O outou e tietie i asini sisina,", "Speak,"], ["o outou e nonofo i ie lelei,", "ye that ride on white asses,"], ["o outou foi o e savavali i le ala;", "ye that sit in judgment,"], ["ia outou talatala i ai;", "and walk by the way."]]},
  {num:11,words:[["auā o le leo o e tufatufa vete i mea e utu ai vai,", "They that are delivered from the noise of archers in the places of drawing water,"], ["latou te ta'u atu le amiotonu a Ieova i lea mea;", "there shall they rehearse the righteous acts of the LORD,"], ["o le amiotonu i ona ta'ita'i i Isaraelu;", "even the righteous acts toward the inhabitants of his villages in Israel:"], ["ona o ifo ai lea o le nuu o Ieova i faitotoa.", "then shall the people of the LORD go down to the gates."]]},
  {num:12,words:[["Ala mai,", "Awake,"], ["ala mai ia,", "awake,"], ["Tepora e;", "Deborah:"], ["ala mai,", "awake,"], ["ala mai ia;", "awake, utter a song:"], ["ia e pese i le vii. Tulai mai ia,", "arise,"], ["Parako e,", "Barak,"], ["o oe na le atalii o Apinoamo,", "and lead thy captivity captive,"], ["ia e ta'ita'i i le tafeaga ou tagata o taua.", "thou son of Abinoam."]]},
  {num:13,words:[["Ona ou faapea ai lea, Ina o ifo ia e ua totoe i alii o le nuu;", "Then he made him that remaineth have dominion over the nobles among the people:"], ["Ieova e, ina e afio ifo ia te au e tau ma e ua malolosi.", "the LORD made me have dominion over the mighty."]]},
  {num:14,words:[["Mai Efaraima o e mau i Amaleka;", "Out of Ephraim was there a root of them against Amalek; after thee,"], ["e mulimuli atu ia te oe o Peniamina faatasi ma lou nuu;", "Benjamin,"], ["mai Makira na o ifo ai faipule;", "among thy people;"], ["mai Sepulona foi o e ua 'u'u le tootoo o le avea 'au.", "out of Machir came down governors, and out of Zebulun they that handle the pen of the writer."]]},
  {num:15,words:[["O alii o Isakara sa ia Tepora;", "And the princes of Issachar were with Deborah;"], ["o Isakara e pei o Parako lava ia,", "even Issachar,"], ["na auina i le vanu e mulimuli atu ia te ia;", "and also Barak:"], ["o i vaitafe o Reupena sa tele ai filifiliga o le loto.", "he was sent on foot into the valley. For the divisions of Reuben there were great thoughts of heart."]]},
  {num:16,words:[["Se a le mea na e nofo ai i lotoā mamoe,", "Why abodest thou among the sheepfolds,"], ["e faalogologo ai i le leo o le fagufagu a le au leoleo mamoe? O i vaitafe o Reupena sa tele ai filifiliga o le loto.", "to hear the bleatings of the flocks? For the divisions of Reuben there were great searchings of heart."]]},
  {num:17,words:[["Na nofo foi Kiliata i le la itu o Ioritana. Se a foi le mea na nofo ai Tanu i vaa? Na nofo foi Asera i le afaga,", "Gilead abode beyond Jordan: and why did Dan remain in ships? Asher continued on the sea shore,"], ["ua nofo lava i ona faga.", "and abode in his breaches."]]},
  {num:18,words:[["O Sepulona, o le nuu lea na tuulafoaiina lona ola ia oti; e faapea foi Nafatali i mea maualuluga o le nuu.", "Zebulun and Naphtali were a people that jeoparded their lives unto the death in the high places of the field."]]},
  {num:19,words:[["Ua o mai tupu, ua latou tau;", "The kings came and fought,"], ["ona tau ai lea o le taua e tupu o Kanana i Tanaka,", "then fought the kings of Canaan in Taanach by the waters of Megiddo;"], ["e latalata ane i le vai i Mekito; latou te lei maua lava ni oloa ario.", "they took no gain of money."]]},
  {num:20,words:[["Na latou tau mai le lagi;", "They fought from heaven;"], ["ua tau lava ma Sesera o fetu i o latou ala.", "the stars in their courses fought against Sisera."]]},
  {num:21,words:[["Na tafea i latou i le alia o Kisona;", "The river of Kishon swept them away,"], ["o le alia lea o le vavau,", "that ancient river,"], ["o le alia o Kisona. Lo'u agaga e,", "the river Kishon. O my soul,"], ["ua e solia lē ua malosi.", "thou hast trodden down strength."]]},
  {num:22,words:[["Ona nuti ai lea o atigivae o solofanua, ona o taufetuliga,", "Then were the horsehoofs broken by the means of the pransings,"], ["o taufetuliga lava o ana 'au malosi.", "the pransings of their mighty ones."]]},
  {num:23,words:[["Ua fai mai le agelu a Ieova,", "Curse ye Meroz,"], ["Ia outou faafano ia Merosa,", "said the angel of the LORD,"], ["ia outou matuā faafano lava i e o nonofo ai; auā na latou le o mai e fesoasoani ia Ieova;", "curse ye bitterly the inhabitants thereof;"], ["e fesoasoani ia Ieova,", "because they came not to the help of the LORD,"], ["e tau ma e ua malolosi.", "to the help of the LORD against the mighty."]]},
  {num:24,words:[["E sili le manuia o Iaeli i fafine uma, o le avā lea a Kaveru o le sa Kenī;", "Blessed above women shall Jael the wife of Heber the Kenite be,"], ["e sili lona manuia i fafine uma o i fale ie.", "blessed shall she be above women in the tent."]]},
  {num:25,words:[["Na ole mai o ia i se vai,", "He asked water,"], ["ona avatu ai lea e ia o le suāsusu;", "and she gave him milk;"], ["na ia avane le suāsusu to'a i le ipu tāua.", "she brought forth butter in a lordly dish."]]},
  {num:26,words:[["Na tago atu lona lima i le fao,", "She put her hand to the nail,"], ["ma lona lima taumatau i le samala a le tufuga;", "and her right hand to the workmen's hammer;"], ["ona ta lea e ia ia Sesera,", "and with the hammer she smote Sisera,"], ["ua momomo ai lona ulu;", "she smote off his head,"], ["na ia tu'i ua ati i ona manifinifi.", "when she had pierced and stricken through his temples."]]},
  {num:27,words:[["Ua punou,", "At her feet he bowed,"], ["ua paū,", "he fell,"], ["ua taoto i ona vae;", "he lay down:"], ["ua punou,", "at her feet he bowed,"], ["ua paū i ona vae;", "he fell:"], ["o le mea na punou ai o ia,", "where he bowed,"], ["na paū ma oti ai lava.", "there he fell down dead."]]},
  {num:28,words:[["Na vaavaai atu i le faamalama le tinā o Sesera,", "The mother of Sisera looked out at a window,"], ["na ia alaga atu i le mea faamatāupega o le faamalama,", "and cried through the lattice,"], ["Se a le mea ua tuai mai ai lona kariota? Se a le mea ua tuai ai ona oo mai o ona kariota?", "Why is his chariot so long in coming? why tarry the wheels of his chariots?"]]},
  {num:29,words:[["Ona tali mai ai lea ia te ia o tamaitai popoto ua ia te ia,", "Her wise ladies answered her, yea,"], ["o ia lava ua toe fai atu o ia ia te ia,", "she returned answer to herself,"]]},
  {num:30,words:[["Latou te lei maua ea? Latou te lei tufatufaina ea o vete? E taitoatasi ma se teine e toatasi pe toalua;", "Have they not sped? have they not divided the prey;"], ["o le vete o ofu lanu eseese a Sesera,", "to every man a damsel or two;"], ["o le vete o ofu lanu eseese ua matagofie;", "to Sisera a prey of divers colours, a prey of divers colours of needlework,"], ["o le ofu lanu eseese ua faamatagofie i itu e lua,", "of divers colours of needlework on both sides,"], ["mo ua o e ua iai vete.", "meet for the necks of them that take the spoil?"]]},
  {num:31,words:[["Ieova e,", "So let all thine enemies perish,"], ["ia faapea ona fanoia atoa uma o e ita ia te oe; a o e ua alolofa atu ia te ia,", "O LORD:"], ["ia pei o le la i latou ina o mu toto'a.", "but let them that love him be as the sun when he goeth forth in his might."], ["Ona filemu lea o le nuu i tausaga e fagafulu.", "And the land had rest forty years."]]},
];
renderVerseSet(jdg_ch_5_Verses, 'jdg-ch5-verses');

var jdg_ch_6_Verses = [
  {num:1,words:[["Ona fai ai lea e le fanauga a Isaraelu le amio leaga i luma o Ieova;", "And the children of Israel did evil in the sight of the LORD:"], ["ona tuuina atu ai lea o i latou e Ieova i lima o Mitiana i tausaga e fitu.", "and the LORD delivered them into the hand of Midian seven years."]]},
  {num:2,words:[["Ua manumalo Mitiana ia Isaraelu;", "And the hand of Midian prevailed against Israel:"], ["ona fai ai lea e le fanauga a Isaraelu mo i latou o lua o i mauga,", "and because of the Midianites the children of Israel made them the dens which are in the mountains,"], ["o ana foi, ma 'olo,", "and caves,"], ["ona o Mitiana.", "and strong holds."]]},
  {num:3,words:[["A totō mea e Isaraelu ona o ae ai lea o Mitiana,", "And so it was, when Israel had sown,"], ["ma Amaleka,", "that the Midianites came up,"], ["atoa ma tagata mai sasae,", "and the Amalekites,"], ["ua latou o ae lava e tau ma i latou.", "and the children of the east, even they came up against them;"]]},
  {num:4,words:[["Ua latou to lauapi e tau ma i latou,", "And they encamped against them,"], ["ona latou faataumaoi ai lea o mea na tutupu i le laueleele,", "and destroyed the increase of the earth,"], ["e oo atu lava i Kasa;", "till thou come unto Gaza,"], ["latou te lei tuuna lava sina mea e 'ai mā Isaraelu,", "and left no sustenance for Israel,"], ["po o se mamoe,", "neither sheep,"], ["po o se povi,", "nor ox,"], ["po o se asini.", "nor ass."]]},
  {num:5,words:[["Auā na latou o ae ma a latou manu ma o latou fale ie,", "For they came up with their cattle and their tents,"], ["ua latou o ae lava e pei o sē ina taa tele;", "and they came as grasshoppers for multitude;"], ["e le mafaitaulia lava i latou ma a latou kamela;", "for both they and their camels were without number:"], ["na latou oo atu foi i le nuu e faataumaoi ai.", "and they entered into the land to destroy it."]]},
  {num:6,words:[["Ona matuā matitiva ai lea o Isaraelu ona o Mitiana;", "And Israel was greatly impoverished because of the Midianites;"], ["ona alalaga ai lea o le fanauga a Isaraelu ia Ieova.", "and the children of Israel cried unto the LORD."]]},
  {num:7,words:[["Ua alalaga atu ia Ieova le fanauga a Isaraelu ona o Mitiana,", "And it came to pass, when the children of Israel cried unto the LORD because of the Midianites,"]]},
  {num:8,words:[["ona auina mai ai lea e Ieova o le perofeta i le fanauga a Isaraelu,", "That the LORD sent a prophet unto the children of Israel,"], ["ua faapea mai o ia ia te i latou,", "which said unto them,"], ["Ua faapea ona fetalai mai o Ieova le Atua o Isaraelu,", "Thus saith the LORD God of Israel,"], ["O a'u na ou aveina ae outou nai Aikupito,", "I brought you up from Egypt,"], ["ma au aumaia outou nai le mea sa nofo pologa ai;", "and brought you forth out of the house of bondage;"]]},
  {num:9,words:[["na ou laveaiina outou nai le lima o Aikupito,", "And I delivered you out of the hand of the Egyptians,"], ["ai lima lava o i latou uma e na faasaua ia te outou,", "and out of the hand of all that oppressed you,"], ["ma ou tulia i latou i o outou luma;", "and drave them out from before you,"], ["na ou avatu foi lo latou laueleele mo outou.", "and gave you their land;"]]},
  {num:10,words:[["Na ou faapea atu foi ia te outou,", "And I said unto you,"], ["O a'u o Ieova lo outou Atua;", "I am the LORD your God;"], ["aua tou te matatau i atua o sa Amorī,", "fear not the gods of the Amorites,"], ["e o latou le nuu ua outou nonofo ai;", "in whose land ye dwell:"], ["a ua outou le anaana i la'u upu.", "but ye have not obeyed my voice."]]},
  {num:11,words:[["Ona alu atu ai lea o le agelu a Ieova,", "And there came an angel of the LORD,"], ["ua nofo i lalo o le tapeneto sa i Ofira,", "and sat under an oak which was in Ophrah,"], ["na ia Ioasa le sa Apieserū;", "that pertained unto Joash the Abiezrite:"], ["o Kitiona lona atalii ua ia sasa saito i le mea e soli ai vine,", "and his son Gideon threshed wheat by the winepress,"], ["ina ia lilo ai ia Mitiana.", "to hide it from the Midianites."]]},
  {num:12,words:[["Ua faaali mai ia te ia le agelu a Ieova,", "And the angel of the LORD appeared unto him,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["Oe na le toa malosi,", "The LORD is with thee,"], ["o ia te oe Ieova.", "thou mighty man of valour."]]},
  {num:13,words:[["Ona fai atu ai lea o Kitiona ia te ia,", "And Gideon said unto him,"], ["E! le Alii e, afai ua ia te i matou Ieova,", "Oh my Lord,"], ["se a le mea ua oo mai ai ia mea uma ia te i matou;", "if the LORD be with us,"], ["o ifea ona vavega uma,", "why then is all this befallen us? and where be all his miracles which our fathers told us of,"], ["na ta'u mai ai e o matou tamā ia te i matou,", "saying,"], ["ua faapea mai, E lei aveina ae ea o i tatou e Ieova ai Aikupito? A o ona po nei ua lafoaiina ai i matou e Ieova,", "Did not the LORD bring us up from Egypt? but now the LORD hath forsaken us,"], ["ua ia tuuina mai foi i matou i lima o Mitiana.", "and delivered us into the hands of the Midianites."]]},
  {num:14,words:[["Ona silasila mai ai lea o Ieova ia te ia,", "And the LORD looked upon him,"], ["ua faapea mai,", "and said,"], ["Alu ia oe i lenei lou malosi,", "Go in this thy might,"], ["e te laveaiina Isaraelu ai le lima o Mitiana;", "and thou shalt save Israel from the hand of the Midianites:"], ["ou te lei auina atu ea oe?", "have not I sent thee?"]]},
  {num:15,words:[["Ona faapea atu ai lea o ia ia te ia,", "And he said unto him,"], ["E! Le Alii e,", "Oh my Lord,"], ["ou te laveaiina Isaraelu i ni a? Faauta mai, ua topito ona faatauvaa lo'u aiga i Manase;", "wherewith shall I save Israel? behold,"], ["o a'u foi,", "my family is poor in Manasseh,"], ["o le aupito itiiti i le aiga o lo'u tama.", "and I am the least in my father's house."]]},
  {num:16,words:[["Ona faapea mai ai lea o Ieova ia te ia,", "And the LORD said unto him,"], ["Auā ta te faatasi lava ma oe; e te fasia foi Mitiana,", "Surely I will be with thee,"], ["e peiseai o se tagata e toatasi.", "and thou shalt smite the Midianites as one man."]]},
  {num:17,words:[["Ona fai atu ai lea o ia ia te ia,", "And he said unto him,"], ["Afai ua e alofa mai ia te au,", "If now I have found grace in thy sight,"], ["ia e faia se faailoga mo a'u e iloa ai o oe lava ua ta tautalatala ma a'u.", "then shew me a sign that thou talkest with me."]]},
  {num:18,words:[["Ou te faatoga atu,", "Depart not hence,"], ["aua ne'i e maliu ese iinei,", "I pray thee,"], ["seia a'u sau ia te oe,", "until I come unto thee,"], ["ma ou au mai la'u taulaga,", "and bring forth my present,"], ["ma ou tuuina atu i ou luma. Ona faapea mai ai lea o ia,", "and set it before thee. And he said,"], ["Ou te nofo lava seia e foi mai.", "I will tarry until thou come again."]]},
  {num:19,words:[["Ua alu atu Kitiona,", "And Gideon went in,"], ["ua ia saunia le tamai 'oti,", "and made ready a kid,"], ["ma areto e le faafefeteina na faia i le efa o falaoa;", "and unleavened cakes of an ephah of flour:"], ["ua tuu e ia tufaaga i le ato,", "the flesh he put in a basket,"], ["ua ia tuu foi le sua i le pani,", "and he put the broth in a pot,"], ["ona avatu lea ia te ia i lalo o le tapeneto,", "and brought it out unto him under the oak,"], ["ma tuu atu ai.", "and presented it."]]},
  {num:20,words:[["Ua fai mai le agelu a le Atua ia te ia,", "And the angel of God said unto him,"], ["Ina tago ia i tufaaga,", "Take the flesh and the unleavened cakes,"], ["ma areto e le faafefeteina, ma e tuu atu i luga o lenei papa,", "and lay them upon this rock,"], ["ia liligi atu ai foi le sua.", "and pour out the broth."], ["Ona faapea ai lea o ia ona fai.", "And he did so."]]},
  {num:21,words:[["Ona faaloaloa atu lea e le agelu a Ieova le pito tootoo na i lona lima,", "Then the angel of the LORD put forth the end of the staff that was in his hand,"], ["ua pai atu i tufaaga ma areto e le faafefeteina;", "and touched the flesh and the unleavened cakes;"], ["ona alu ae ai lea o le afi nai le papa,", "and there rose up fire out of the rock,"], ["ua susunuina ai tufaaga ma areto e le faafefeteina. Ona alu ai lea o le agelu a Ieova na ia te ia.", "and consumed the flesh and the unleavened cakes. Then the angel of the LORD departed out of his sight."]]},
  {num:22,words:[["Ua iloa e Kitiona o le agelu a Ieova lava o ia, ona faapea ane ai lea o Kitiona,", "And when Gideon perceived that he was an angel of the LORD,"], ["Aue, le Alii e,", "Gideon said,"], ["Ieova,", "Alas,"], ["auā ua ou iloa le agelu a Ieova, ua ma fesagai lava.", "O Lord GOD! for because I have seen an angel of the LORD face to face."]]},
  {num:23,words:[["Ona fetalai mai ai lea o Ieova ia te ia,", "And the LORD said unto him,"], ["Ina filemu ia oe,", "Peace be unto thee;"], ["aua e te mata'u,", "fear not:"], ["e te le oti.", "thou shalt not die."]]},
  {num:24,words:[["Ona faia ai lea e Kitiona i lea mea o le fata faitaulaga ia Ieova,", "Then Gideon built an altar there unto the LORD,"], ["ua faaigoa i ai o Ieova-saloma;", "and called it Jehovah-shalom:"], ["ua i ai i Ofira o sa Apieserū ua oo i ona po nei.", "unto this day it is yet in Ophrah of the Abiezrites."]]},
  {num:25,words:[["Ua fetalai mai Ieova ia te ia i lea lava po,", "And it came to pass the same night,"], ["Ina ave ia le povi poa taanoa a lou tamā,", "that the LORD said unto him,"], ["ma lona lua o povi poa, e fitu ona tausaga,", "Take thy father's young bullock,"], ["ma ia e sōloi i lalo le fata faitaulaga o Paala,", "even the second bullock of seven years old,"], ["o i lou tamā;", "and throw down the altar of Baal that thy father hath,"], ["ia vavae foi i lalo le tupua o Asaira ua latalata ane i ai;", "and cut down the grove that is by it:"]]},
  {num:26,words:[["a ia e faia se fata e fai ai taulaga ia Ieova lou Atua i luga o lenei 'olo,", "And build an altar unto the LORD thy God upon the top of this rock,"], ["ma le fafie ua faaafu;", "in the ordered place,"], ["e te ave foi lona lua o povi poa,", "and take the second bullock,"], ["e te fai ai se taulaga mu i le laau o le tupua o Asaria o le a e vavae i lalo.", "and offer a burnt sacrifice with the wood of the grove which thou shalt cut down."]]},
  {num:27,words:[["Ona ave ai lea e Kitiona o tagata e toasefulu o ana auauna,", "Then Gideon took ten men of his servants,"], ["ua faia lava e pei ona fetalai mai ai o Ieova ia te ia;", "and did as the LORD had said unto him: and so it was,"], ["ua faia e ia i le po,", "because he feared his father's household,"], ["auā e le mafai ia te ia ona faia i le ao,", "and the men of the city, that he could not do it by day,"], ["ina ua mata'u lava o ia i le aiga o lona tamā atoa ma tagata o le aai.", "that he did it by night."]]},
  {num:28,words:[["Ua ala i le taeao tagata o le aai,", "And when the men of the city arose early in the morning,"], ["faauta ua sōloia i lalo le faia faitaulaga o Paala,", "behold,"], ["ma le tupua o Asaira na latalata ane i ai ua vavaeina i lalo;", "the altar of Baal was cast down, and the grove was cut down that was by it,"], ["ua fai foi le taulaga i le lua o povi poa i luga o le fata ua faia.", "and the second bullock was offered upon the altar that was built."]]},
  {num:29,words:[["Ona latou faapea ane ai lea o le tasi i le tasi,", "And they said one to another,"], ["Po o ai ea ua faia le mea nei? Ua fesilisili ma suesue i latou,", "Who hath done this thing? And when they enquired and asked,"], ["ona fai ane ai lea o i latou,", "they said,"], ["Na faia le mea nei e Kitiona le atalii o Ioasa.", "Gideon the son of Joash hath done this thing."]]},
  {num:30,words:[["Ona faapea atu ai lea o tagata o le aai ia Ioasa,", "Then the men of the city said unto Joash,"], ["Au mai ia lou atalii,", "Bring out thy son,"], ["ina ia oti o ia;", "that he may die:"], ["auā ua ia sōloia le fata faitaulaga o Paala,", "because he hath cast down the altar of Baal,"], ["auā foi ua ia vavaeina i lalo le tupua o Asaira na latalata ane i ai.", "and because he hath cut down the grove that was by it."]]},
  {num:31,words:[["Ona faapea mai ai lea o Ioasa ia te i latou uma na tutū mai ia te ia,", "And Joash said unto all that stood against him,"], ["O outou na,", "Will ye plead for Baal? will ye save him? he that will plead for him,"], ["tou te finafinau ea mo Paala? Tou te fia laveaiina o ia? O le na te finau mo ia, ia oti lava ia i le taeao nei;", "let him be put to death whilst it is yet morning:"], ["afai o se atua ia,", "if he be a god,"], ["ina faia e ia lava lana finauga,", "let him plead for himself,"], ["auā ua sōloia e se tasi lona fata faitaulaga;", "because one hath cast down his altar."]]},
  {num:32,words:[["o lea lava aso na ia faaigoaina ai o ia,", "Therefore on that day he called him Jerubbaal,"], ["o Ierupaala,", "saying,"], ["ua faapea atu, Ia la finau o Paala ma ia,", "Let Baal plead against him,"], ["auā ua ia sōloia lona fata faitaulaga.", "because he hath thrown down his altar."]]},
  {num:33,words:[["Ona faapotopoto faatasi ai lea o Mitiana uma lava,", "Then all the Midianites and the Amalekites and the children of the east were gathered together,"], ["ma Amaleka atoa ma tagata mai sasae, ua latou sopoia mai le vaitafe ,", "and went over,"], ["ua latou to lauapi i le vanu o Isereelu.", "and pitched in the valley of Jezreel."]]},
  {num:34,words:[["A ua ufitia Kitiona e le Agaga o Ieova;", "But the Spirit of the LORD came upon Gideon,"], ["ona ili ai lea e ia o le pu,", "and he blew a trumpet;"], ["ona faapotopotoina lea o Apieseru e mulimuli atu ia te ia.", "and Abiezer was gathered after him."]]},
  {num:35,words:[["Ua ia aauina atu sāvali ia Manase uma,", "And he sent messengers throughout all Manasseh;"], ["ua faapotopotoina foi i latou e mulimuli atu ia te ia;", "who also was gathered after him:"], ["ua ia aauina atu o sāvali ia Asera,", "and he sent messengers unto Asher,"], ["ma Sepulona,", "and unto Zebulun,"], ["ma Nafatali,", "and unto Naphtali;"], ["ona latou o ae ai lea e faafetaiai ia te i latou.", "and they came up to meet them."]]},
  {num:36,words:[["Ua faapea atu Kitiona i le Atua, Afai e te faaolaina Isaraelu i lo'u lima,", "And Gideon said unto God,"], ["e pei ona e fetalai mai ai,", "If thou wilt save Israel by mine hand,"], ["faauta mai, o a'u,", "as thou hast said,"]]},
  {num:37,words:[["ou te tuuina atu le fulufulu mamoe i le mea e sasa ai le saito;", "Behold,"], ["afai ua na o le fulufulu mamoe e i ai le sau,", "I will put a fleece of wool in the floor;"], ["a e matutu le laueleele uma,", "and if the dew be on the fleece only, and it be dry upon all the earth beside,"], ["ona ou iloa ai lea e te faaolaina Isaraelu i lo'u nei lima,", "then shall I know that thou wilt save Israel by mine hand,"], ["e pei ona e fetalai mai ai.", "as thou hast said."]]},
  {num:38,words:[["Ona faapea ai lava lea;", "And it was so:"], ["ua ala usu atu ia i le taeao,", "for he rose up early on the morrow,"], ["ona tatao ai lea e ia o le fulufulu mamoe,", "and thrust the fleece together,"], ["ua ia tāulia foi le sau nai le fulufulu mamoe,", "and wringed the dew out of the fleece,"], ["ua tumu le ipu i le suāvai.", "a bowl full of water."]]},
  {num:39,words:[["Ona fai atu lea o Kitiona i le Atua,", "And Gideon said unto God,"], ["Aua e te toatamai ia te au,", "Let not thine anger be hot against me,"], ["ua na o le toe upu ou te fai atu ai nei;", "and I will speak but this once:"], ["ou te aioi atu ia te oe,", "let me prove,"], ["ia toe tasi ona ou tofotofo i le fulufulu mamoe;", "I pray thee,"], ["ia matutu na o le fulufulu mamoe,", "but this once with the fleece;"], ["a o le lalueleele uma,", "let it now be dry only upon the fleece,"], ["ia i ai le sau.", "and upon all the ground let there be dew."]]},
  {num:40,words:[["Ua faapea lava ona faia e le Atua i lea lava po;", "And God did so that night:"], ["auā ua matutu na o le fulufulu mamoe, a o le laueleele uma,", "for it was dry upon the fleece only,"], ["sa i ai le sau.", "and there was dew on all the ground."]]},
];
renderVerseSet(jdg_ch_6_Verses, 'jdg-ch6-verses');

var jdg_ch_7_Verses = [
  {num:1,words:[["Ona ala usu atu ai lea o Ierupaala,", "Then Jerubbaal,"], ["o Kitiona lava lea,", "who is Gideon, and all the people that were with him,"], ["ma le nuu uma na ia te ia,", "rose up early,"], ["ua ia to lauapi e latalata ane i le vaipuna i Harota;", "and pitched beside the well of Harod:"], ["sa i ai le itu taua a Mitiana i le itu atu i matu ia i latou,", "so that the host of the Midianites were on the north side of them, by the hill of Moreh,"], ["e latalata ane i le mauga o More i le vanu.", "in the valley."]]},
  {num:2,words:[["Ua fetalai mai Ieova ia Kitiona,", "And the LORD said unto Gideon,"], ["E toatele naua le nuu o loo ia te oe;", "The people that are with thee are too many for me to give the Midianites into their hands,"], ["ou te le tuuina atu Mitiana i o latou lima, ne'i mitamita mai Isaraelu,", "lest Israel vaunt themselves against me,"], ["i o'u luma e faapea mai,", "saying,"], ["O lo'u lava lima ua ola ai a'u.", "Mine own hand hath saved me."]]},
  {num:3,words:[["O lenei,", "Now therefore go to,"], ["ia e alaga atu lava i le nuu ia latou lagona,", "proclaim in the ears of the people,"], ["ia faapea atu, Ai se mata'u ma gatete,", "saying,"], ["ina liliu atu ia,", "Whosoever is fearful and afraid,"], ["ma foi atu nai le mauga o Kiliata.", "let him return and depart early from mount Gilead."], ["Ona foi atu ai lea o le nuu e luafulu o afe ma afe e lua,", "And there returned of the people twenty and two thousand;"], ["a ua totoe le sefulu o afe.", "and there remained ten thousand."]]},
  {num:4,words:[["Ona fetalai mai ai lea o Ieova ia Kitiona,", "And the LORD said unto Gideon,"], ["E toatele pea le nuu;", "The people are yet too many;"], ["ia e aveina ifo i latou i le vai,", "bring them down unto the water,"], ["ona ou tofotofoina ai lea o i latou mo oe i lea mea;", "and I will try them for thee there:"], ["o le ou te fai atu ai ia te oe,", "and it shall be, that of whom I say unto thee,"], ["Lua te o ma lenei,", "This shall go with thee,"], ["ona oulua o ai lea ma ia;", "the same shall go with thee;"], ["o le ou te fai atu ai foi ia te oe,", "and of whomsoever I say unto thee,"], ["Lua te le o ma lenei,", "This shall not go with thee,"], ["ona le alu ai lea o ia.", "the same shall not go."]]},
  {num:5,words:[["Ua aveina ifo e ia le nuu i le vai,", "So he brought down the people unto the water:"], ["ona fetalai mai ai lea o Ieova ia Kitiona,", "and the LORD said unto Gideon,"], ["O i latou uma o e etoeto i o latou laulaufaiva i le vai,", "Every one that lappeth of the water with his tongue,"], ["e pei ona etoeto o le ulī,", "as a dog lappeth,"], ["e te tuuese atu ia te i latou;", "him shalt thou set by himself;"], ["e faapea foi i latou uma o e tootuli e inu ai.", "likewise every one that boweth down upon his knees to drink."]]},
  {num:6,words:[["Ua faitauina e ua tuu o latou lima i o latou gutu,", "And the number of them that lapped,"], ["ma etoeto ai le vai ,", "putting their hand to their mouth,"], ["ua tolu selau o ia tagata; a o le nuu uma ua totoe,", "were three hundred men:"], ["ua latou tootuli e inu i le vai.", "but all the rest of the people bowed down upon their knees to drink water."]]},
  {num:7,words:[["Ona fetalai mai ai lea o Ieova ia Kitiona,", "And the LORD said unto Gideon,"], ["O le tolu selau o tagata e na etoeto i le vai ou te faaola ai ia te outou,", "By the three hundred men that lapped will I save you,"], ["ma tuuina atu Mitiana i lou lima; a o le nuu uma ua totoe ,", "and deliver the Midianites into thine hand:"], ["ia taitasi ma alu i lona nuu.", "and let all the other people go every man unto his place."]]},
  {num:8,words:[["Ona ave ai lea e le nuu o mea e 'ai i o latou lima,", "So the people took victuals in their hand,"], ["ma a latou pu;", "and their trumpets:"], ["ona aauina atu ai lea e ia o Isaraelu uma ua totoe , ia taitasi ma alu i lona fale ie;", "and he sent all the rest of Israel every man unto his tent,"], ["a ua taofia e ia o ia tagata e tolu selau;", "and retained those three hundred men:"], ["o le itu taua foi a Mitiana ua i lalo i le vanu.", "and the host of Midian was beneath him in the valley."]]},
  {num:9,words:[["O lea lava po ua fetalai mai ai Ieova ia te ia,", "And it came to pass the same night,"], ["Ina tulai atu ia,", "that the LORD said unto him,"], ["ma e alu ifo i le itu tauā;", "Arise, get thee down unto the host;"], ["auā ua ou tuuina atu i latou i lou lima.", "for I have delivered it into thine hand."]]},
  {num:10,words:[["A e afai e te fefe ona alu ifo, lua te o ifo i le itu tauā,", "But if thou fear to go down,"], ["oulua ma Fora lau auauna;", "go thou with Phurah thy servant down to the host:"]]},
  {num:11,words:[["e te faalogo i mea ua latou fetautalatalai ai;", "And thou shalt hear what they say;"], ["e mulimuli ane ona malosi ai lea oe e alu ifo ai i le itu taua. Ona o ifo ai lea o ia ma Fora lana auauna i 'au a le itu taua e pito mai.", "and afterward shall thine hands be strengthened to go down unto the host. Then went he down with Phurah his servant unto the outside of the armed men that were in the host."]]},
  {num:12,words:[["Ua taooto i le vanu Mitiana, ma Amaleka,", "And the Midianites and the Amalekites and all the children of the east lay along in the valley like grasshoppers for multitude;"], ["atoa ma tagata uma mai sasae, e pei o sē ina taa tele;", "and their camels were without number,"], ["e le mafaitaulia a latou kamela, o pei o le oneone i le matafaga ona tele.", "as the sand by the sea side for multitude."]]},
  {num:13,words:[["Ua oo atu Kitiona,", "And when Gideon was come,"], ["faauta,", "behold,"], ["o loo ta'u atu e le tasi tagata o lana miti i le tasi,", "there was a man that told a dream unto his fellow,"], ["ua faapea atu,", "and said,"], ["Faauta,", "Behold,"], ["ua fai la'u miti;", "I dreamed a dream,"], ["faauta foi,", "and,"], ["na taavalevale le tasi potoi karite i le itu taua a Mitiana,", "lo,"], ["ua oo i le tasi fale ie,", "a cake of barley bread tumbled into the host of Midian,"], ["ua toia ai,", "and came unto a tent,"], ["ona paū ai lea,", "and smote it that it fell,"], ["ua mafuli i lalo,", "and overturned it,"], ["ua taatia lava le fale ie.", "that the tent lay along."]]},
  {num:14,words:[["Ona tali mai ai lea o le tasi,", "And his fellow answered and said,"], ["E leai se isi mea lenei,", "This is nothing else save the sword of Gideon the son of Joash,"], ["ua na o le pelu a Kitiona le atalii o Ioasa,", "a man of Israel:"], ["o le tagata o Isaraelu lea;", "for into his hand hath God delivered Midian,"], ["ua tuuina atu e le Atua i lona lima o Mitiana ma le itu taua uma.", "and all the host."]]},
  {num:15,words:[["Ua faalogo Kitiona i le tala o le miti ma lona faamatalaga,", "And it was so, when Gideon heard the telling of the dream,"], ["ona ifo ai lea o ia i le Atua . Ua toe foi atu i le itu taua a Isaraelu,", "and the interpretation thereof,"], ["ua ia faapea atu ai,", "that he worshipped, and returned into the host of Israel,"], ["Tutū mai ia,", "and said,"], ["auā ua tuuina mai i o outou lima e Ieova o le itu taua a Mitiana.", "Arise; for the LORD hath delivered into your hand the host of Midian."]]},
  {num:16,words:[["Ua ia vaea le tolu o selau i 'au e tolu,", "And he divided the three hundred men into three companies,"], ["ua ia avatu foi pu i lima o i latou uma,", "and he put a trumpet in every man's hand,"], ["ma kate le 'i'i'o,", "with empty pitchers,"], ["ma sulu i totonu o kate.", "and lamps within the pitchers."]]},
  {num:17,words:[["Ua ia faapea atu ia i latou,", "And he said unto them, Look on me,"], ["Ia outou vaavaai mai ia te au,", "and do likewise:"], ["ma ia faaa'oa'o mai ai lava;", "and,"], ["faauta foi,", "behold, when I come to the outside of the camp,"], ["a a'u oo i le toagālauapi e pito mai,", "it shall be that, as I do,"], ["ona outou faia lava lea e pei ona ou faia.", "so shall ye do."]]},
  {num:18,words:[["A matou ilia pu,", "When I blow with a trumpet,"], ["o a'u ma i latou uma o ia te au,", "I and all that are with me,"], ["outou foi tou te ilia pu ia soo lava le togālauapi uma,", "then blow ye the trumpets also on every side of all the camp, and say,"], ["ma outou fai ane,", "The sword of the LORD,"], ["O le pelu a Ieova ma Kitiona.", "and of Gideon."]]},
  {num:19,words:[["Ona oo atu lea o Kitiona ma tagata e toaselau ua ia te ia i le togālauapi e pito mai,", "So Gideon,"], ["i le amataga o le leoleoga i le itu po vaeloto;", "and the hundred men that were with him,"], ["ua latou faatoa laga matāmoe;", "came unto the outside of the camp in the beginning of the middle watch; and they had but newly set the watch:"], ["ona latou ilia lava lea o pu,", "and they blew the trumpets,"], ["ma taei i kate i o latou lima.", "and brake the pitchers that were in their hands."]]},
  {num:20,words:[["Ona ilia lea o pu e 'au e tolu,", "And the three companies blew the trumpets,"], ["ma latou taei i kate,", "and brake the pitchers,"], ["ua 'u'u foi sulu i o latou lima tauagavale,", "and held the lamps in their left hands, and the trumpets in their right hands to blow withal:"], ["o pu foi i o latou lima taumatau e ili ai;", "and they cried,"], ["ona latou alalaga atu ai lea,", "The sword of the LORD,"], ["O le pelu a Ieova ma Kitiona.", "and of Gideon."]]},
  {num:21,words:[["Ua latou tutū e taitasi i le mea sa i ai e sio ai le togālauapi;", "And they stood every man in his place round about the camp:"], ["ona taufetuli ai lea o le itu taua uma,", "and all the host ran,"], ["ua alalaga,", "and cried,"], ["ua sosola lava.", "and fled."]]},
  {num:22,words:[["Ua ilia pu e le tolu selau,", "And the three hundred blew the trumpets,"], ["ona faaoo atu ai lea e Ieova o le pelu a le tasi i le tasi i le itu taua uma;", "and the LORD set every man's sword against his fellow,"], ["ona sosola ai lea o le itu taua i Peteseta i Sererata,", "even throughout all the host: and the host fled to Beth-shittah in Zererath,"], ["ua oo i le tuaoi o Apelemeola,", "and to the border of Abel-meholah,"], ["e lata ane i Tapata.", "unto Tabbath."]]},
  {num:23,words:[["Ua faapotopotoina tagata o Isaraelu mai Nafatali,", "And the men of Israel gathered themselves together out of Naphtali,"], ["ma Asera,", "and out of Asher,"], ["ma Manase uma lava,", "and out of all Manasseh,"], ["ona latou tuliloaina ai lea o Mitiana.", "and pursued after the Midianites."]]},
  {num:24,words:[["Ua aauina atu foi e Kitiona o sāvali i le mauga uma o Efaraima, ua faapea atu,", "And Gideon sent messengers throughout all mount Ephraim,"], ["Ina faaifo ia, e pupuni ia Mitiana,", "saying,"], ["ia muamua ia te i latou,", "Come down against the Midianites,"], ["ma ia outou maua ai le vai, e oo atu i Petepara ma Ioritana.", "and take before them the waters unto Beth-barah and Jordan."], ["Ona faapotopoto ai lea o tagata uma o Efaraima,", "Then all the men of Ephraim gathered themselves together,"], ["ma latou maua le vai e oo atu i Petepara ma Ioritana.", "and took the waters unto Beth-barah and Jordan."]]},
  {num:25,words:[["Ona latou maua ai lea o tamaalii o Mitiana e toalua,", "And they took two princes of the Midianites,"], ["o Oreva ma Seeva;", "Oreb and Zeeb;"], ["ua latou fasia foi Oreva i luga o le papa o Oreva,", "and they slew Oreb upon the rock Oreb, and Zeeb they slew at the winepress of Zeeb,"], ["o Seeva foi ua latou fasia i le mea e soli ai vine o Seeva;", "and pursued Midian,"], ["ua latou tuliloa ia Mitiana. Ua latou avatu ulu o Oreva ma Seeva ia Kitiona i le la itu o Ioritana.", "and brought the heads of Oreb and Zeeb to Gideon on the other side Jordan."]]},
];
renderVerseSet(jdg_ch_7_Verses, 'jdg-ch7-verses');

var jdg_ch_8_Verses = [
  {num:1,words:[["Ona faapea mai ai lea o tagata o Efaraima ia te ia,", "And the men of Ephraim said unto him,"], ["Se a lenei mea ua e faia ia te i matou,", "Why hast thou served us thus, that thou calledst us not,"], ["ina ua e le amia mai i matou ina ua e alu atu e tau ma Mitiana? Ua latou matuā finau tele mai ia te ia.", "when thou wentest to fight with the Midianites? And they did chide with him sharply."]]},
  {num:2,words:[["Ona faapea atu ai lea o ia ia te i latou,", "And he said unto them,"], ["Se a se mea ua ou faia nei e tusa ma la outou? E lei sili ona lelei ea nai toe fuifui vine o Efaraima i le taugāvine o Apieseru?", "What have I done now in comparison of you? Is not the gleaning of the grapes of Ephraim better than the vintage of Abiezer?"]]},
  {num:3,words:[["Ua tuuina atu e le Atua i o outou lima o tamaalii o Mitiana,", "God hath delivered into your hands the princes of Midian,"], ["o Oreva ma Seeva;", "Oreb and Zeeb:"], ["se a foi se mea ou te mafaia ona fai e tusa ma outou? Ona faalauleleiina ai lea o i latou ia te ia,", "and what was I able to do in comparison of you? Then their anger was abated toward him,"], ["ina ua fai atu e ia lena upu.", "when he had said that."]]},
  {num:4,words:[["Ua oo atu Kitiona i Ioritana,", "And Gideon came to Jordan, and passed over,"], ["ua sopoia atu e ia atoa ma le tolu selau o tagata ua ia te ia,", "he,"], ["ua lailoa i latou,", "and the three hundred men that were with him,"], ["a e tuliloa lava.", "faint, yet pursuing them."]]},
  {num:5,words:[["Ona fai atu ai lea o ia i tagata o Sukota,", "And he said unto the men of Succoth,"], ["Ia outou avane ni potoi areto i le nuu ua mulimuli mai ia te au,", "Give, I pray you,"], ["auā ua lailoa i latou,", "loaves of bread unto the people that follow me;"], ["a o a'u,", "for they be faint, and I am pursuing after Zebah and Zalmunna,"], ["ou te tuliloa atu lava ia Seva ma Salemuna o tupu o Mitiana.", "kings of Midian."]]},
  {num:6,words:[["Ona faapea mai ai lea o alii o Sukota,", "And the princes of Succoth said, Are the hands of Zebah and Zalmunna now in thine hand,"], ["Po ua e maua nei ea o Seva ma Salemuna matou te avatu ai mea e 'ai ma au 'au.", "that we should give bread unto thine army?"]]},
  {num:7,words:[["Ona faapea atu ai lea o Kitiona,", "And Gideon said,"], ["A tuuina mai e Ieova o Seva ma Salemuna i lo'u lima,", "Therefore when the LORD hath delivered Zebah and Zalmunna into mine hand,"], ["ona ou solia ai lea o outou tino i laau tuitui mai le vao ma mea talatala.", "then I will tear your flesh with the thorns of the wilderness and with briers."]]},
  {num:8,words:[["Ua alu ae ia nai lea mea i Penueli,", "And he went up thence to Penuel,"], ["ua faapea foi ona fai atu o ia ia te i latou. Ona tali mai ai lea ia te ia o tagata o Penueli,", "and spake unto them likewise:"], ["e pei ona tali mai e tagata o Sukota.", "and the men of Penuel answered him as the men of Succoth had answered him."]]},
  {num:9,words:[["Ona fai atu ai lea o ia i tagata o Penueli,", "And he spake also unto the men of Penuel,"], ["ua faapea atu,", "saying,"], ["Pe a a'u foi mai ma le manuia,", "When I come again in peace,"], ["ona ou soloia lava lea o lena 'olo.", "I will break down this tower."]]},
  {num:10,words:[["Sa i Karekori o Seva,", "Now Zebah and Zalmunna were in Karkor,"], ["ma Salemuna,", "and their hosts with them,"], ["atoa ma la la itu taua faatasi ma i laua, pe sefulu o afe ma afe e lima,", "about fifteen thousand men,"], ["na o i latou ia ua totoe o le itu taua uma a tagata mai sasae;", "all that were left of all the hosts of the children of the east:"], ["auā na fasia tagata e fai pelu e selau afe ma afe e luafulu.", "for there fell an hundred and twenty thousand men that drew sword."]]},
  {num:11,words:[["Ona alu ae ai lea o Kitiona i le ala o e ua mau i fale ie i sasae o Nopa ma Iakepea;", "And Gideon went up by the way of them that dwelt in tents on the east of Nobah and Jogbehah,"], ["ona faia ai lea e ia o le itu taua,", "and smote the host:"], ["auā sa nofo talanoa lava le itu taua.", "for the host was secure."]]},
  {num:12,words:[["Ua sosola foi Seva ma Salemuna,", "And when Zebah and Zalmunna fled,"], ["ona tuliloa atu lea e ia ia te i laua,", "he pursued after them,"], ["ua ia maua lava o tupu o Mitiana e toalua,", "and took the two kings of Midian,"], ["o Seva ma Salemuna;", "Zebah and Zalmunna,"], ["ua ia faagateteina le itu taua uma.", "and discomfited all the host."]]},
  {num:13,words:[["Ona foi mai lea o Kitiona le atalii o Ioasa mai le taua, ua ui ane i le aega o Heresa.", "And Gideon the son of Joash returned from battle before the sun was up,"]]},
  {num:14,words:[["Ona maua lea e ia o le tasi taulealea o tagata o Sukota,", "And caught a young man of the men of Succoth,"], ["ua ia fesili ia te ia,", "and enquired of him:"], ["ona tusi ai lea e ia ia te ia i alii o Sukota ma o latou toeaina,", "and he described unto him the princes of Succoth, and the elders thereof,"], ["o tagata e toafitugafulu ma le toafitu.", "even threescore and seventeen men."]]},
  {num:15,words:[["Ona alu atu ai lea o ia i tagata o Sukota,", "And he came unto the men of Succoth,"], ["ua faapea atu ai,", "and said,"], ["Faauta,", "Behold Zebah and Zalmunna,"], ["o Seva ma Salemuna na outou tauemua mai ai au,", "with whom ye did upbraid me,"], ["ua faapea mai,", "saying,"], ["Po ua e maua nei ea o Seva ma Salemuna,", "Are the hands of Zebah and Zalmunna now in thine hand,"], ["matou te avatu ai mea e 'ai mā ou tagata ua lailoa.", "that we should give bread unto thy men that are weary?"]]},
  {num:16,words:[["Ona ave ai lea e ia o toeaina o le aai,", "And he took the elders of the city,"], ["ma laau tuitui mai le vao ma mea talatala,", "and thorns of the wilderness and briers,"], ["ua ia aoaiina ai tagata Sukota.", "and with them he taught the men of Succoth."]]},
  {num:17,words:[["Ona soloia lea e ia o le 'olo o Penueli,", "And he beat down the tower of Penuel,"], ["ma ua fasioti i tagata o le aai.", "and slew the men of the city."]]},
  {num:18,words:[["Ona fai atu ai lea o ia ia Seva ma Salemuna,", "Then said he unto Zebah and Zalmunna,"], ["Pe ni tagata faapefea na outou fasiotia i Tapora? Ona la fai mai ai lea,", "What manner of men were they whom ye slew at Tabor? And they answered,"], ["E pei o oe sa faapea foi i latou;", "As thou art, so were they;"], ["e taitasi ma aulelei e pei ni alo o se tupu.", "each one resembled the children of a king."]]},
  {num:19,words:[["Ona fai atu ai lea o ia,", "And he said,"], ["O o'u uso ia,", "They were my brethren,"], ["o tama a lo'u tinā i latou;", "even the sons of my mother: as the LORD liveth,"], ["o loo soifua Ieova,", "if ye had saved them alive,"], ["ana oulua faaolaina i latou po ua ou le fasiotia oulua.", "I would not slay you."]]},
  {num:20,words:[["Ona fai atu ai lea o ia ia Ietero lana ulumatua,", "And he said unto Jether his firstborn,"], ["Ina tulai mai ia,", "Up,"], ["ma e fasiotia i laua.", "and slay them."], ["A ua le se'i e le tama lana pelu ina ua fefe o ia,", "But the youth drew not his sword: for he feared,"], ["auā o le tama lava ia.", "because he was yet a youth."]]},
  {num:21,words:[["Ona fai mai ai lea o Seva ma Salemuna,", "Then Zebah and Zalmunna said,"], ["Ina e tulai mai ia oe,", "Rise thou,"], ["ma fasi ia te i maua;", "and fall upon us: for as the man is,"], ["auā e pei o le tagata e faapea foi lona malosi.", "so is his strength."], ["Ona tulai atu ai lea o Kitiona,", "And Gideon arose,"], ["ua ia fasiotia Seva ma Salemuna;", "and slew Zebah and Zalmunna,"], ["ona ave ese ai lea e ia o mea na asoa ai i ua o a la kamela.", "and took away the ornaments that were on their camels' necks."]]},
  {num:22,words:[["Ona fai atu ai lea o tagata o Isaraelu ia Kitiona,", "Then the men of Israel said unto Gideon,"], ["Ia e pule ia te i matou,", "Rule thou over us,"], ["o oe,", "both thou,"], ["ma lou atalii,", "and thy son,"], ["ma le atalii o lou atalii;", "and thy son's son also:"], ["auā na e faaolaina mai i matou ai lima o Mitiana.", "for thou hast delivered us from the hand of Midian."]]},
  {num:23,words:[["Ua fai mai Kitiona ia te i latou,", "And Gideon said unto them,"], ["Ou te le pule ia te outou,", "I will not rule over you,"], ["e le pule foi lo'u atalii ia te outou;", "neither shall my son rule over you:"], ["e pule lava Ieova ia te outou.", "the LORD shall rule over you."]]},
  {num:24,words:[["Ua fai mai foi Kitiona ia te i latou,", "And Gideon said unto them,"], ["Ou te ole atu ia te outou i le tasi mea;", "I would desire a request of you,"], ["ia outou au mai ia te au e taitasi le tagata ma le mama o ana lava vete; (auā sa ia te i latou o mama auro;", "that ye would give me every man the earrings of his prey. (For they had golden earrings,"], ["auā o sa Isamaelī i latou.)", "because they were Ishmaelites.)"]]},
  {num:25,words:[["Ona fai atu ai lea o i latou ia te ia,", "And they answered,"], ["Matou te avatu lava. Ona latou folasia lea o le ofu,", "We will willingly give them. And they spread a garment,"], ["ma lafo i ai e taitasi le tagata ma le mama o ana lava vete.", "and did cast therein every man the earrings of his prey."]]},
  {num:26,words:[["O le mamafa o mama auro na ia ole atu ai,", "And the weight of the golden earrings that he requested was a thousand and seven hundred shekels of gold;"], ["o sekeli auro ia e tasi le afe ma le fitu o selau,", "beside ornaments,"], ["a e tuu ia o mea na asoa ai, ma mama i taliga,", "and collars,"], ["ma ofu pāuli na i ai i tupu o Mitiana,", "and purple raiment that was on the kings of Midian,"], ["atoa ma filifili auro sa i ua o a la kamela.", "and beside the chains that were about their camels' necks."]]},
  {num:27,words:[["Ona fai ai lea e Kitiona o le efota,", "And Gideon made an ephod thereof,"], ["ua tuu ai e ia i lana aai o Ofira;", "and put it in his city,"], ["ua o atu i ai o Isaraelu uma,", "even in Ophrah: and all Israel went thither a whoring after it:"], ["ua mulilua ai;", "which thing became a snare unto Gideon,"], ["ona avea lea o lenei mea ma mailei ia Kitiona ma lona aiga.", "and to his house."]]},
  {num:28,words:[["Ua toilalo lava Mitiana i luma o le fanauga a Isaraelu,", "Thus was Midian subdued before the children of Israel,"], ["ua latou le toe ea lava. Ona filemu ai lea o le nuu i tausaga e fagafulu i ona po o Kitiona.", "so that they lifted up their heads no more. And the country was in quietness forty years in the days of Gideon."]]},
  {num:29,words:[["Ona alu ai lea o Ierupaala le atalii o Ioasa, ua nofo o ia i lona lava aiga.", "And Jerubbaal the son of Joash went and dwelt in his own house."]]},
  {num:30,words:[["Sa ia Kitiona ona atalii e toafitugafulu na fanaua lava e ia;", "And Gideon had threescore and ten sons of his body begotten:"], ["auā na toatele lava ana avā.", "for he had many wives."]]},
  {num:31,words:[["O lana palake sa i Sekema,", "And his concubine that was in Shechem,"], ["na fanau foi e ia se atalii mona;", "she also bare him a son,"], ["ona faaigoaina ai lea o ia o Apimeleko.", "whose name he called Abimelech."]]},
  {num:32,words:[["Ua oti foi Kitiona le atalii o Ioasa,", "And Gideon the son of Joash died in a good old age,"], ["ua toeaina lava ia;", "and was buried in the sepulchre of Joash his father,"], ["na tanu foi o ia i le tuugamau o Ioasa lona tamā i Ofira o sa Apieserū.", "in Ophrah of the Abiezrites."]]},
  {num:33,words:[["Ua oti Kitiona,", "And it came to pass,"], ["ona toe liliu ese ai lea o le fanauga a Isaraelu e mulimuli ia Paala,", "as soon as Gideon was dead,"], ["e mulilua ai,", "that the children of Israel turned again, and went a whoring after Baalim,"], ["ua latou faia foi o Paala-perita mo latou atua.", "and made Baal-berith their god."]]},
  {num:34,words:[["Ua le manatua e le fanauga a Isaraelu o Ieova lo latou Atua, o le na laveaiina i latou ai lima o i latou uma lava e na vagavagai,", "And the children of Israel remembered not the LORD their God,"], ["o e ita ia te i latou.", "who had delivered them out of the hands of all their enemies on every side:"]]},
  {num:35,words:[["E lei agalelei atu foi i latou i le aiga o Ierupaala,", "Neither shewed they kindness to the house of Jerubbaal,"], ["o Kitiona lea,", "namely, Gideon,"], ["e tusa ma mea uma lava na agalelei atu ai o ia ia Isaraelu.", "according to all the goodness which he had shewed unto Israel."]]},
];
renderVerseSet(jdg_ch_8_Verses, 'jdg-ch8-verses');

var jdg_ch_9_Verses = [
  {num:1,words:[["Ona alu atu ai lea o Apimeleko le atalii o Ierupaala i Sekema i tuagane o lona tinā,", "And Abimelech the son of Jerubbaal went to Shechem unto his mother's brethren,"], ["ua tautalatala ma i latou atoa ma le aiga uma lava o le tamā o lona tinā,", "and communed with them, and with all the family of the house of his mother's father,"], ["ua faapea atu,", "saying,"]]},
  {num:2,words:[["Se'i outou matuā fai atu i tagata uma o Sekema,", "Speak, I pray you,"], ["Po o i fea ona malie ia te outou,", "in the ears of all the men of Shechem,"], ["pe pule ia te outou o atalii uma o Ierupaala o tagata e toafitugafulu lava ia,", "Whether is better for you, either that all the sons of Jerubbaal,"], ["pe pule ia te outou le tagata e toatasi? Ia outou manatua foi,", "which are threescore and ten persons,"], ["o a'u nei o outou ivi ma o outou aano.", "reign over you, or that one reign over you? remember also that I am your bone and your flesh."]]},
  {num:3,words:[["Ona tautala lea ia te ia o tuagane o lona tinā i tagata uma o Sekema ia upu uma;", "And his mother's brethren spake of him in the ears of all the men of Shechem all these words:"], ["ona uai atu ai lea o latou loto ia Apimeleko,", "and their hearts inclined to follow Abimelech;"], ["auā ua latou faapea ane,", "for they said,"], ["O lo tatou uso lava ia.", "He is our brother."]]},
  {num:4,words:[["Ona latou avatu ai lea ia te ia o tupe e fitugafulu mai le fale o Paala-perita,", "And they gave him threescore and ten pieces of silver out of the house of Baal-berith,"], ["na totogi a'i e Apimeleko o tagata faatauvaa ma e ulavavale,", "wherewith Abimelech hired vain and light persons,"], ["ina ia latou mulimuli atu ia te ia.", "which followed him."]]},
  {num:5,words:[["Ua alu atu ia i le aiga o lona tamā i Ofira,", "And he went unto his father's house at Ophrah,"], ["ona fasiotia lea e ia i luga o le maa e tasi ona lava uso,", "and slew his brethren the sons of Jerubbaal,"], ["o atalii o Ierupaala e toafitugafulu tagata;", "being threescore and ten persons,"], ["a ua sao Iotama le atalii o Ierupaala,", "upon one stone:"], ["o le uii ia;", "notwithstanding yet Jotham the youngest son of Jerubbaal was left;"], ["auā na lafi lava ia.", "for he hid himself."]]},
  {num:6,words:[["Ona faapotopoto ai lea o tagata uma o Sekema,", "And all the men of Shechem gathered together,"], ["atoa ma le aiga uma o Milo;", "and all the house of Millo,"], ["ona latou o lea,", "and went, and made Abimelech king,"], ["ma latou tofia Apimeleko e fai ma tupu i le mea ua tu ai le aluna i Sekema.", "by the plain of the pillar that was in Shechem."]]},
  {num:7,words:[["Ona ta'ua atu lea ia Iotama;", "And when they told it to Jotham,"], ["ona alu ai lea o ia,", "he went and stood in the top of mount Gerizim,"], ["ma tu i le tumutumu o le mauga o Keresema,", "and lifted up his voice,"], ["ua ia leo tele,", "and cried,"], ["ma alaga, ua faapea atu ia te i latou,", "and said unto them,"], ["Outou tagata o Sekema e,", "Hearken unto me,"], ["ia outou faalogologo mai ia te au,", "ye men of Shechem,"], ["ina ia faafofoga le Atua ia te outou,", "that God may hearken unto you."]]},
  {num:8,words:[["Na o atu laau e faauuina se tupu mo i latou;", "The trees went forth on a time to anoint a king over them;"], ["ona latou fai atu ai lea i le olive,", "and they said unto the olive tree,"], ["Ina fai ia oe mo matou tupu.", "Reign thou over us."]]},
  {num:9,words:[["A ua fai mai le olive ia te i latou,", "But the olive tree said unto them,"], ["Ou te tuuna ea lo'u lololo,", "Should I leave my fatness,"], ["o le mea e faamamafiina atu ai le Atua atoa ma tagata,", "wherewith by me they honour God and man,"], ["i lo'u alu ai e pule i laau?", "and go to be promoted over the trees?"]]},
  {num:10,words:[["Ona fai atu ai lea o laau i le mati,", "And the trees said to the fig tree,"], ["Ina sau ia oe,", "Come thou,"], ["e fai oe mo matou tupu.", "and reign over us."]]},
  {num:11,words:[["A ua fai mai le mati ia te i latou,", "But the fig tree said unto them,"], ["Ou te tuuna ea lo'u suamalie,", "Should I forsake my sweetness,"], ["ma o'u fua lelei,", "and my good fruit,"], ["i lo'u alu ai e pule i laau?", "and go to be promoted over the trees?"]]},
  {num:12,words:[["Ua fai atu foi laau i le vine,", "Then said the trees unto the vine,"], ["Ina sau ia oe,", "Come thou,"], ["e fai oe mo matou tupu.", "and reign over us."]]},
  {num:13,words:[["Ona fai mai ai lea o le vine ia te i latou,", "And the vine said unto them,"], ["Ou te tuuna ea lo'u uaina,", "Should I leave my wine,"], ["o le mea e faafiafia i le Atua atoa ma tagata,", "which cheereth God and man,"], ["i lo'u alu ai e pule i laau?", "and go to be promoted over the trees?"]]},
  {num:14,words:[["Ua fai atu foi laau uma i le laau tuitui,", "Then said all the trees unto the bramble,"], ["Ina sau ia oe,", "Come thou,"], ["e fai oe mo matou tupu.", "and reign over us."]]},
  {num:15,words:[["Ona fai mai ai lea o le laau tuitui i laau,", "And the bramble said unto the trees,"], ["Afai tou te faamaoni ona faauuina o a'u e fai mo outou tupu,", "If in truth ye anoint me king over you,"], ["ia outou o mai, ia outou faatuatua mai i lo'u paolo;", "then come and put your trust in my shadow:"], ["a e afai e leai,", "and if not,"], ["ia alu atu le afi ai le laau tuitui,", "let fire come out of the bramble,"], ["ma faaumatia arasi o Lepanona.", "and devour the cedars of Lebanon."]]},
  {num:16,words:[["O lenei,", "Now therefore,"], ["afai ua faamaoni ma ua tonu la outou amio,", "if ye have done truly and sincerely,"], ["ina ua outou tofia o Apimeleko e fai ma tupu;", "in that ye have made Abimelech king,"], ["afai foi ua outou agalelei atu ia Ierupaala ma lona aiga,", "and if ye have dealt well with Jerubbaal and his house,"], ["ma ua outou faia ia te ia e tusa ma mea na ia faia;", "and have done unto him according to the deserving of his hands;"]]},
  {num:17,words:[["auā o lo'u tamā na taulia le taua mo outou,", "(For my father fought for you, and adventured his life far,"], ["na ia tuulafoaiina lona ola ina ia laveaiina ai outou ai lima o Mitiana;", "and delivered you out of the hand of Midian:"]]},
  {num:18,words:[["a ua laga mai outou i le aso nei i le aiga o lo'u tamā,", "And ye are risen up against my father's house this day, and have slain his sons,"], ["ma ua outou fasiotia ona atalii,", "threescore and ten persons,"], ["o tagata e toafitugafulu,", "upon one stone,"], ["i luga o le maa e tasi;", "and have made Abimelech, the son of his maidservant,"], ["o Apimeleko foi o le tama a lana auauna fafine ua outou faia o ia ma tupu o tagata o Sekema,", "king over the men of Shechem, because he is your brother;"], ["auā o lo outou uso lava ia.", ")"]]},
  {num:19,words:[["A e afai ua faamaoni ma ua tonu la outou amio ia Ierupaala ma lona aiga i lenei lava aso,", "If ye then have dealt truly and sincerely with Jerubbaal and with his house this day,"], ["ia outou fiafia lava ia Apimeleko,", "then rejoice ye in Abimelech,"], ["o ia foi ia fiafia lava ia te outou.", "and let him also rejoice in you:"]]},
  {num:20,words:[["A e afai e leai,", "But if not, let fire come out from Abimelech,"], ["ia alu atu le afi ai ia Apimeleko e faaumatia ai tagata o Sekema ma le aiga o Milo;", "and devour the men of Shechem, and the house of Millo; and let fire come out from the men of Shechem,"], ["ia alu atu foi le afi ai tagata o Sekema ma le aiga o Milo e faaumatia ai Apimeleko.", "and from the house of Millo, and devour Abimelech."]]},
  {num:21,words:[["Ona tele vave ai lea o Iotama,", "And Jotham ran away,"], ["ua sola lava ia,", "and fled,"], ["ua alu atu i Peeri,", "and went to Beer, and dwelt there,"], ["ua ia nofo ai ona o Apimeleko lona uso.", "for fear of Abimelech his brother."]]},
  {num:22,words:[["Na pule Apimeleko ia Isaraelu i tausaga e tolu;", "When Abimelech had reigned three years over Israel,"]]},
  {num:23,words:[["ona tuuina atu ai lea e le Atua o le loto leaga ia Apimeleko ma tagata o Sekema;", "Then God sent an evil spirit between Abimelech and the men of Shechem;"], ["ona faa'ole'ole ai lea o tagata o Sekema ia Apimeleko;", "and the men of Shechem dealt treacherously with Abimelech:"]]},
  {num:24,words:[["ina ia oo le saua na faia i atalii o Ierupaala e toafitugafulu,", "That the cruelty done to the threescore and ten sons of Jerubbaal might come,"], ["ma ia tauia lo latou toto ia Apimeleko lo latou uso,", "and their blood be laid upon Abimelech their brother,"], ["na na fasiotia i latou,", "which slew them; and upon the men of Shechem,"], ["atoa ma tagata o Sekema e na fesoasoani ia te ia i le fasiga o ona uso.", "which aided him in the killing of his brethren."]]},
  {num:25,words:[["Ua tofia e tagata o Sekema nisi e lamalama ia te ia i tumutumu o mauga;", "And the men of Shechem set liers in wait for him in the top of the mountains,"], ["ua latou faoa mea a i latou uma o e ui ane ia i latou i lea ala;", "and they robbed all that came along that way by them:"], ["ona ta'u atu ai lea ia Apimeleko.", "and it was told Abimelech."]]},
  {num:26,words:[["Ona o mai ai lea o Kaala le atalii o Epeto ma ona uso,", "And Gaal the son of Ebed came with his brethren,"], ["ua latou o atu i Sekema;", "and went over to Shechem:"], ["ona faalagolago ai lea ia te ia o tagata o Sekema.", "and the men of Shechem put their confidence in him."]]},
  {num:27,words:[["Ua latou o atu i le fanua,", "And they went out into the fields,"], ["ua latou tau vine i o latou tovine,", "and gathered their vineyards,"], ["ua latou solia foi fua o le vine ,", "and trode the grapes,"], ["ua pepese fiafia i latou; ua latou o atu foi i le malumalu o lo latou atua,", "and made merry,"], ["na latou aai,", "and went into the house of their god,"], ["ma inu,", "and did eat and drink,"], ["ma ua latou fetuu ia Apimeleko.", "and cursed Abimelech."]]},
  {num:28,words:[["Ona faapea atu ai lea o Kaala le atalii o Epeto,", "And Gaal the son of Ebed said,"], ["Po o ai ea Apimeleko,", "Who is Abimelech,"], ["po o ai foi Sekema tatou te auauna i ai? E le o le atalii o Ierupaala ea? O Sepula foi o le ua tofia e ia e pule? Ia outou auauna i tagata o Hamoro le tamā o Sekema;", "and who is Shechem, that we should serve him? is not he the son of Jerubbaal? and Zebul his officer? serve the men of Hamor the father of Shechem:"], ["se a le mea tatou te auauna ai ia te ia?", "for why should we serve him?"]]},
  {num:29,words:[["E, ana ia te au le pule i le nuu nei,", "And would to God this people were under my hand! then would I remove Abimelech. And he said to Abimelech,"], ["po ua ou ave ese ai ia Apimeleko! Ua faapea atu foi o ia ia Apimeleko,", "Increase thine army,"], ["Ina faatoatele ia au 'au, ma e sau.", "and come out."]]},
  {num:30,words:[["Ua faalogo foi Sepula le alii o le aai i upu a Kaala le atalii o Epeto,", "And when Zebul the ruler of the city heard the words of Gaal the son of Ebed,"], ["ona matuā tupu ai lea o lona ita.", "his anger was kindled."]]},
  {num:31,words:[["Ua ia aauina atu faalilolilo le sāvali ia Apimeleko,", "And he sent messengers unto Abimelech privily,"], ["e faapea atu,", "saying,"], ["Faauta,", "Behold,"], ["o Kaala le atalii o Epeto ma ona uso,", "Gaal the son of Ebed and his brethren be come to Shechem;"], ["ua latou o mai i Sekema;", "and,"], ["faauta foi,", "behold,"], ["ua latou lagaina le aai e fou ia te oe.", "they fortify the city against thee."]]},
  {num:32,words:[["O lenei,", "Now therefore up by night,"], ["ia e laga po mai oe, atoa ma le nuu ua ia te oe,", "thou and the people that is with thee,"], ["ma e tanu 'au i le vao;", "and lie in wait in the field:"]]},
  {num:33,words:[["a oo foi i le taeao i le faatoa alu ae o le la,", "And it shall be,"], ["e te laga mai ai,", "that in the morning, as soon as the sun is up,"], ["ma e faasalalau mai i luma o le aai;", "thou shalt rise early,"], ["faauta foi,", "and set upon the city:"], ["o ia ma le nuu ua ia te ia,", "and,"], ["a latou o atu ia te oe,", "behold, when he and the people that is with him come out against thee,"], ["ona faitalia lea oe se mea e te faia ia te ia.", "then mayest thou do to them as thou shalt find occasion."]]},
  {num:34,words:[["Ona laga po ai lea o Apimeleko atoa ma le nuu uma ua ia te ia,", "And Abimelech rose up, and all the people that were with him,"], ["ua latou tanu 'au e latalata ane i Sekema o 'au e fa.", "by night, and they laid wait against Shechem in four companies."]]},
  {num:35,words:[["Ua alu atu foi Kaala le atalii o Epeto,", "And Gaal the son of Ebed went out,"], ["ua tu foi o ia i le puipui o le faitotoa o le aai;", "and stood in the entering of the gate of the city:"], ["ona laga mai ai lea o Apimeleko,", "and Abimelech rose up, and the people that were with him,"], ["ma le nuu ua ia te ia sa tanu 'au.", "from lying in wait."]]},
  {num:36,words:[["Ua iloa atu e Kaala le nuu,", "And when Gaal saw the people,"], ["ona faapea atu ai lea o ia ia Sepula,", "he said to Zebul, Behold,"], ["Faauta i le nuu ua alu ifo i tumutumu o mauga.", "there come people down from the top of the mountains."], ["Ona fai mai ai lea o Sepula ia te ia,", "And Zebul said unto him,"], ["Ua e iloa tau o ata o mauga e peiseai ni tagata.", "Thou seest the shadow of the mountains as if they were men."]]},
  {num:37,words:[["Ona toe fai atu ai lea o Kaala, ua faapea atu,", "And Gaal spake again and said,"], ["Faauta,", "See there come people down by the middle of the land,"], ["ua o ifo le nuu mai lea mea maualuga i le nuu, ua alu ane foi le tasi 'au i le aluna o i Meoneni.", "and another company come along by the plain of Meonenim."]]},
  {num:38,words:[["Ona fai atu ai lea o Sepula ia te ia,", "Then said Zebul unto him,"], ["O fea o i ai nei lou gutu,", "Where is now thy mouth,"], ["sa e faapea ai,", "wherewith thou saidst, Who is Abimelech,"], ["O ai ea Apimeleko matou te auauna ia te ia? E le o le nuu ea lenei sa e ta'ufaatauvaaina? O lenei,", "that we should serve him? is not this the people that thou hast despised? go out,"], ["alu atu ia,", "I pray now,"], ["tou te tau ma i latou.", "and fight with them."]]},
  {num:39,words:[["Ona alu atu lea o Kaala i luma o tagata o Sekema,", "And Gaal went out before the men of Shechem,"], ["ua tau ma Apimeleko.", "and fought with Abimelech."]]},
  {num:40,words:[["Ona tulia lea o ia e Apimeleko,", "And Abimelech chased him,"], ["ua sola lava ia i ona luma;", "and he fled before him,"], ["e toatele o i latou ua pauu ua manunua,", "and many were overthrown and wounded,"], ["ua oo atu i le puipui o le faitotoa.", "even unto the entering of the gate."]]},
  {num:41,words:[["Ua nofo Apimeleko i Aruma,", "And Abimelech dwelt at Arumah:"], ["a ua tuli e Sepula ia Kaala ma lona au uso,", "and Zebul thrust out Gaal and his brethren,"], ["ina ia le nonofo i latou i Sekema.", "that they should not dwell in Shechem."]]},
  {num:42,words:[["Ona oo lea i le taeao,", "And it came to pass on the morrow,"], ["ua o atu ai le nuu i le vao;", "that the people went out into the field;"], ["ua latou ta'u atu ai ia Apimeleko.", "and they told Abimelech."]]},
  {num:43,words:[["Ona ave ai lea e ia o le nuu,", "And he took the people,"], ["ua ia vaea i latou i 'au e tolu,", "and divided them into three companies,"], ["ua tanu 'au ai i le vao;", "and laid wait in the field,"], ["ona vaai lea o ia,", "and looked,"], ["faauta,", "and, behold,"], ["ua o mai le nuu nai le aai,", "the people were come forth out of the city;"], ["ona laga atu lea o ia ia te i latou,", "and he rose up against them,"], ["ma fasi ia te i latou.", "and smote them."]]},
  {num:44,words:[["Ua salalau Apimeleko ma le 'au sa ia te ia,", "And Abimelech, and the company that was with him,"], ["ua latou tutū atu i le puipui o le faitotoa o le aai;", "rushed forward,"], ["a o 'au e lua ua faasalalau i latou i e na i ai uma lava i le vao,", "and stood in the entering of the gate of the city:"], ["ma latou fafasi ia i latou.", "and the two other companies ran upon all the people that were in the fields, and slew them."]]},
  {num:45,words:[["Ua tau lava Apimeleko ma le aai,", "And Abimelech fought against the city all that day;"], ["ua po lava lea aso;", "and he took the city,"], ["ua ia maua le aai, ma le nuu sa i ai ua na fasia,", "and slew the people that was therein,"], ["ma na sofaia le aai,", "and beat down the city,"], ["ma na luluina ai i le masima.", "and sowed it with salt."]]},
  {num:46,words:[["Ua faalogo ai tagata uma i le 'olo o Sekema,", "And when all the men of the tower of Shechem heard that,"], ["ona latou ulufale ai lea i le 'olo maualuga i le malumalu o le atua o Perita.", "they entered into an hold of the house of the god Berith."]]},
  {num:47,words:[["Ua ta'u atu ia Apimeleko,", "And it was told Abimelech,"], ["ua faapotopotoina tagata uma i le 'olo o Sekema;", "that all the men of the tower of Shechem were gathered together."]]},
  {num:48,words:[["ona alu ae lea o Apimeleko i le mauga o Salemoni,", "And Abimelech gat him up to mount Zalmon,"], ["o ia atoa ma le nuu uma sa ia te ia;", "he and all the people that were with him;"], ["ua ave e Apimeleko to'i i lona lima,", "and Abimelech took an axe in his hand,"], ["ua na vaea le la laau,", "and cut down a bough from the trees,"], ["ua sii,", "and took it, and laid it on his shoulder,"], ["ma faaee i lona ua,", "and said unto the people that were with him,"], ["ma na fai atu i le nuu sa ia te ia,", "What ye have seen me do,"], ["O le mea ua outou iloa ua ou faia,", "make haste,"], ["ia vave ona fai faapea e outou.", "and do as I have done."]]},
  {num:49,words:[["Ona ta lava lea e le nuu uma,", "And all the people likewise cut down every man his bough,"], ["e taitasi ma lana la laau ,", "and followed Abimelech,"], ["ma latou mulimuli atu ia Apimeleko; ona latou tuu atu ai lea i le 'olo maualuga,", "and put them to the hold,"], ["ma latou susunu i le afi le 'olo maualuga i o latou luga;", "and set the hold on fire upon them;"], ["ua oti ai tagata uma o le 'olo o Sekema,", "so that all the men of the tower of Shechem died also,"], ["pe atoa le afe o tane ma fafine.", "about a thousand men and women."]]},
  {num:50,words:[["Ona alu atu lea o Apimeleko i Tipesa,", "Then went Abimelech to Thebez,"], ["ua to ai lauapi i Tipesa,", "and encamped against Thebez,"], ["ona aea ai lea.", "and took it."]]},
  {num:51,words:[["Sa i ai le 'olo malosi i totonu o le aai,", "But there was a strong tower within the city,"], ["na sosola i ai o tane ma fafine uma,", "and thither fled all the men and women,"], ["o tagata uma lava o le aai;", "and all they of the city,"], ["ua latou pupuni ai ia te i latou,", "and shut it to them,"], ["ma latou o ae i le fogā'olo.", "and gat them up to the top of the tower."]]},
  {num:52,words:[["Ua oo atu Apimeleko i le 'olo,", "And Abimelech came unto the tower,"], ["ma tau ai le taua;", "and fought against it,"], ["ua ia faalatalata foi i le puipui o le 'olo e faamu ai i le afi.", "and went hard unto the door of the tower to burn it with fire."]]},
  {num:53,words:[["Ona lafo lea e le tasi fafine o le fasi maaolo i luga o le ulu o Apimeleko,", "And a certain woman cast a piece of a millstone upon Abimelech's head,"], ["ua ia momomo ai lona ulu.", "and all to brake his skull."]]},
  {num:54,words:[["Ona valaau loa lea o ia i le taulealea o lona soātau,", "Then he called hastily unto the young man his armourbearer,"], ["ua fai atu ia te ia,", "and said unto him,"], ["Se'i mai ia lau pelu,", "Draw thy sword,"], ["ma e faaoti ia te au,", "and slay me,"], ["ne'i latou faapea ia te au,", "that men say not of me,"], ["O le fafine le na fasiotia ai o ia. Ona tutu'i ai lea ia te ia e lona taulealea,", "A woman slew him. And his young man thrust him through,"], ["ua oti ai.", "and he died."]]},
  {num:55,words:[["Ua iloa e tagata o Isaraelu ua oti Apimeleko,", "And when the men of Israel saw that Abimelech was dead,"], ["ona latou taitasi lea ma alu i lona nuu.", "they departed every man unto his place."]]},
  {num:56,words:[["Ua faapea ona taui atu e le Atua le leaga o Apimeleko na ia faia i lona tamā,", "Thus God rendered the wickedness of Abimelech, which he did unto his father,"], ["ina ua fasioti i ona uso e toafitugafulu;", "in slaying his seventy brethren:"]]},
  {num:57,words:[["o le leaga uma foi o tagata o Sekema ua faafoi atu e le Atua i o latou ulu;", "And all the evil of the men of Shechem did God render upon their heads:"], ["ua oo foi ia te i latou le fetuu o Iotama le atalii o Ierupaala.", "and upon them came the curse of Jotham the son of Jerubbaal."]]},
];
renderVerseSet(jdg_ch_9_Verses, 'jdg-ch9-verses');

var jdg_ch_10_Verses = [
  {num:1,words:[["Ua mavae Apimeleko ona tu mai ai lea e faaola ia Isaraelu o Tulaga le atalii o Pua,", "And after Abimelech there arose to defend Israel Tola the son of Puah,"], ["le atalii lea o Toto,", "the son of Dodo,"], ["o le tagata o Isakara,", "a man of Issachar;"], ["sa mau o ia i Samira i le mauga o Efaraima.", "and he dwelt in Shamir in mount Ephraim."]]},
  {num:2,words:[["Na ia faamasino ia Isaraelu i tausaga e luafulu ma le tolu,", "And he judged Israel twenty and three years,"], ["ona oti ai lea o ia,", "and died,"], ["ua tanumia i Samira.", "and was buried in Shamir."]]},
  {num:3,words:[["Ua mavae o ia ona tu mai ai lea o Iairo le Kiliata;", "And after him arose Jair, a Gileadite,"], ["na ia faamasino ia Isaraelu i tausaga e luafulu ma le lua.", "and judged Israel twenty and two years."]]},
  {num:4,words:[["Sa ia te ia atalii e toatolugafulu,", "And he had thirty sons that rode on thirty ass colts,"], ["e na tietie i asini e tolu sefulu;", "and they had thirty cities,"], ["sa ia i latou o aai e tolu sefulu, ua igoa ai o Havota-iairo ua oo mai i le aso nei,", "which are called Havoth-jair unto this day,"], ["o loo i le nuu o Kiliata.", "which are in the land of Gilead."]]},
  {num:5,words:[["Ua oti Iairo,", "And Jair died,"], ["ua tanumia i Kamoni.", "and was buried in Camon."]]},
  {num:6,words:[["Ona toe amio leaga lea o le fanauga a Isaraelu i luma o Ieova,", "And the children of Israel did evil again in the sight of the LORD,"], ["ua latou auauna ia Paala,", "and served Baalim,"], ["ma Asaira,", "and Ashtaroth,"], ["ma atua o Suria,", "and the gods of Syria,"], ["ma atua o Saitonu,", "and the gods of Zidon,"], ["ma atua o Moapi,", "and the gods of Moab,"], ["ma atua o le fanauga a Amoni,", "and the gods of the children of Ammon,"], ["ma atua o Filisitia;", "and the gods of the Philistines,"], ["a ua latou tuulafoai ia Ieova,", "and forsook the LORD,"], ["ua latou le auauna ia te ia.", "and served not him."]]},
  {num:7,words:[["Ona toasa tele ai lea o Ieova ia Isaraelu,", "And the anger of the LORD was hot against Israel,"], ["ua na tuuina atu ai i latou i lima o Filisitia,", "and he sold them into the hands of the Philistines,"], ["ma lima o le fanauga a Amoni,", "and into the hands of the children of Ammon."]]},
  {num:8,words:[["Sa latou faatiga,", "And that year they vexed and oppressed the children of Israel:"], ["ma faasaua i le fanauga a Isaraelu i ia ona po i tausaga e sefulu ma le valu,", "eighteen years, all the children of Israel that were on the other side Jordan in the land of the Amorites,"], ["o le fanauga uma a Isaraelu e na i le la itu o Ioritana i le nuu o sa Amorī i Kiliata.", "which is in Gilead."]]},
  {num:9,words:[["Ona sopoia atu lea o le fanauga a Amoni i Ioritana,", "Moreover the children of Ammon passed over Jordan to fight also against Judah,"], ["latou te tau ma Iuta,", "and against Benjamin,"], ["ma Peniamina, ma le aiga o Efaraima;", "and against the house of Ephraim;"], ["ua matuā puapuagaina Isaraelu.", "so that Israel was sore distressed."]]},
  {num:10,words:[["Ona alalaga lea o le fanauga a Isaraelu ia Ieova,", "And the children of Israel cried unto the LORD,"], ["o loo faapea,", "saying,"], ["Ua matou agasala atu ia te oe,", "We have sinned against thee,"], ["ina ua matou tuulafoai i lo matou Atua,", "both because we have forsaken our God,"], ["a ua matou auauna ia Paala.", "and also served Baalim."]]},
  {num:11,words:[["Ona fetalai mai lea o Ieova i le fanauga a Isaraelu,", "And the LORD said unto the children of Israel,"], ["E le o Aikupito ea,", "Did not I deliver you from the Egyptians,"], ["ma sa Amorī,", "and from the Amorites,"], ["ma le fanauga a Amoni,", "from the children of Ammon,"], ["ma Filisitia;", "and from the Philistines?"]]},
  {num:12,words:[["ma sa Saitonū,", "The Zidonians also,"], ["ma Amaleka,", "and the Amalekites,"], ["ma Meona,", "and the Maonites,"], ["sa latou faasauaina outou,", "did oppress you;"], ["ona outou valaau mai lea ia te au,", "and ye cried to me,"], ["ma ou faaolaina outou ai o latou lima.", "and I delivered you out of their hand."]]},
  {num:13,words:[["A o outou,", "Yet ye have forsaken me,"], ["ua outou tuulafoaiina a'u, ma ua outou auauna i atu ese;", "and served other gods:"], ["o le mea lea ou te le toe faaola ai ia te outou.", "wherefore I will deliver you no more."]]},
  {num:14,words:[["O ia, ina valaau i atua ua outou loto i ai,", "Go and cry unto the gods which ye have chosen;"], ["se'i latou faaola ia te outou i ona po o lo outou puapuaga.", "let them deliver you in the time of your tribulation."]]},
  {num:15,words:[["Ona fai atu lea o le fanauga a Isaraelu ia Ieova,", "And the children of Israel said unto the LORD, We have sinned:"], ["Ua matou agasala,", "do thou unto us whatsoever seemeth good unto thee;"], ["ia e faia ia te i matou mea uma ua e finagalo i ai;", "deliver us only,"], ["tau lava ina e laveai mai ia te i matou i lenei aso.", "we pray thee, this day."]]},
  {num:16,words:[["Ona latou tuu ese lea o atua ese sa ia te i latou,", "And they put away the strange gods from among them,"], ["ma latou auauna ia Ieova;", "and served the LORD:"], ["na tigaina lona finagalo ona o le puapuaga o Isaraelu.", "and his soul was grieved for the misery of Israel."]]},
  {num:17,words:[["Ua faapotopotoina le fanauga a Amoni,", "Then the children of Ammon were gathered together,"], ["ma latou to lauapi i Kiliata; ona faapotopoto lea o le fanauga a Isaraelu,", "and encamped in Gilead. And the children of Israel assembled themselves together,"], ["ua to lauapi i latou i Mesepa.", "and encamped in Mizpeh."]]},
  {num:18,words:[["Ona fai ane lea o le nuu ma alii o Kiliata o le tasi i le tasi,", "And the people and princes of Gilead said one to another,"], ["O ai se tasi na te amata ona tau ma le fanauga a Amoni? E fai o ia ma alii sili i e nonofo uma lava i Kiliata.", "What man is he that will begin to fight against the children of Ammon? he shall be head over all the inhabitants of Gilead."]]},
];
renderVerseSet(jdg_ch_10_Verses, 'jdg-ch10-verses');

var jdg_ch_11_Verses = [
  {num:1,words:[["O Iefata le Kiliata,", "Now Jephthah the Gileadite was a mighty man of valour,"], ["o le toa malosi lava ia, o le tama a le fafine talitane,", "and he was the son of an harlot:"], ["na fanaua Iefata e Kiliata.", "and Gilead begat Jephthah."]]},
  {num:2,words:[["Na fanau mai le avā a Kiliata o tama tane ia te ia;", "And Gilead's wife bare him sons;"], ["ua matutua tama tane a le fafine,", "and his wife's sons grew up,"], ["ona latou tulia lea o Iefata,", "and they thrust out Jephthah,"], ["ma latou fai atu ia te ia,", "and said unto him,"], ["E te le maua se tofi i le aiga o lo matou tamā,", "Thou shalt not inherit in our father's house;"], ["auā o oe le tama a le fafine ese.", "for thou art the son of a strange woman."]]},
  {num:3,words:[["Ona sola ese ai lea o Iefata i ona uso,", "Then Jephthah fled from his brethren,"], ["ua nofo i le nuu o Topa;", "and dwelt in the land of Tob:"], ["ona faapotopoto atu ai lea ia Iefata o tagata faatauvaa,", "and there were gathered vain men to Jephthah,"], ["ua latou feoai ma ia.", "and went out with him."]]},
  {num:4,words:[["Ua oo i ona aso na tau ai le fanauga a Amoni ma Isaraelu.", "And it came to pass in process of time, that the children of Ammon made war against Israel."]]},
  {num:5,words:[["Ua oo ina a tau le fanauga a Amoni ma Isaraelu,", "And it was so, that when the children of Ammon made war against Israel,"], ["ona o atu lea o toeaina o Kiliata e aami ia Iefata i le nuu o topa.", "the elders of Gilead went to fetch Jephthah out of the land of Tob:"]]},
  {num:6,words:[["Ua latou fai atu ia Iefata,", "And they said unto Jephthah,"], ["Maliu mai ia,", "Come,"], ["ina fai oe ma alii e avea 'au ia i matou,", "and be our captain,"], ["ina ia tatou tau ma le fanauga a Amoni.", "that we may fight with the children of Ammon."]]},
  {num:7,words:[["A ua fai mai Iefata i toeaina o Kiliata,", "And Jephthah said unto the elders of Gilead,"], ["E le na outou 'ino'ino ea ia te au, ma tuli ia te au ai le fale o lo'u tamā;", "Did not ye hate me,"], ["o le ā foi le mea ua outou o mai ai nei ia te au ina o tigaina outou?", "and expel me out of my father's house? and why are ye come unto me now when ye are in distress?"]]},
  {num:8,words:[["Ona fai atu lea o toeaina o Kiliata ia Iefata,", "And the elders of Gilead said unto Jephthah,"], ["O le mea lava lea ua matou toe faasaga mai ai ia te oe,", "Therefore we turn again to thee now,"], ["tatou te maliu ma i matou,", "that thou mayest go with us,"], ["ma e tau ma le fanauga a Amoni,", "and fight against the children of Ammon,"], ["ona e fai lea ma alii sili i e nonofo uma lava i Kiliata.", "and be our head over all the inhabitants of Gilead."]]},
  {num:9,words:[["Ona fai mai lea o Iefata i toeaina o Kiliata,", "And Jephthah said unto the elders of Gilead,"], ["Afai tatou te foi ma outou e tau ma le fanauga a Amoni,", "If ye bring me home again to fight against the children of Ammon,"], ["a foaiina mai foi i latou ia te au e Ieova,", "and the LORD deliver them before me,"], ["e faia ea a'u ma alii sili ia te outou?", "shall I be your head?"]]},
  {num:10,words:[["Ua fai atu toeaina o Kiliata ia Iefata,", "And the elders of Gilead said unto Jephthah,"], ["E faafofoga mai Ieova ia i tatou,", "The LORD be witness between us,"], ["pe afai matou te le faia e tusa ma lau fetalaiga.", "if we do not so according to thy words."]]},
  {num:11,words:[["Ona ō lea o Iefata ma toeaina o Kiliata;", "Then Jephthah went with the elders of Gilead, and the people made him head and captain over them:"], ["ona tofia lea o ia e le nuu e fai ma alii sili ma ave 'au ia i latou. Ua fai ane e Iefata ana upu uma i luma o Ieova i Mesepa.", "and Jephthah uttered all his words before the LORD in Mizpeh."]]},
  {num:12,words:[["Ona auina atu lea e Iefata o le sāvali i le tupu o le fanauga a Amoni,", "And Jephthah sent messengers unto the king of the children of Ammon,"], ["ua faapea,", "saying,"], ["Se a se mea o i ai ia te i tāua ma a'u,", "What hast thou to do with me,"], ["ina ua e sau ia te au e tau i lo'u lava laueleele?", "that thou art come against me to fight in my land?"]]},
  {num:13,words:[["Ua fai mai le tupu o le fanauga a Amoni i le sāvali a Iefata,", "And the king of the children of Ammon answered unto the messengers of Jephthah,"], ["Auā ua faoa e Isaraelu lo'u laueleele i lona alu ae i Aikupito,", "Because Israel took away my land,"], ["e pau mai i Arinona e pau atu i Iapoka,", "when they came up out of Egypt,"], ["a e oo atu i Ioritana;", "from Arnon even unto Jabbok,"], ["o lenei,", "and unto Jordan:"], ["ia toe tuu mai ai ma le filemu.", "now therefore restore those lands again peaceably."]]},
  {num:14,words:[["Ona toe aauina atu ai lea e Iefata o le sāvali i le tupu o le fanauga a Amoni,", "And Jephthah sent messengers again unto the king of the children of Ammon:"]]},
  {num:15,words:[["ua fai atu ia te ia,", "And said unto him,"], ["O loo faapea mai Iefata,", "Thus saith Jephthah,"], ["E lei faoa lava e Isaraelu le laueleele o Moapi,", "Israel took not away the land of Moab,"], ["ma le laueleele o le fanauga a Amoni;", "nor the land of the children of Ammon:"]]},
  {num:16,words:[["auā na ae mai Isaraelu i Aikupito,", "But when Israel came up from Egypt,"], ["ma ui ane i le vao, e oo i le sami Ulaula;", "and walked through the wilderness unto the Red sea,"], ["ua oo atu i Katesa.", "and came to Kadesh;"]]},
  {num:17,words:[["Ona aauina atu lea e Isaraelu o le sāvali i le tupu o Etoma,", "Then Israel sent messengers unto the king of Edom, saying,"], ["o loo faapea,", "Let me, I pray thee,"], ["Se'i ou ui ane i lou nuu.", "pass through thy land: but the king of Edom would not hearken thereto."], ["A e le faalogo mai le tupu o Etoma,", "And in like manner they sent unto the king of Moab:"], ["na aauina atu foi nisi i le tupu o Moapi, a e le mafai o ia;", "but he would not consent:"], ["ona nofo ai lea o Isaraelu i Katesa.", "and Israel abode in Kadesh."]]},
  {num:18,words:[["Ona latou ui atu lea i le vao,", "Then they went along through the wilderness,"], ["ma latou faataamilo i le nuu o Etoma ma le nuu o Moapi;", "and compassed the land of Edom,"], ["ua latou oo atu ai i le mea e alu ae ai le la i le nuu o Moapi,", "and the land of Moab, and came by the east side of the land of Moab,"], ["ma latou to lauapi i le la itu o Arinona,", "and pitched on the other side of Arnon,"], ["a e lei sopoia le tuaoi o Moapi;", "but came not within the border of Moab:"], ["auā o Arinona o le tuaoi lea o Moapi.", "for Arnon was the border of Moab."]]},
  {num:19,words:[["Ona aauina lea e Isaraelu o le sāvali ia Sekono le tupu o sa Amorī,", "And Israel sent messengers unto Sihon king of the Amorites, the king of Heshbon;"], ["le tupu a Hesepona,", "and Israel said unto him,"], ["ua faapea atu ai Isaraelu ia te ia,", "Let us pass,"], ["Se'i ou ui ane i lou laueleele e oo atu ai i lo'u nuu.", "we pray thee, through thy land into my place."]]},
  {num:20,words:[["A e lei talia e Sekono le upu a Isaraelu ina ia latou ui ane i lona nuu;", "But Sihon trusted not Israel to pass through his coast:"], ["ua faapotopoto foi e Sekono i lona nuu uma lava,", "but Sihon gathered all his people together,"], ["ua to lauapi i Iaesa;", "and pitched in Jahaz,"], ["ona latou tau ai lea ma Isaraelu.", "and fought against Israel."]]},
  {num:21,words:[["Ona tuuina atu lea e Ieova le Atua o Isaraelu o Sekono ma lona nuu uma i le lima o Isaraelu,", "And the LORD God of Israel delivered Sihon and all his people into the hand of Israel,"], ["ua latou fafasi ia i latou;", "and they smote them: so Israel possessed all the land of the Amorites,"], ["na maua foi e Isaraelu le nuu uma lava o sa Amorī o e sa nonofo i lea nuu.", "the inhabitants of that country."]]},
  {num:22,words:[["Na latou maua le laueleele uma lava o sa Amorī, e pau mai i Arinona,", "And they possessed all the coasts of the Amorites,"], ["a e pau mai i Iapoka;", "from Arnon even unto Jabbok,"], ["e pau atu i le vao, e oo atu i Ioritana.", "and from the wilderness even unto Jordan."]]},
  {num:23,words:[["O lenei, o Ieova le Atua o Isaraelu na ia tuli ese atu i sa Amorī ai luma o lona nuu o Isaraelu,", "So now the LORD God of Israel hath dispossessed the Amorites from before his people Israel,"], ["a e fai ea mo oe.", "and shouldest thou possess it?"]]},
  {num:24,words:[["O le mea e avane ai e Kimosa lou atua ia te oe, e te le taofia ea mo oe? O mea uma foi e aumai ai e Ieova lo matou Atua mo i matou,", "Wilt not thou possess that which Chemosh thy god giveth thee to possess? So whomsoever the LORD our God shall drive out from before us,"], ["matou te taofia lava mo i matou.", "them will we possess."]]},
  {num:25,words:[["O lenei pe sili ea oe ia Palako le atalii o Seporu,", "And now art thou any thing better than Balak the son of Zippor, king of Moab? did he ever strive against Israel,"], ["le tupu o Moapi? Pe na fai ea e ia se finauga ma Isaraelu? Pe na tau ea ia se taua ma i latou?", "or did he ever fight against them,"]]},
  {num:26,words:[["A o nofo Isaraelu i Hesepona ma ona faoa aai,", "While Israel dwelt in Heshbon and her towns,"], ["ma Aroeru ma ona faoa aai,", "and in Aroer and her towns,"], ["ma aai uma e lata ane i Arinona,", "and in all the cities that be along by the coasts of Arnon,"], ["e tolu galau ona tausaga? Se a le mea na outou le fao ai i ona po ia?", "three hundred years? why therefore did ye not recover them within that time?"]]},
  {num:27,words:[["O a'u foi, ou te lei agasala atu ia te oe;", "Wherefore I have not sinned against thee,"], ["a o oe, ua e agaleaga mai ia te au, ina ua sii mai le taua ia te au;", "but thou doest me wrong to war against me:"], ["o Ieova le faamasino, ia faamasino e ia i lenei aso i le fanauga a Isaraelu ma le fanauga a Amoni.", "the LORD the Judge be judge this day between the children of Israel and the children of Ammon."]]},
  {num:28,words:[["A ua le faalogo mai le tupu o le fanauga a Amoni i upu a Iefata na ia molia ia te ia.", "Howbeit the king of the children of Ammon hearkened not unto the words of Jephthah which he sent him."]]},
  {num:29,words:[["Ua oo ia Iefata le Agaga o Ieova,", "Then the Spirit of the LORD came upon Jephthah,"], ["ona alu ane lea o ia i Kiliata ma Manase,", "and he passed over Gilead,"], ["ua ia alu ane foi i Mesepa i Kiliata;", "and Manasseh, and passed over Mizpeh of Gilead,"], ["ona alu ane lea o ia nai Mesepa i Kiliata i le fanauga a Amoni.", "and from Mizpeh of Gilead he passed over unto the children of Ammon."]]},
  {num:30,words:[["Ona faia lea e Iefata le tauto ia Ieova,", "And Jephthah vowed a vow unto the LORD,"], ["o loo faapea,", "and said,"], ["Afai e te tuuna mai lava le fanauga a Amoni i lo'u lima;", "If thou shalt without fail deliver the children of Ammon into mine hands,"]]},
  {num:31,words:[["ona fai lea mo Ieova o se na te ulufafo i faitotoa o lou fale e faafetaiai ia te au i lo'u foi atu ma le manuia nai le fanauga a Amoni;", "Then it shall be, that whatsoever cometh forth of the doors of my house to meet me,"], ["pe ou te fai ai le taulaga mu.", "when I return in peace from the children of Ammon, shall surely be the LORD'S, and I will offer it up for a burnt offering."]]},
  {num:32,words:[["Ona alu ane lea o Iefata i le fanauga a Amoni e tau ma i latou;", "So Jephthah passed over unto the children of Ammon to fight against them;"], ["ua tuuina atu foi i latou e Ieova i lona lima.", "and the LORD delivered them into his hands."]]},
  {num:33,words:[["Ua ia fasia i latou,", "And he smote them from Aroer,"], ["e afua mai i Aroeru, e oo atu i Meniti,", "even till thou come to Minnith,"], ["o aai e luafulu,", "even twenty cities,"], ["e oo atu lava i Apelakarame, o le fasi e matuā tele lava;", "and unto the plain of the vineyards,"], ["ua faatoilaloina ai le fanauga a Amoni i luma o le fanauga a Isaraelu.", "with a very great slaughter. Thus the children of Ammon were subdued before the children of Israel."]]},
  {num:34,words:[["Ona alu atu lea o Iefata i Mesepa i lona fale;", "And Jephthah came to Mizpeh unto his house,"], ["faauta foi,", "and,"], ["o lona afafine ua ulufafo mai e faafetaiai ia te ia ma topa ma siva;", "behold,"], ["o lona afafine e toatasi o ia,", "his daughter came out to meet him with timbrels and with dances:"], ["ua leai sona atalii po o se afafine,", "and she was his only child;"], ["ua na o ia lava.", "beside her he had neither son nor daughter."]]},
  {num:35,words:[["Ua iloa atu o ia,", "And it came to pass,"], ["ona saei lea e ia ona ofu,", "when he saw her,"], ["ua fai atu,", "that he rent his clothes,"], ["Aue! Lo'u afafine e,", "and said,"], ["ua e matuā faatigaina a'u;", "Alas,"], ["o loo ua e faatasi ma e faaatuatuvale ia te au;", "my daughter! thou hast brought me very low,"], ["o a'u foi,", "and thou art one of them that trouble me:"], ["ua ou tautala atu ia Ieova,", "for I have opened my mouth unto the LORD,"], ["ou te le mafai ona faafoi mai la'u upu .", "and I cannot go back."]]},
  {num:36,words:[["Ona tali mai lea o ia ia te ia,", "And she said unto him, My father,"], ["Sena e,", "if thou hast opened thy mouth unto the LORD,"], ["ua e tautala atu ea ia Ieova? Ia e faia ia te au e tusa ma lau na ua e fai atu ai;", "do to me according to that which hath proceeded out of thy mouth;"], ["ina ua uma ona taui atu e Ieova ona o oe i e na ita mai ia te oe o le fanauga a Amoni.", "forasmuch as the LORD hath taken vengeance for thee of thine enemies, even of the children of Ammon."]]},
  {num:37,words:[["Ua ia fai mai foi i lona tama,", "And she said unto her father,"], ["Ia e faia lenei mea ia te au;", "Let this thing be done for me:"], ["tuu mai ia te au i masina e lua, ou te alu atu,", "let me alone two months,"], ["ma ou ifoifo i luga o mauga,", "that I may go up and down upon the mountains,"], ["ma ou tagi ona o lo'u taupou,", "and bewail my virginity,"], ["o a'u atoa ma a'u uo.", "I and my fellows."]]},
  {num:38,words:[["Ua ia fai atu,", "And he said,"], ["Ina alu ia oe;", "Go. And he sent her away for two months:"], ["ona tuu atu lea o ia ia te ia i masina e lua; ua alu atu o ia ma ana uo,", "and she went with her companions,"], ["ua tagi ona o lona taupou i luga o mauga.", "and bewailed her virginity upon the mountains."]]},
  {num:39,words:[["Ua oo ina mavae o masina e lua,", "And it came to pass at the end of two months,"], ["ona foi ai lea o ia i lona tamā;", "that she returned unto her father,"], ["ua ia faia ia te ia lana tauto sa na tauto ai;", "who did with her according to his vow which he had vowed:"], ["o ia foi ua le iloa se tane.", "and she knew no man. And it was a custom in Israel,"]]},
  {num:40,words:[["Ona fai lea ma tu ia Isaraelu, o lea tausaga ma lea tausaga ua o ai afafine o Isaraelu e vivii i le afafine o Iefata le Kiliata e taifa aso i tausaga.", "That the daughters of Israel went yearly to lament the daughter of Jephthah the Gileadite four days in a year."]]},
];
renderVerseSet(jdg_ch_11_Verses, 'jdg-ch11-verses');

var jdg_ch_12_Verses = [
  {num:1,words:[["Ona faapotopoto lea o tagata o Efaraima,", "And the men of Ephraim gathered themselves together,"], ["ua latou o ane i le itu i matu,", "and went northward,"], ["ua latou fai mai ia Iefata. Se a le mea na e alu atu ai e tau ma le fanauga a Amoni,", "and said unto Jephthah,"], ["a ua le aami ia i matou,", "Wherefore passedst thou over to fight against the children of Ammon,"], ["se'i tatou o ma oe? Matou te susunu lou fale i luga o oe i le afi.", "and didst not call us to go with thee? we will burn thine house upon thee with fire."]]},
  {num:2,words:[["Ua fai atu Iefata ia i latou, Sa tele lo matou fefinauaiga,", "And Jephthah said unto them,"], ["o a'u, ma lo'u nuu,", "I and my people were at great strife with the children of Ammon;"], ["i le ma le fanauga a Amoni;", "and when I called you,"], ["ona ou aami lea ia te outou, a ua outou le faaola mai ia te au ai o latou lima;", "ye delivered me not out of their hands."]]},
  {num:3,words:[["na ou iloa tou te lei faaola mai,", "And when I saw that ye delivered me not, I put my life in my hands,"], ["ona ou tuu atu lea o lo'u ola i lo'u lima,", "and passed over against the children of Ammon,"], ["ma ou alu atu i le fanauga a Amoni;", "and the LORD delivered them into my hand:"], ["ua tuuina mai foi i latou i lo'u lima e Ieova. O le a foi le mea ua outou o mai ai ia te au i lenei aso e sii mai le taua ia te au?", "wherefore then are ye come up unto me this day, to fight against me?"]]},
  {num:4,words:[["Ona faapotopoto lea e Iefata tagata uma o Kiliata,", "Then Jephthah gathered together all the men of Gilead,"], ["ua tau ma Efaraima. Ua fafasi e tagata o Kiliata ia Efaraima,", "and fought with Ephraim:"], ["auā na latou fai ane,", "and the men of Gilead smote Ephraim,"], ["O e na sosola mai Efaraima,", "because they said,"], ["outou na i Kiliata,", "Ye Gileadites are fugitives of Ephraim among the Ephraimites,"], ["o i Efaraima ma Manase.", "and among the Manassites."]]},
  {num:5,words:[["Na maua foi e Kiliata asaga o Ioritana,", "And the Gileadites took the passages of Jordan before the Ephraimites:"], ["na muamua i Efaraima;", "and it was so,"], ["i le,", "that when those Ephraimites which were escaped said,"], ["a fai mai e na sosola o Efaraima,", "Let me go over;"], ["Se'i ou asa atu;", "that the men of Gilead said unto him,"], ["ona fai ane lea o tagata o Kiliata ia te ia,", "Art thou an Ephraimite? If he said,"], ["E te se Efaraima ea? A fai mai o ia,", "Nay;"]]},
  {num:6,words:[["E leai; ona latou fai atu lea ia te ia,", "Then said they unto him,"], ["Fai mai, Seepoleta;", "Say now Shibboleth:"], ["ona fai mai lea o ia, Sepoleta, auā na te le mafai ona tautala faapea;", "and he said Sibboleth:"], ["ona latou pue lea ia te ia, ma fasi ia te ia i asaga o Ioritana.", "for he could not frame to pronounce it right."], ["O ona po ia na fasiotia o Efaraima e fagafulu o afe ma afe e lua.", "Then they took him, and slew him at the passages of Jordan: and there fell at that time of the Ephraimites forty and two thousand."]]},
  {num:7,words:[["Na faamasino Iefata ia Isaraelu i tausaga e ono; ona oti lea o Iefata le Kiliata,", "And Jephthah judged Israel six years. Then died Jephthah the Gileadite,"], ["ua latou tanu ia te ia i le tasi aai o Kiliata.", "and was buried in one of the cities of Gilead."]]},
  {num:8,words:[["Ua mavae atu o ia, ona faamasinoina lea o Isaraelu e Ivisona le Peteleema.", "And after him Ibzan of Beth-lehem judged Israel."]]},
  {num:9,words:[["Sa ia te ia o atalii e toatolugafulu ma afafine e toatolugafulu;", "And he had thirty sons,"], ["ua ia aueseina ona afafine e toatolugafulu;", "and thirty daughters,"], ["ua au mai foi mai tuā avā e toatolugafulu ma ona atalii;", "whom he sent abroad,"], ["ua ia faamasino ia Isaraelu i tausaga e fitu.", "and took in thirty daughters from abroad for his sons. And he judged Israel seven years."]]},
  {num:10,words:[["Ona oti lea o Ivisona,", "Then died Ibzan,"], ["ua tanumia o ia i Peteleema.", "and was buried at Beth-lehem."]]},
  {num:11,words:[["Ua mavae atu o ia,", "And after him Elon,"], ["ona faamasino lea ia Isaraelu o Aluna le Sepulona;", "a Zebulonite, judged Israel;"], ["ua ia faamasino ia Isaraelu i tausaga e sefulu.", "and he judged Israel ten years."]]},
  {num:12,words:[["Ona oti lea o Aluna le Sepulona; ua tanumia o ia i Ailona,", "And Elon the Zebulonite died,"], ["i le nuu o Sepulona.", "and was buried in Aijalon in the country of Zebulun."]]},
  {num:13,words:[["Ua mavae atu o ia,", "And after him Abdon the son of Hillel, a Pirathonite,"], ["ona faamasino lea ia Isaraelu o Apetonu le atalii o 'Ileli le Piratonu.", "judged Israel."]]},
  {num:14,words:[["Sa ia te ia atalii e toafagafulu,", "And he had forty sons and thirty nephews,"], ["ma atalii o ona atalii e toatolugafulu, e na tietie i asini e fitugafulu;", "that rode on threescore and ten ass colts:"], ["ua ia faamasino ia Isaraelu i tausaga e valu.", "and he judged Israel eight years."]]},
  {num:15,words:[["Ona oti lea o Apetonu le atalii o 'Ileli le Piratonu;", "And Abdon the son of Hillel the Pirathonite died, and was buried in Pirathon in the land of Ephraim,"], ["ua tanumia o ia i Piratonu i le nuu o Efaraima i le mauga o sa Amalekā.", "in the mount of the Amalekites."]]},
];
renderVerseSet(jdg_ch_12_Verses, 'jdg-ch12-verses');

var jdg_ch_13_Verses = [
  {num:1,words:[["Ua toe amio leaga le fanauga a Isaraelu i luma o Ieova;", "And the children of Israel did evil again in the sight of the LORD;"], ["ona tuuina atu lea o i latou e Ieova i lima o Filisitia i tausaga e fagafulu.", "and the LORD delivered them into the hand of the Philistines forty years."]]},
  {num:2,words:[["O le tasi tagata o Soraa i le itu aiga o Tanu,", "And there was a certain man of Zorah,"], ["o Manoa lona igoa;", "of the family of the Danites,"], ["sa pa lana avā,", "whose name was Manoah; and his wife was barren,"], ["ua le fanau lava.", "and bare not."]]},
  {num:3,words:[["Ua faaali mai le agelu a Ieova i le fafine,", "And the angel of the LORD appeared unto the woman,"], ["ua fai mai ia te ia,", "and said unto her,"], ["Faauta mai,", "Behold now,"], ["o oe e pa,", "thou art barren,"], ["e te lei fanau,", "and bearest not:"], ["o le a e to,", "but thou shalt conceive,"], ["ma ē fanau se tama tane.", "and bear a son."]]},
  {num:4,words:[["O lenei, ia e faaeteete,", "Now therefore beware,"], ["ne'i e inu uaina po o se 'ava,", "I pray thee,"], ["aua foi e te 'ai se mea leaga;", "and drink not wine nor strong drink,"], ["auā faauta, o le a to oe,", "and eat not any unclean thing:"]]},
  {num:5,words:[["e te fanau foi se tama tane;", "For,"], ["e le oo se tafi i lona ulu,", "lo, thou shalt conceive,"], ["auā e faia le tama ma naseri i le Atua,", "and bear a son;"], ["e afua mai ina fanau;", "and no razor shall come on his head: for the child shall be a Nazarite unto God from the womb:"], ["o ia foi e afua mai ona faaola ia Isaraelu ai lima o Filisitia.", "and he shall begin to deliver Israel out of the hand of the Philistines."]]},
  {num:6,words:[["Ona alu atu lea o le fafine ua ta'u atu ai i lana tane,", "Then the woman came and told her husband,"], ["o loo faapea,", "saying,"], ["Na alu ane ia te au le tagata o le Atua,", "A man of God came unto me,"], ["o lona tino mai ua pei o le tino o se agelu a le Atua,", "and his countenance was like the countenance of an angel of God,"], ["e matuā matautia lava;", "very terrible:"], ["ou te lei fesili ia te ia pe maifea o ia;", "but I asked him not whence he was,"], ["na ia le ta'u mai foi ia te au lona igoa.", "neither told he me his name:"]]},
  {num:7,words:[["Na ia fai mai ia te au,", "But he said unto me,"], ["Faauta, o le a to oe,", "Behold,"], ["e te fanau foi le tama tane;", "thou shalt conceive,"], ["o lenei, aua e te inu uaina po o se 'ava,", "and bear a son;"], ["aua foi e te 'ai se mea leaga,", "and now drink no wine nor strong drink,"], ["auā e faia le tama ma naseri i le Atua, e afua mai ina fanau,", "neither eat any unclean thing:"], ["e oo i le aso o lona oti.", "for the child shall be a Nazarite to God from the womb to the day of his death."]]},
  {num:8,words:[["Ona faatoga atu lea o Manoa ia Ieova,", "Then Manoah intreated the LORD,"], ["ua faapea Ou te aioi le Alii e,", "and said,"], ["o le tagata o le Atua na e auina mai,", "O my Lord,"], ["se'i toe maliu mai o ia ia te i maua,", "let the man of God which thou didst send come again unto us,"], ["ma faali mai se mea ma te faia i le tama o le a fanau mai.", "and teach us what we shall do unto the child that shall be born."]]},
  {num:9,words:[["Ua faafofoga mai le Atua i le upu a Manoa,", "And God hearkened to the voice of Manoah;"], ["ua toe alu atu le agelu a le Atua i le fafine, a o nofo o ia i le fanua;", "and the angel of God came again unto the woman as she sat in the field:"], ["a o Manoa lana tane sa le i ai ma ia.", "but Manoah her husband was not with her."]]},
  {num:10,words:[["Ona faataalise lea o le fafine ona momo'e,", "And the woman made haste,"], ["ma ta'u atu i lana tane,", "and ran, and shewed her husband,"], ["ma na fai atu ia te ia,", "and said unto him,"], ["Faauta,", "Behold, the man hath appeared unto me,"], ["ua faaali mai ia te au le tagata na alu ane ia te au i le tasi aso.", "that came unto me the other day."]]},
  {num:11,words:[["Ona tulai lea o Manoa,", "And Manoah arose,"], ["ma mulimuli atu i lana avā;", "and went after his wife,"], ["ua oo atu i le tagata,", "and came to the man,"], ["ona fai atu lea o ia ia te ia,", "and said unto him,"], ["O oe ea le tagata na oulua tautala ma le fafine? Ua fai mai o ia,", "Art thou the man that spakest unto the woman? And he said,"], ["O a'u lava lea.", "I am."]]},
  {num:12,words:[["Ua fai atu Manoa, O lenei,", "And Manoah said,"], ["ia taunuu au fetalaiga;", "Now let thy words come to pass. How shall we order the child,"], ["se a se mea e tatau ai i le tama, ma se mea e faia ia te ia?", "and how shall we do unto him?"]]},
  {num:13,words:[["Ua fai mai le agelu a Ieova ia Manoa,", "And the angel of the LORD said unto Manoah,"], ["O mea uma na ou fai atu ai i le fafine ia tausi i ai o ia;", "Of all that I said unto the woman let her beware."]]},
  {num:14,words:[["o mea uma e tupu i le vine aua na te 'ai ai;", "She may not eat of any thing that cometh of the vine,"], ["o le uaina ma le 'ava,", "neither let her drink wine or strong drink,"], ["aua na te inu ai, o mea leaga uma aua na te 'aina;", "nor eat any unclean thing:"], ["o mea uma na ou fai atu ai ia te ia ia tausi i ai o ia.", "all that I commanded her let her observe."]]},
  {num:15,words:[["Ona fai atu lea o Manoa i le agelu a Ieova,", "And Manoah said unto the angel of the LORD,"], ["Se'i ou taofi ia te oe,", "I pray thee, let us detain thee,"], ["ou te sauni ai mā oe se tamai 'oti.", "until we shall have made ready a kid for thee."]]},
  {num:16,words:[["Ua fai mai le agelu a Ieova ia Manoa,", "And the angel of the LORD said unto Manoah,"], ["E ui lava ina e taofi ia te au, ou te le 'ai i lau mea e 'ai;", "Though thou detain me,"], ["a e afai e te faia se taulaga mu,", "I will not eat of thy bread:"], ["ia e fai ai ia Ieova; auā e le iloa e Manoa,", "and if thou wilt offer a burnt offering,"], ["o le agelu a Ieova o ia.", "thou must offer it unto the LORD. For Manoah knew not that he was an angel of the LORD."]]},
  {num:17,words:[["Ona fai atu lea o Manoa i le agelu a Ieova,", "And Manoah said unto the angel of the LORD,"], ["O ai ea lou suafa,", "What is thy name,"], ["ma te vivii ai ia te oe pe a taunuu lau fetalaiga?", "that when thy sayings come to pass we may do thee honour?"]]},
  {num:18,words:[["Ona fai mai lea o le agelu a Ieova ia te ia,", "And the angel of the LORD said unto him,"], ["O le a le mea e te fesili mai ai i lo'u igoa,", "Why askest thou thus after my name,"], ["auā e silisili ese ia.", "seeing it is secret?"]]},
  {num:19,words:[["Ona ave lea e Manoa o le tamai 'oti atoa ma le taulaga i mea e 'ai,", "So Manoah took a kid with a meat offering,"], ["ua ia faitaulaga ai i luga o le papa ia Ieova,", "and offered it upon a rock unto the LORD:"], ["ona fai lea e le agelu o le vavega,", "and the angel did wondrously;"], ["a o matamata ai Manoa ma lana avā;", "and Manoah and his wife looked on."]]},
  {num:20,words:[["ua alu ae i le lagi le mumū o le afi ai luga o le fata faitaulaga,", "For it came to pass,"], ["ona alu ae lea o le agelu a Ieova i le mumū o le afi o le fata faitaulaga,", "when the flame went up toward heaven from off the altar,"], ["a o matamata ai Manoa ma lana ava;", "that the angel of the LORD ascended in the flame of the altar. And Manoah and his wife looked on it,"], ["ona faapauu fao ai lea o i laua i le eleele.", "and fell on their faces to the ground."]]},
  {num:21,words:[["E lei toe faaali mai lava le agelu a Ieova ia Manoa ma lana avā; ona iloa lava lea e Manoa, o ia o le agelu a Ieova.", "But the angel of the LORD did no more appear to Manoah and to his wife. Then Manoah knew that he was an angel of the LORD."]]},
  {num:22,words:[["Ua fai atu Manoa i lana avā,", "And Manoah said unto his wife,"], ["E oti lava i taua,", "We shall surely die,"], ["auā ua ta vaaia le Atua.", "because we have seen God."]]},
  {num:23,words:[["A ua fai mai lana avā ia te ia,", "But his wife said unto him,"], ["Ana finagalo Ieova e fasioti ia i taua, po ua na le talia se taulaga mu,", "If the LORD were pleased to kill us,"], ["ma se taulaga i mea e 'ai ai ia te i taua,", "he would not have received a burnt offering and a meat offering at our hands,"], ["po ua na le faaali mai foi nei mea uma; ua na le ta'ua mai foi ia te i taua ni mea faapea,", "neither would he have shewed us all these things,"], ["e pei ona ta'ua mai nei.", "nor would as at this time have told us such things as these."]]},
  {num:24,words:[["Ona fanau mai lea o le fafine o le tama tane,", "And the woman bare a son,"], ["ua faaigoa ia te ia o Samasoni;", "and called his name Samson:"], ["ua tupu le tama,", "and the child grew,"], ["ua faamanuia foi o ia e Ieova.", "and the LORD blessed him."]]},
  {num:25,words:[["Ua amata ona faagaeetia o ia e le Agaga o Ieova i Maane-tanu i le va o Soraa ma Esetaola.", "And the Spirit of the LORD began to move him at times in the camp of Dan between Zorah and Eshtaol."]]},
];
renderVerseSet(jdg_ch_13_Verses, 'jdg-ch13-verses');

var jdg_ch_14_Verses = [
  {num:1,words:[["Ua alu ifo Samasoni i Timenata, ona iloa ai lea o le fafine i Timenata,", "And Samson went down to Timnath,"], ["o le fafine o Filisitia.", "and saw a woman in Timnath of the daughters of the Philistines."]]},
  {num:2,words:[["Ona alu ae lea o ia,", "And he came up,"], ["ma ta'u atu ai i lona tamā ma lona tinā, ua fai atu,", "and told his father and his mother,"], ["Ua ou iloa le fafine i Timenata,", "and said,"], ["o le fafine o Filisitia; o lenei,", "I have seen a woman in Timnath of the daughters of the Philistines:"], ["ia oulua au mai o ia e fai ma'u avā.", "now therefore get her for me to wife."]]},
  {num:3,words:[["Ona fai mai lea o lona tamā ma lona tinā ia te ia,", "Then his father and his mother said unto him,"], ["E leai ea se fafine i afafine o ou uso ma lo'u nuu uma,", "Is there never a woman among the daughters of thy brethren,"], ["ina ua e alu e fai avā i Filisitia e le peritomeina? Ua fai atu Samasoni i lona tamā,", "or among all my people, that thou goest to take a wife of the uncircumcised Philistines? And Samson said unto his father,"], ["Ia au mai lea ma'u,", "Get her for me;"], ["auā e lelei lava ia i lo'u manatu.", "for she pleaseth me well."]]},
  {num:4,words:[["A ua le iloa e lona tamā ma lona tinā,", "But his father and his mother knew not that it was of the LORD,"], ["ua mai ia Ieova lean mea;", "that he sought an occasion against the Philistines:"], ["e saili ai e ia se mea e faalani ai se misa ma Filisitia. O ona po ia na malo ai Filisitia ia Isaraelu.", "for at that time the Philistines had dominion over Israel."]]},
  {num:5,words:[["Ona o ifo lea o Samasoni,", "Then went Samson down,"], ["ma lona tamā,", "and his father and his mother,"], ["ma lona tinā i Timenata;", "to Timnath, and came to the vineyards of Timnath:"], ["ua oo atu i tovine o Timenata,", "and,"], ["faauta,", "behold,"], ["ua tu mai ia te ia le leona taanoa o tagi mai.", "a young lion roared against him."]]},
  {num:6,words:[["Ona osofia lea o ia e le Agaga o Ieova,", "And the Spirit of the LORD came mightily upon him,"], ["ua na saeia le leona ,", "and he rent him as he would have rent a kid,"], ["e pei ona saeia se tamai 'oti, a e leai lava se mea i lona lima;", "and he had nothing in his hand:"], ["ua ia le ta'u atu i lona tamā ma lona tinā le mea ua na faia.", "but he told not his father or his mother what he had done."]]},
  {num:7,words:[["Ona alu ifo lea,", "And he went down,"], ["ma na tautala ma le fafine;", "and talked with the woman;"], ["ua lelei lava o ia i le manatu o Samasoni.", "and she pleased Samson well."]]},
  {num:8,words:[["Ua foi atu o ia ina ua mavae nisi aso ina ia aumaia o ia;", "And after a time he returned to take her,"], ["ona afe ane lea o ia e matamata i le tino o le leona;", "and he turned aside to see the carcase of the lion:"], ["faauta,", "and, behold,"], ["o le vao lagomeli atoa ma le meli i le tino o le leona.", "there was a swarm of bees and honey in the carcase of the lion."]]},
  {num:9,words:[["Ua ia to mai ai i ona lima,", "And he took thereof in his hands,"], ["ua 'ai fano,", "and went on eating,"], ["ua oo atu i lona tamā ma lona tinā, ona avatu lea e ia ia te i laua,", "and came to his father and mother,"], ["ua la aai ai;", "and he gave them,"], ["a e le ta'u atu e ia ia te i laua,", "and they did eat:"], ["na ia to mai le meli ai le tino o le leona.", "but he told not them that he had taken the honey out of the carcase of the lion."]]},
  {num:10,words:[["Ua alu ifo lona tamā i le fafine,", "So his father went down unto the woman:"], ["ona fai ai lea e Samasoni i lea mea o le tausamaaga,", "and Samson made there a feast;"], ["auā na faapea le tu i taulelea.", "for so used the young men to do."]]},
  {num:11,words:[["Ua latou iloa o ia,", "And it came to pass,"], ["ona latou tuu atu lea o ana aumea e toatolugafulu,", "when they saw him,"], ["latou te i ai ma ia.", "that they brought thirty companions to be with him."]]},
  {num:12,words:[["Ua fai atu Samasoni ia i latou,", "And Samson said unto them,"], ["Se'i ou fai atu ia te outou la'u tupua,", "I will now put forth a riddle unto you:"], ["afai tou te matea mai lona uiga, i aso e fitu o le tausamaaga,", "if ye can certainly declare it me within the seven days of the feast,"], ["ma outou maua,", "and find it out,"], ["ona ou avatu lea ia te outou o ie e tolugafulu ma ofu e tolugafulu;", "then I will give you thirty sheets and thirty change of garments:"]]},
  {num:13,words:[["a e afai tou te le mafai ona matea mai lona uiga,", "But if ye cannot declare it me,"], ["ona outou au mai lea ia te au o ie lino e tolugafulu ma ofu e tolugafulu. Ua latou fai mai ia te ia,", "then shall ye give me thirty sheets and thirty change of garments. And they said unto him,"], ["Ina fai mai ia lau tupua,", "Put forth thy riddle,"], ["matou te faalogologo atu ai.", "that we may hear it."]]},
  {num:14,words:[["Ona fai atu lea o ia ia te i latou,", "And he said unto them,"], ["Na alu atu le mea e 'ai nai lē 'ai mea;", "Out of the eater came forth meat,"], ["na alu atu foi le mea suamalie nai lē malosi. Ua latou le mafai ona matea le tupua i aso e tolu.", "and out of the strong came forth sweetness. And they could not in three days expound the riddle."]]},
  {num:15,words:[["Ua oo i le aso fitu,", "And it came to pass on the seventh day,"], ["ona latou fai ane lea i le avā a Samasoni,", "that they said unto Samson's wife,"], ["Ia e faaoleole i lau tane,", "Entice thy husband,"], ["ma faaali mai ia i matou le tupua,", "that he may declare unto us the riddle,"], ["ne'i matou susunuina oe ma le aiga o lou tamā i le afi;", "lest we burn thee and thy father's house with fire:"], ["pe na outou aami ea ia i matou e faamativa ia te i matou? E le o lea ea?", "have ye called us to take that we have? is it not so?"]]},
  {num:16,words:[["Ona tagi lea o le avā a Samasoni ia te ia,", "And Samson's wife wept before him,"], ["ua faapea atu,", "and said,"], ["Ua na ona e 'ino'ino ia te au,", "Thou dost but hate me,"], ["a e te le alofa mai lava ia te au;", "and lovest me not:"], ["ua e fai atu le tupua i tagata o lo'u nuu, a e te lei faaali mai ai ia te au;", "thou hast put forth a riddle unto the children of my people,"], ["ua fai mai o ia ia te ia,", "and hast not told it me. And he said unto her,"], ["Faauta,", "Behold,"], ["ou te lei faaali atu i lo'u tamā ma lo'u tinā;", "I have not told it my father nor my mother,"], ["ou te faaali atu ea ia te oe?", "and shall I tell it thee?"]]},
  {num:17,words:[["Ua tagi lava o ia ia te ia i aso e fitu sa fai ai le tausamaaga;", "And she wept before him the seven days, while their feast lasted:"], ["ona oo lea i le aso fitu ua ia faaali atu ai ia te ia,", "and it came to pass on the seventh day,"], ["auā ua faatauanauina o ia e ia,", "that he told her,"], ["ona faaali atu lea e ia o le tupua i tagata o lona nuu.", "because she lay sore upon him: and she told the riddle to the children of her people."]]},
  {num:18,words:[["Ona fai mai lea ia te ia o tagata o le nuu i le aso fitu,", "And the men of the city said unto him on the seventh day before the sun went down,"], ["a o lei alu ifo le la,", "What is sweeter than honey? and what is stronger than a lion? And he said unto them,"], ["Se a se mea e sili ona suamalie i le meli? Se a foi se mea e sili ona malosi i le leona? Ona ia fai atu lea ia i latou, Ana le se anoa la'u povi na outou suatia ai le eleele,", "If ye had not plowed with my heifer,"], ["po ua outou le matea la'u tupua.", "ye had not found out my riddle."]]},
  {num:19,words:[["Ona osofia lea o ia e le Agaga o Ieova;", "And the Spirit of the LORD came upon him,"], ["ona alu ifo lea o ia i Asekelona,", "and he went down to Ashkelon,"], ["ma na fasia o latou tagata e toatolugafulu, ona ave lea e ia o latou ofu,", "and slew thirty men of them,"], ["na ia avatu ai ofu i e na matea mai le tupua;", "and took their spoil,"], ["ua matuā ita o ia,", "and gave change of garments unto them which expounded the riddle. And his anger was kindled,"], ["ona alu ae lea o ia i le fale o lona tamā.", "and he went up to his father's house."]]},
  {num:20,words:[["A ua ave le avā a Samasoni mā lana uo,", "But Samson's wife was given to his companion,"], ["le na fai ma uo ia te ia.", "whom he had used as his friend."]]},
];
renderVerseSet(jdg_ch_14_Verses, 'jdg-ch14-verses');

var jdg_ch_15_Verses = [
  {num:1,words:[["Ua mavae nisi aso i ona po o le seleselegāsaito,", "But it came to pass within a while after,"], ["ona asiasi atu lea o Samasoni i lana avā,", "in the time of wheat harvest,"], ["ua ave ai se tamai 'oti; ua fai ane,", "that Samson visited his wife with a kid;"], ["ou te alu atu i la'u avā i le afeafe;", "and he said,"], ["a e le mafai lona tamā ina ia ulu atu ai o ia.", "I will go in to my wife into the chamber. But her father would not suffer him to go in."]]},
  {num:2,words:[["Ua fai mai lona tamā,", "And her father said, I verily thought that thou hadst utterly hated her;"], ["Fā'i ua e 'ino'ino lava ia te ia,", "therefore I gave her to thy companion:"], ["ona ou avatu lea o ia i lau uo;", "is not her younger sister fairer than she? take her,"], ["e le ua sili ea ona lalelei lona uso itiiti ia te ia? Ia fai lea mona sui ia te oe.", "I pray thee, instead of her."]]},
  {num:3,words:[["A ua fai atu Samasoni ia te i latou,", "And Samson said concerning them,"], ["Ou te le sala a'u i lenei mea ia Filisitia,", "Now shall I be more blameless than the Philistines,"], ["pe a a'u faia se mea e tiga ai i latou.", "though I do them a displeasure."]]},
  {num:4,words:[["Ona alu lea o Samasoni,", "And Samson went and caught three hundred foxes,"], ["ua ia puea alope e tolu selau;", "and took firebrands,"], ["ua ia ave foi sulu, ma na liliu le tasi iu i le tasi iu,", "and turned tail to tail,"], ["ua tuu foi le sulu e tasi i le va o iu e lua i totonugalemu.", "and put a firebrand in the midst between two tails."]]},
  {num:5,words:[["Ona tugia lea e ia o sulu i le afi,", "And when he had set the brands on fire,"], ["ma tuu atu ai i saito o tu a Filisitia;", "he let them go into the standing corn of the Philistines,"], ["ona mu lea o faaputugāsaito atoa ma saito o tu,", "and burnt up both the shocks, and also the standing corn,"], ["o tovine atoa ma olive.", "with the vineyards and olives."]]},
  {num:6,words:[["Ona fai ane lea o Filisitia,", "Then the Philistines said,"], ["O ai ea ua faia lenei mea? Ua latou fai atu ai,", "Who hath done this? And they answered,"], ["O Samasoni le tane a le afafine o le Timenata,", "Samson, the son in law of the Timnite,"], ["ina ua na fao lana avā,", "because he had taken his wife,"], ["ma avatu ai i lana uo.", "and given her to his companion."], ["Ona o ae lea o Filisitia,", "And the Philistines came up,"], ["ma latou susunuina o ia ma lona tamā i le afi.", "and burnt her and her father with fire."]]},
  {num:7,words:[["Ua fai atu Samasoni ia te i latou,", "And Samson said unto them,"], ["E ui lava ina outou faia o lea mea,", "Though ye have done this,"], ["a e ou te taui atu ia te outou,", "yet will I be avenged of you,"], ["e mulimuli ane ona ou mapu lea.", "and after that I will cease."]]},
  {num:8,words:[["Ona fasia lea o i latou e ia o vae ma ogavae, o le fasi tele;", "And he smote them hip and thigh with a great slaughter:"], ["ona alu ifo lea o ia, ua nofo i le va i papa o Etama.", "and he went down and dwelt in the top of the rock Etam."]]},
  {num:9,words:[["Ona o ae lea o Filisitia,", "Then the Philistines went up,"], ["ua to lauapi i Iuta,", "and pitched in Judah,"], ["sa faasalalau i latou i Le'i.", "and spread themselves in Lehi."]]},
  {num:10,words:[["Ua fai atu tagata o Iuta,", "And the men of Judah said,"], ["O le a le mea ua outou o mai ai e tau ma i matou? Ua fai mai i latou,", "Why are ye come up against us? And they answered,"], ["Matou te o mai e fusifusi ia Samasoni,", "To bind Samson are we come up,"], ["e fai ia te ia e pei ona faia e ia ia i matou.", "to do to him as he hath done to us."]]},
  {num:11,words:[["Ona o ifo lea o tagata o Iuta e tolu gaafe i le va i papa o Etama,", "Then three thousand men of Judah went to the top of the rock Etam,"], ["ua latou fai mai ia Samasoni,", "and said to Samson,"], ["E te lei iloa ea ua pule lava Filisitia ia i tatou? O le a lenei mea ua e faia ia te i matou? Ua fai atu o ia ia te i latou,", "Knowest thou not that the Philistines are rulers over us? what is this that thou hast done unto us? And he said unto them,"], ["E faapei ona latou faia ia te au,", "As they did unto me,"], ["ua faapei ona ou faia ia te i latou.", "so have I done unto them."]]},
  {num:12,words:[["Ua latou fai mai ia te ia,", "And they said unto him,"], ["Ua matou ifoifo mai nei e fusifusi ia te oe,", "We are come down to bind thee,"], ["ma tuuu atu ia te oe i lima o Filisitia. Ona fai atu lea o Samasoni ia i latou,", "that we may deliver thee into the hand of the Philistines. And Samson said unto them,"], ["Ina outou tauto mai ia te au,", "Swear unto me,"], ["tou te le fasia a'u e outou.", "that ye will not fall upon me yourselves."]]},
  {num:13,words:[["Ua latou fai mai ia te ia,", "And they spake unto him,"], ["o loo faapea,", "saying,"], ["E leai;", "No;"], ["a e matou te fusifusia lava oe,", "but we will bind thee fast,"], ["ma tuu atu ia te oe i o latou lima,", "and deliver thee into their hand:"], ["a e matou te le fasia lava oe. Ona latou fusifusia lea o ia i maea fou e lua,", "but surely we will not kill thee. And they bound him with two new cords,"], ["ua latou avae ia te ia ai le papa.", "and brought him up from the rock."]]},
  {num:14,words:[["Ua oo o ia i Le'i,", "And when he came unto Lehi,"], ["ona alalaga fiafia lea o Filisitia ona o ia. Ona osofia lea o ia e le Agaga o Ieova,", "the Philistines shouted against him:"], ["ua avea maea sa i ona lima e pei se manoa lino ua mu i le afi,", "and the Spirit of the LORD came mightily upon him, and the cords that were upon his arms became as flax that was burnt with fire,"], ["ua matala noanoaga i ona lima.", "and his bands loosed from off his hands."]]},
  {num:15,words:[["Ona maua lea e ia o le ivi auvae fou o le asini,", "And he found a new jawbone of an ass,"], ["na ia tuu atu lona lima,", "and put forth his hand,"], ["ma tago i ai,", "and took it,"], ["ma fasi a'i tagata e afe.", "and slew a thousand men therewith."]]},
  {num:16,words:[["Ona fai ane lea o Samasoni,", "And Samson said,"], ["O le ivi auvae o le asini,", "With the jawbone of an ass,"], ["o le faupuega, e lua faupuega;", "heaps upon heaps,"], ["o le ivi auvae o le asini ua ou fasi a'i tagata e afe.", "with the jaw of an ass have I slain a thousand men."]]},
  {num:17,words:[["Ua oo ina uma lana upu,", "And it came to pass,"], ["ona ia lafoai lea o le ivi auvae nai lona lima;", "when he had made an end of speaking, that he cast away the jawbone out of his hand,"], ["ua ia faaigoa ai lea mea o Ramale'i.", "and called that place Ramath-lehi."]]},
  {num:18,words:[["Ona matuā fia inu lea o ia;", "And he was sore athirst,"], ["ua ia valaau ia Ieova,", "and called on the LORD,"], ["ua faapea atu,", "and said, Thou hast given this great deliverance into the hand of thy servant:"], ["Ua e foai mai i lau auauna lenei olataga tele a o le a a'u oti i le fia inu,", "and now shall I die for thirst,"], ["ona maua lea o a'u e le au le peritomeina.", "and fall into the hand of the uncircumcised?"]]},
  {num:19,words:[["Ona māvae lea i le Atua se mea magoto sa i Le'i,", "But God clave an hollow place that was in the jaw,"], ["ona alu atu ai lea o le vai,", "and there came water thereout;"], ["ua inu ai o ia,", "and when he had drunk,"], ["ona foi atu lea o lona agaga, ua ola lava ia;", "his spirit came again,"], ["o le mea lea ua ia faaigoa ai lea mea o Eniakori,", "and he revived:"], ["o loo i Le'i,", "wherefore he called the name thereof En-hakkore,"], ["ua oo mai i lenei lava aso.", "which is in Lehi unto this day."]]},
  {num:20,words:[["Ua ia faamasino ia Isaraelu i ona po na malo ai Filisitia, o tausaga e luafulu.", "And he judged Israel in the days of the Philistines twenty years."]]},
];
renderVerseSet(jdg_ch_15_Verses, 'jdg-ch15-verses');

var jdg_ch_16_Verses = [
  {num:1,words:[["Ua alu atu Samasoni i Kasa,", "Then went Samson to Gaza,"], ["ona iloa ai lea e ia o le fafine talitane;", "and saw there an harlot,"], ["ua ia alu ane ia te ia.", "and went in unto her."]]},
  {num:2,words:[["Ona ta'uatua lea ia Kasa,", "And it was told the Gazites,"], ["ua faapea,", "saying,"], ["Ua sau Samasoni iinei,", "Samson is come hither. And they compassed him in,"], ["Ona latou siosio ai lea,", "and laid wait for him all night in the gate of the city,"], ["ma lamalama ia te ia ua aoina le po,", "and were quiet all the night,"], ["i le faitotoa o le aai;", "saying,"], ["ua atoa le po o faalologo i latou,", "In the morning,"], ["o loo faapea,", "when it is day,"], ["Tatou te fasia o ia pe a malama ae le taeao.", "we shall kill him."]]},
  {num:3,words:[["Ua taoto Samasoni,", "And Samson lay till midnight,"], ["ua oo i le tulua o po ma ao;", "and arose at midnight,"], ["ona tulai lea o ia i le tulua o po ma ao,", "and took the doors of the gate of the city,"], ["ua tago atu i puipui o le faitotoa o le aai ma pou e lua,", "and the two posts, and went away with them,"], ["ua na fa'ia atoa ma le faamau,", "bar and all,"], ["ua faaee i lona ua,", "and put them upon his shoulders,"], ["ma avae i le tumutumu o le mauga sa feagai ma Heperona.", "and carried them up to the top of an hill that is before Hebron."]]},
  {num:4,words:[["E mulimuli ane ua ia manao i le fafine i le vanu o Soreka,", "And it came to pass afterward, that he loved a woman in the valley of Sorek,"], ["o Talila lona igoa.", "whose name was Delilah."]]},
  {num:5,words:[["Ona o ae lea ia te ia o alii o Filisitia,", "And the lords of the Philistines came up unto her,"], ["ua latou fai atu ia te ia,", "and said unto her,"], ["Ia e faaoleole ia te ia,", "Entice him,"], ["ina ia iloa po o le a lona malosi tele, pe se a foi se mea matou te malo ai ia te ia,", "and see wherein his great strength lieth,"], ["ma fusifusi ia te ia ina ia faatigaina o ia;", "and by what means we may prevail against him,"], ["o i matou foi,", "that we may bind him to afflict him:"], ["matou te taitasi ma avatu ai ia te oe o tupe e tasi le afe ma le selau e tasi.", "and we will give thee every one of us eleven hundred pieces of silver."]]},
  {num:6,words:[["Ua fai mai Talila ia Samasoni,", "And Delilah said to Samson, Tell me,"], ["Se'i e ta'u mai ia te au,", "I pray thee,"], ["po o le a e te malosi tele ai? Pe se a foi se mea e fusifusia ai oe ina ia faatigaina oe?", "wherein thy great strength lieth, and wherewith thou mightest be bound to afflict thee."]]},
  {num:7,words:[["Ua fai atu Samasoni ia te ia,", "And Samson said unto her,"], ["Afai latou te fusifusia a'u i maea mata e fitu e lei faapopoina,", "If they bind me with seven green withs that were never dried,"], ["ona vaivai ai lea o a'u,", "then shall I be weak,"], ["e avea foi e pei o se tasi tagata.", "and be as another man."]]},
  {num:8,words:[["Ona avae lea ia te ia e alii o Filisitia o maea mata e fitu, e lei faapopoina,", "Then the lords of the Philistines brought up to her seven green withs which had not been dried,"], ["ua ia fusifusia a'i o ia.", "and she bound him with them."]]},
  {num:9,words:[["Sa nonofo ma ia i le afeafe o e lamalama;", "Now there were men lying in wait,"], ["ua ia fai mai ia te ia,", "abiding with her in the chamber. And she said unto him,"], ["Samasoni e, ua o mai ia te oe o Filisitia;", "The Philistines be upon thee,"], ["ona motusi lea e ia o maea e pei ona motusi le manoa lino ua mu i le afi;", "Samson. And he brake the withs,"], ["ua le iloa po o le a lona malosi.", "as a thread of tow is broken when it toucheth the fire. So his strength was not known."]]},
  {num:10,words:[["Ua fai mai Talila ia Samasoni,", "And Delilah said unto Samson,"], ["Faauta,", "Behold,"], ["ua e pelogia a'u,", "thou hast mocked me,"], ["ua e fai mai foi mea pepelo;", "and told me lies:"], ["o lenei,", "now tell me,"], ["se'i e ta'u mai lava ia te au,", "I pray thee,"], ["po o le a e fusifusi a'i oe.", "wherewith thou mightest be bound."]]},
  {num:11,words:[["Ona fai atu lea o ia ia te ia,", "And he said unto her,"], ["Afai e matuā fusifusia a'u i maea fou,", "If they bind me fast with new ropes that never were occupied,"], ["e lei fai a'i se galuega, ona ou vaivai ai lea,", "then shall I be weak,"], ["e avea foi a'u e pei o se tasi tagata.", "and be as another man."]]},
  {num:12,words:[["Ona ave lea e Talila o maea fou,", "Delilah therefore took new ropes,"], ["ua na fusifusia a'i o ia,", "and bound him therewith,"], ["ona fai mai lea o ia ia te ia, Samasoni e,", "and said unto him,"], ["ua o mai Filisitia ia te oe. Sa nonofo i le afeafe o e lamalama;", "The Philistines be upon thee,"], ["ona ia motusi ai lea o maea ai ona lima e pei o se manoa.", "Samson. And there were liers in wait abiding in the chamber. And he brake them from off his arms like a thread."]]},
  {num:13,words:[["Ona fai mai lea o Talila ia Samasoni,", "And Delilah said unto Samson,"], ["Ua oo mai i lenei aso ua e pelogia a'u,", "Hitherto thou hast mocked me,"], ["ma e fai mai mea pepelo ia te au; ina ta'u mai ia ia te au,", "and told me lies:"], ["pe se a se mea e fusifusia a'i oe.", "tell me wherewith thou mightest be bound."], ["Ona fai atu lea o ia ia te ia,", "And he said unto her,"], ["Afai e te lagā fuafuati e fitu o lo'u lauulu faatasi ma le ala o le ie .", "If thou weavest the seven locks of my head with the web."]]},
  {num:14,words:[["Ua ia faamauina i le faamau,", "And she fastened it with the pin,"], ["ona fai mai lea o ia ia te ia,", "and said unto him,"], ["Samasoni e,", "The Philistines be upon thee,"], ["ua o mai ia te oe o Filisitia. Ona ala lea o ia na moe,", "Samson. And he awaked out of his sleep,"], ["ua na liaiina le faamau o le mea ua lalagaina,", "and went away with the pin of the beam,"], ["atoa ma le ala o le ie .", "and with the web."]]},
  {num:15,words:[["Ona fai mai lea o ia ia te ia,", "And she said unto him,"], ["Pe faapefea ona e fai mai,", "How canst thou say,"], ["ua e alofa mai ia te au, a e le ia te au lou loto? Ua e pelogia a'u,", "I love thee,"], ["o le atu tolu lenei e te lei ta'u mai ia te au,", "when thine heart is not with me? thou hast mocked me these three times,"], ["po o le a lou malosi tele.", "and hast not told me wherein thy great strength lieth."]]},
  {num:16,words:[["Ua oo ina faatiga ia te ia i lona fai mai i aso uma,", "And it came to pass,"], ["ua na faatauanauina o ia;", "when she pressed him daily with her words,"], ["ona faavaivai ai lea o lona loto,", "and urged him,"], ["a oti;", "so that his soul was vexed unto death;"]]},
  {num:17,words:[["ona ta'u atu ai lea ia te ia o lona loto uma,", "That he told her all his heart,"], ["ua fai atu ia te ia,", "and said unto her,"], ["E lei oo se tafi i lo'u ulu;", "There hath not come a razor upon mine head;"], ["auā o a'u o le naseri i le Atua,", "for I have been a Nazarite unto God from my mother's womb:"], ["talu ina fanau mai; afai e tafi lo'u lauulu ,", "if I be shaven,"], ["ona mavae ai lea o lo'u malosi,", "then my strength will go from me,"], ["ou te vaivai,", "and I shall become weak,"], ["e avea foi a'u e pei o se tasi tagata.", "and be like any other man."]]},
  {num:18,words:[["Ua iloa e Talila ua na ta'u atu ia te ia lona loto uma,", "And when Delilah saw that he had told her all his heart,"], ["ona ia feau atu lea, ma aami i alii o Filisitia,", "she sent and called for the lords of the Philistines,"], ["o loo faapea,", "saying,"], ["Ina maliu mai ia, o le toe siliga lenei,", "Come up this once,"], ["auā ua na ta'u mai ia te au lona loto uma lava.", "for he hath shewed me all his heart."], ["Ona o ae lea ia te ia o alii o Filisitia,", "Then the lords of the Philistines came up unto her,"], ["ua latou avae foi tupe i o latou lima.", "and brought money in their hand."]]},
  {num:19,words:[["Ua na faamoe ia te ia i ona vae;", "And she made him sleep upon her knees;"], ["ona valaau lea i le tagata e tafi i fuafuati e fitu o lona lauulu,", "and she called for a man,"], ["ona afua ai lea e ia ona faatiga ia te ia;", "and she caused him to shave off the seven locks of his head; and she began to afflict him,"], ["ua mavae lona malosi ai ia te ia.", "and his strength went from him."]]},
  {num:20,words:[["Ua fai mai o ia,", "And she said,"], ["Samasoni e, ua o mai Filisitia ia te oe. Ua ala ia na moe,", "The Philistines be upon thee,"], ["ona fai ane lea,", "Samson. And he awoke out of his sleep,"], ["Ou te alu atu e pei ona muai fai,", "and said,"], ["ma ou lulu ia te au; a o ia na te lei iloa,", "I will go out as at other times before,"], ["ua afio ese Ieova ia te ia.", "and shake myself. And he wist not that the LORD was departed from him."]]},
  {num:21,words:[["Ona pue lea e Filisitia ia te ia,", "But the Philistines took him,"], ["ua sasali ona mata;", "and put out his eyes,"], ["ua ave ifo ia te ia i Kasa,", "and brought him down to Gaza,"], ["ma nonoa ia te ia i fusi 'apa memea e lua;", "and bound him with fetters of brass;"], ["ua ia olo saito foi i le fale puipui.", "and he did grind in the prison house."]]},
  {num:22,words:[["A ua amata ona toe tupu o le lauulu i lona ulu, e pei o ona po na le tafia.", "Howbeit the hair of his head began to grow again after he was shaven."]]},
  {num:23,words:[["Ua potopoto alii o Filisitia e fai le taulaga tele ia Takono lo latou atua,", "Then the lords of the Philistines gathered them together for to offer a great sacrifice unto Dagon their god,"], ["ma fiafia ai;", "and to rejoice:"], ["ua latou faapea,", "for they said,"], ["Ua tuuina mai Samasoni lo tatou fili i o tatou lima e lo tatou atua.", "Our god hath delivered Samson our enemy into our hand."]]},
  {num:24,words:[["Ua iloa o ia e le nuu,", "And when the people saw him,"], ["ona latou vivii lea i lo latou atua,", "they praised their god:"], ["auā ua faapea i latou,", "for they said,"], ["Ua tuuina mai i o tatou lima e lo tatou atua o lo tatou fili,", "Our god hath delivered into our hands our enemy,"], ["o le na moana ai lo tatou fanua,", "and the destroyer of our country,"], ["ma na fasia o tatou e toatele.", "which slew many of us."]]},
  {num:25,words:[["Ua oo ina fiafia o latou loto,", "And it came to pass,"], ["ona latou fai ane lea,", "when their hearts were merry,"], ["Valaau ia Samasoni,", "that they said, Call for Samson,"], ["se'i tatou tapisa a'i ai.", "that he may make us sport."], ["Ona latou amia lea o Samasoni ai le fale puipui,", "And they called for Samson out of the prison house;"], ["ua tapisa ai i latou;", "and he made them sport:"], ["ua latou faatuina o ia i le va o poutu.", "and they set him between the pillars."]]},
  {num:26,words:[["Ua fai atu Samasoni i le taulealea, le na taofi i lona lima,", "And Samson said unto the lad that held him by the hand,"], ["Tuu mai ia o a'u,", "Suffer me that I may feel the pillars whereupon the house standeth,"], ["se'i ou tagotago atu i pou e mau ai le fale, ou te faalagolago atu i ai.", "that I may lean upon them."]]},
  {num:27,words:[["Sa tumu le fale i tane ma fafine; sa i ai o alii uma o Filisitia;", "Now the house was full of men and women;"], ["sa i luga o le fale,", "and all the lords of the Philistines were there;"], ["pe atoa se tolu gaafe o tane ma fine,", "and there were upon the roof about three thousand men and women,"], ["o loo maimoa ia Samasoni, o loo faa'ataina.", "that beheld while Samson made sport."]]},
  {num:28,words:[["Ona valaau lea o Samasoni ia Ieova ua fai atu,", "And Samson called unto the LORD, and said,"], ["Le Alii Ieova e,", "O Lord GOD,"], ["ia e manatu mai,", "remember me, I pray thee,"], ["ma e faamalosi mai tau lava i lenei toe mea,", "and strengthen me, I pray thee,"], ["le Atua e,", "only this once,"], ["ina ia ou taui ma sui faatasi ia Filisitia i o'u mata e lua.", "O God, that I may be at once avenged of the Philistines for my two eyes."]]},
  {num:29,words:[["Ona lolo'u ai lea e Samasoni i pou e lua i totonu na mau ai le fale,", "And Samson took hold of the two middle pillars upon which the house stood,"], ["ma lagolago ai,", "and on which it was borne up, of the one with his right hand,"], ["o le tasi i lona lima taumatau ma le tasi i lona lima taugavale.", "and of the other with his left."]]},
  {num:30,words:[["Ua fai atu Samasoni,", "And Samson said,"], ["Ia ou oti faatasi ma Filisitia. Ona punou faamalosi lea,", "Let me die with the Philistines. And he bowed himself with all his might;"], ["ua paū le fale i luga o alii, ma luga o le nuu uma sa i ai;", "and the house fell upon the lords,"], ["sa toatele e na fasiotia e ia i lona oti i e na fasiotia a o ola ia.", "and upon all the people that were therein. So the dead which he slew at his death were more than they which he slew in his life."]]},
  {num:31,words:[["Ona o ifo lea o ona uso ma le aiga uma o lona tamā,", "Then his brethren and all the house of his father came down,"], ["ua latou siitia o ia,", "and took him,"], ["ma avae,", "and brought him up,"], ["ua tanu ia te ia i le va o Soraa ma Esetaola i le tuugamau o Manoa lona tamā. Ua ia faamasino ia Isaraelu i tausaga e luafulu.", "and buried him between Zorah and Eshtaol in the buryingplace of Manoah his father. And he judged Israel twenty years."]]},
];
renderVerseSet(jdg_ch_16_Verses, 'jdg-ch16-verses');

var jdg_ch_17_Verses = [
  {num:1,words:[["O le tasi tagata na i le mauga o Efaraima,", "And there was a man of mount Ephraim,"], ["o Mika lona igoa.", "whose name was Micah."]]},
  {num:2,words:[["Ua ia fai atu i lona tinā,", "And he said unto his mother,"], ["O tupe e afe ma le selau e tasi,", "The eleven hundred shekels of silver that were taken from thee,"], ["na avea nai ia te oe,", "about which thou cursedst,"], ["sa e fetuu ai,", "and spakest of also in mine ears,"], ["na e fai ane foi a o ou faalogo atu;", "behold,"], ["faauta i tupe,", "the silver is with me;"], ["ua ia te au,", "I took it. And his mother said,"], ["na ou avea. Ona fai mai lea o lona tinā ia te ia,", "Blessed be thou of the LORD,"], ["Ia faamanuia oe la'u tama e Ieova.", "my son."]]},
  {num:3,words:[["Na ia toe avatu tupe e afe ma le selau e tasi i lona tinā,", "And when he had restored the eleven hundred shekels of silver to his mother,"], ["Ua fai mai lona tinā, Na ou matuā faasaina ia tupe ia Ieova ai lo'u lima mo la'u tama,", "his mother said,"], ["e fai a'i se tupua ua ta,", "I had wholly dedicated the silver unto the LORD from my hand for my son,"], ["ma se tupua ario; o lenei,", "to make a graven image and a molten image:"], ["avatu pea ia ia te oe.", "now therefore I will restore it unto thee."]]},
  {num:4,words:[["A ua na toe avatu tupe i lona tinā;", "Yet he restored the money unto his mother;"], ["ona ave lea e lona tinā o tupe e lua selau i le tufuga fai mea uamea,", "and his mother took two hundred shekels of silver,"], ["ua ia fai a'i le tupua ua ta ma le tupua ario,", "and gave them to the founder, who made thereof a graven image and a molten image:"], ["sa i ai i le fale o Mika.", "and they were in the house of Micah."]]},
  {num:5,words:[["Sa i le tagata o Mika se fale o le Atua,", "And the man Micah had an house of gods, and made an ephod,"], ["na ia faia le efota ma tupua,", "and teraphim,"], ["ua ia tofia foi le tasi o ona atalii ua fai ma faitaulaga ia te ia.", "and consecrated one of his sons, who became his priest."]]},
  {num:6,words:[["O ona po ia sa leai se tupu ia Isaraelu,", "In those days there was no king in Israel,"], ["sa taitasi ma fai le mea ua tonu i lona lava manatu.", "but every man did that which was right in his own eyes."]]},
  {num:7,words:[["O le taulealea foi mai Peteleema o Iuta mai le itu aiga o Iuta,", "And there was a young man out of Beth-lehem-judah of the family of Judah,"], ["a o le sa Levī o ia,", "who was a Levite,"], ["ua āumau o ia i lea mea.", "and he sojourned there."]]},
  {num:8,words:[["Ua alu o ia nai le aai o Peteleema o Iuta e soona āumau i se mea e maua;", "And the man departed out of the city from Beth-lehem-judah to sojourn where he could find a place: and he came to mount Ephraim to the house of Micah,"], ["ona oo atu lea o lana malaga i le mauga o Efaraima i le fale o Mika.", "as he journeyed."]]},
  {num:9,words:[["Ua fesili atu Mika ia te ia,", "And Micah said unto him,"], ["Na ifea oe? Ua tali mai o ia ia te ia,", "Whence comest thou? And he said unto him,"], ["O a'u le sa Levī, mai Peteleema o Iuta;", "I am a Levite of Beth-lehem-judah,"], ["ou te alu e soona āumau i se mea ou te maua.", "and I go to sojourn where I may find a place."]]},
  {num:10,words:[["Ona fai atu lea o Mika ia te ia,", "And Micah said unto him,"], ["Ta te nonofo ma a'u,", "Dwell with me,"], ["ia fai oe mo'u tamā ma'u faitaulaga; a o a'u,", "and be unto me a father and a priest,"], ["ou te avatu ia te oe tupe e sefulu i lea tausaga ma lea tausaga,", "and I will give thee ten shekels of silver by the year,"], ["ma ou ofu,", "and a suit of apparel,"], ["ma au mea e 'ai.", "and thy victuals."], ["Ona alu ane ai lea o le sa Levī.", "So the Levite went in."]]},
  {num:11,words:[["Ua loto le sa Levī ona la nonofo ma le tagata,", "And the Levite was content to dwell with the man;"], ["sa i ai le taulealea ia te ia e pei o sona lava atalii.", "and the young man was unto him as one of his sons."]]},
  {num:12,words:[["Ona tofia lea e Mika o le sa Levī,", "And Micah consecrated the Levite;"], ["na fai foi le taulealea ma faitaulaga ia te ia,", "and the young man became his priest,"], ["sa i ai o ia i le aiga o Mika.", "and was in the house of Micah."]]},
  {num:13,words:[["Ona fai ane lea o Mika,", "Then said Micah,"], ["O lenei, ua ou iloa e agalelei mai Ieova ia te au,", "Now know I that the LORD will do me good,"], ["auā ua ia te au le sa Levī e fai ma ositaulaga.", "seeing I have a Levite to my priest."]]},
];
renderVerseSet(jdg_ch_17_Verses, 'jdg-ch17-verses');

var jdg_ch_18_Verses = [
  {num:1,words:[["O ona po ia sa leai se tupu ia Isaraelu;", "In those days there was no king in Israel:"], ["o ona po foi ia na saili ai e le itu aiga o Tanu se mea e nonofo ai i latou;", "and in those days the tribe of the Danites sought them an inheritance to dwell in;"], ["auā ua oo i lea aso e lei te'a atu ia te i latou o latou fanua na tofia i itu aiga o Isaraelu.", "for unto that day all their inheritance had not fallen unto them among the tribes of Israel."]]},
  {num:2,words:[["Ua aauina e le fanauga a Tanu ai lo latou aiga tagata e toalima mai lo latou nuu,", "And the children of Dan sent of their family five men from their coasts, men of valour,"], ["o tagata totoa,", "from Zorah,"], ["mai Soraa ma Esetaola,", "and from Eshtaol,"], ["e asiasi le nuu ma vaavaai i ai;", "to spy out the land, and to search it;"], ["ua latou fai atu ia te i latou,", "and they said unto them, Go,"], ["O ia,", "search the land:"], ["ina outou vaavaai i le nuu. Ona latou oo lea i le mauga o Efaraima i le fale o Mika,", "who when they came to mount Ephraim,"], ["ua latou momoe ai.", "to the house of Micah, they lodged there."]]},
  {num:3,words:[["Sa latalata ane i latou i le fale o Mika,", "When they were by the house of Micah,"], ["ona latou iloa lea o le leo o le taulealea o sa Levī,", "they knew the voice of the young man the Levite:"], ["ua latou afe ai;", "and they turned in thither,"], ["ona latou fai atu lea ia te ia,", "and said unto him,"], ["O ai ea na aumaina oe iinei? Se a foi sau mea e fai iinei? O a ea ni mea ua ia te oe i le mea nei?", "Who brought thee hither? and what makest thou in this place? and what hast thou here?"]]},
  {num:4,words:[["Ua ia fai mai ia te i latou,", "And he said unto them,"], ["O loo faapea ona fai e Mika ia te au;", "Thus and thus dealeth Micah with me,"], ["na te totogi ia te au,", "and hath hired me,"], ["a e fai a'u ma faitaulaga ia te ia.", "and I am his priest."]]},
  {num:5,words:[["Ona latou fai atu lea ia te ia,", "And they said unto him,"], ["Ia e fesili i le Atua,", "Ask counsel,"], ["ina ia matou iloa,", "we pray thee, of God,"], ["pe manuia la matou malaga matou te o atu ai?", "that we may know whether our way which we go shall be prosperous."]]},
  {num:6,words:[["Ua fai mai le faitaulaga ia te i latou,", "And the priest said unto them,"], ["O ia ma le manuia;", "Go in peace:"], ["o loo ua silafia e Ieova lo outou ala tou te ui ai.", "before the LORD is your way wherein ye go."]]},
  {num:7,words:[["Ona savavali lea o ia tagata e toalima,", "Then the five men departed,"], ["ua oo i Laisa,", "and came to Laish,"], ["ua latou vaavaai i le nuu sa i ai,", "and saw the people that were therein,"], ["ua latou nonofo faatalanoa,", "how they dwelt careless,"], ["e pei o le masani o Saitonu; o loo fifilemu,", "after the manner of the Zidonians,"], ["ua faatalanoa lava;", "quiet and secure;"], ["ua leai foi se na te faamā ia te i latou i se mea i le nuu,", "and there was no magistrate in the land,"], ["se na te pule ai;", "that might put them to shame in any thing;"], ["sa mamao foi latou ma Saitonu,", "and they were far from the Zidonians,"], ["sa latou le feaveai mea ma nisi tagata.", "and had no business with any man."]]},
  {num:8,words:[["Ona oo lea i o latou uso i Soraa ma Esetaola. Ua fai mai o latou uso ia te i latou,", "And they came unto their brethren to Zorah and Eshtaol: and their brethren said unto them,"], ["Se a sa outou tala?", "What say ye?"]]},
  {num:9,words:[["Ua fai atu i latou,", "And they said,"], ["Tulai ia,", "Arise, that we may go up against them:"], ["ina tatou o ae ia te i latou,", "for we have seen the land,"], ["auā ua matou vaavaai i le nuu,", "and,"], ["faauta,", "behold,"], ["e matuā lelei lava;", "it is very good: and are ye still? be not slothful to go,"], ["tou te nofonofo ea? Aua ne'i mumusu e o atu ia oo e fai mo outou le nuu.", "and to enter to possess the land."]]},
  {num:10,words:[["A outou o atu,", "When ye go,"], ["ona outou oo lea i le nuu ua nonofo faatalanoa,", "ye shall come unto a people secure,"], ["ma le fanua lautele;", "and to a large land: for God hath given it into your hands;"], ["auā ua foai mai ai e le Atua ia te outou le nuu e le oge i se mea e tasi i le lalolagi.", "a place where there is no want of any thing that is in the earth."]]},
  {num:11,words:[["Ona o ai lea ai lea mea nisi o le aiga o sa Tanū mai Soraa ma Esetaola,", "And there went from thence of the family of the Danites,"], ["o tagata e toaono galau,", "out of Zorah and out of Eshtaol,"], ["ua saunia ma auupega o le taua.", "six hundred men appointed with weapons of war."]]},
  {num:12,words:[["Ua o ae i latou,", "And they went up,"], ["ma to lauapi i Kiriata-iarima i Iuta;", "and pitched in Kirjath-jearim,"], ["o le mea lea na igoa ai lea mea o Maane-tanu,", "in Judah:"], ["ua oo mai i nei ona aso;", "wherefore they called that place Mahaneh-dan unto this day:"], ["faauta,", "behold,"], ["o loo i tua o Kiriata-iarima.", "it is behind Kirjath-jearim."]]},
  {num:13,words:[["Ona latou o atu lea ai lea mea i le mauga o Efaraima,", "And they passed thence unto mount Ephraim,"], ["ua oo atu i le fale o Mika.", "and came unto the house of Micah."]]},
  {num:14,words:[["Ona fai mai lea o tagata e toalima e na o e asiasi i le nuu o Laisa, ua faapea mai i o latou uso,", "Then answered the five men that went to spy out the country of Laish,"], ["Ua outou iloa ea,", "and said unto their brethren,"], ["o i ai i nei fale le efota,", "Do ye know that there is in these houses an ephod,"], ["ma tupua, ma le tupua ua ta,", "and teraphim,"], ["ma le tupua ario; o lenei,", "and a graven image,"], ["ia filifili se mea e fai.", "and a molten image? now therefore consider what ye have to do."]]},
  {num:15,words:[["Ona latou afe ai lea,", "And they turned thitherward,"], ["ua oo i le fale o le taulealea o le sa Levī,", "and came to the house of the young man the Levite,"], ["o le fale o Mika,", "even unto the house of Micah,"], ["ua latou fealofani ma ia.", "and saluted him."]]},
  {num:16,words:[["O tagata e toaono galau ua saunia ma auupega o le taua,", "And the six hundred men appointed with their weapons of war,"], ["o le fanauga a Tanu,", "which were of the children of Dan,"], ["sa tutū i latou i le puipui o le faitotoa.", "stood by the entering of the gate."]]},
  {num:17,words:[["A ua o ae tagata e toalima,", "And the five men that went to spy out the land went up,"], ["e na o e asiasi i le nuu, ua latou ulu atu ai,", "and came in thither,"], ["ua ave le tupua ua ta,", "and took the graven image,"], ["ma le efota,", "and the ephod,"], ["ma tupua,", "and the teraphim,"], ["ma le tupua ario; a o le faitaulaga ua tu o ia i le puipui o le faitotoa ma tagata e toaono galau,", "and the molten image:"], ["e ua saunia ma auupega o le taua.", "and the priest stood in the entering of the gate with the six hundred men that were appointed with weapons of war."]]},
  {num:18,words:[["Ua latou ulu atu i le fale o Mika,", "And these went into Micah's house,"], ["ma latou ave le tupua ua ta,", "and fetched the carved image,"], ["ma le efota, ma tupua,", "the ephod,"], ["ma le tupua ario;", "and the teraphim,"], ["ona fai mai lea o le faitaulaga ia i latou,", "and the molten image. Then said the priest unto them,"], ["Se a le mea tou te faiana?", "What do ye?"]]},
  {num:19,words:[["A ua latou fai mai ia te ia,", "And they said unto him,"], ["Faalologo ia,", "Hold thy peace,"], ["tuu lou lima i lou gutu,", "lay thine hand upon thy mouth,"], ["ma ia tatou o ma i matou, ia fai oe mo matou tamā ma faitaulaga;", "and go with us,"], ["pe lelei ea ona fai oe ma faitaulaga;", "and be to us a father and a priest:"], ["pe lelei ea ona fai oe ma faitaulaga i le aiga o le tagata e toatasi,", "is it better for thee to be a priest unto the house of one man,"], ["pe fai ma faitaulaga i le itu aiga ma le aiga o Isaraelu?", "or that thou be a priest unto a tribe and a family in Israel?"]]},
  {num:20,words:[["Ua fiafia ai le loto o le faitaulaga,", "And the priest's heart was glad,"], ["ona ave ai lea e ia o le efota,", "and he took the ephod,"], ["ma tupua,", "and the teraphim,"], ["ma le tupua ua ta,", "and the graven image,"], ["ua o atu faatasi ma le nuu.", "and went in the midst of the people."]]},
  {num:21,words:[["Ona toe o ai lea o i latou, ma latou savavali; ua latou tuu atu i o latou luma,", "So they turned and departed,"], ["o tama iti, ma manu, ma avegāmea.", "and put the little ones and the cattle and the carriage before them."]]},
  {num:22,words:[["Ua mamao i latou ma le fale o Mika,", "And when they were a good way from the house of Micah,"], ["ona faapotopoto lea o tagata sa i fale e tuaoi ma le fale o Mika,", "the men that were in the houses near to Micah's house were gathered together,"], ["ua latou tulituliloa i le fanauga a Tanu.", "and overtook the children of Dan."]]},
  {num:23,words:[["Ona latou valaau lea i le fanauga a Tanu,", "And they cried unto the children of Dan. And they turned their faces,"], ["ona latou faasaga mai ai lea,", "and said unto Micah,"], ["ua latou fai mai ia Mika, Se a ea le mea ua e tiga ai ,", "What aileth thee,"], ["ina ua e faapotopotoina mai ai na tagata ia te oe?", "that thou comest with such a company?"]]},
  {num:24,words:[["Ua fai mai o ia,", "And he said,"], ["Ua outou aveesea o'u atua na ou faia,", "Ye have taken away my gods which I made,"], ["ma le faitaulaga ua outou o,", "and the priest, and ye are gone away:"], ["se a sa'u toe mea? A o le a lena ua outou fai mai ai,", "and what have I more? and what is this that ye say unto me,"], ["Se a le mea ou te tiga ai?", "What aileth thee?"]]},
  {num:25,words:[["Ua fai mai le fanauga a Tanu ia te ia,", "And the children of Dan said unto him,"], ["Aua ne'i lagona lou leo e i matou,", "Let not thy voice be heard among us,"], ["ne'i oso atu ia te outou tagata lotōa,", "lest angry fellows run upon thee, and thou lose thy life,"], ["ona oti ai lea o oe ma lou aiga.", "with the lives of thy household."]]},
  {num:26,words:[["Ona savavali lea o le fanauga a Tanu i la latou malaga. Ua iloa e Mika ua sili ona malosi i latou ia te ia,", "And the children of Dan went their way:"], ["ona liliu lea o ia,", "and when Micah saw that they were too strong for him,"], ["ua foi atu i lona aiga.", "he turned and went back unto his house."]]},
  {num:27,words:[["A o i latou,", "And they took the things which Micah had made,"], ["ua latou ave mea na faia e Mika,", "and the priest which he had,"], ["ma le faitaulaga sa ia te ia, ua latou oo atu i Laisa i le nuu filemu,", "and came unto Laish,"], ["ua nonofo faatalanoa lava;", "unto a people that were at quiet and secure:"], ["ua latou fasia i latou i le pelu,", "and they smote them with the edge of the sword,"], ["ma susunu le aai i le afi.", "and burnt the city with fire."]]},
  {num:28,words:[["Sa leai se na te laveai,", "And there was no deliverer,"], ["auā e vava mamao lea ma Saitonu,", "because it was far from Zidon,"], ["sa latou le feaveai foi mea ma nisi tagata;", "and they had no business with any man;"], ["sa i le vanu lea nuu e lata ane i Petereopo. Ua latou faia le faiaai,", "and it was in the valley that lieth by Beth-rehob. And they built a city,"], ["ma latou mau ai.", "and dwelt therein."]]},
  {num:29,words:[["Ua latou faaigoa le igoa o le aai o Tanu,", "And they called the name of the city Dan,"], ["i le igoa o Tanu lo latou tamā,", "after the name of Dan their father,"], ["na fanau ai ia Isaraelu;", "who was born unto Israel:"], ["a e peitai o Laisa le igoa o le aai anamua.", "howbeit the name of the city was Laish at the first."]]},
  {num:30,words:[["Ua faatuina mo i latou e le fanauga a Tanu le tupua ua ta,", "And the children of Dan set up the graven image:"], ["o Ionatana foi le atalii o Keresoma,", "and Jonathan,"], ["le atalii lea o Manase,", "the son of Gershom,"], ["o ia ma ona atalii sa fai ma faitaulaga i latou i le itu aiga o sa Tanū,", "the son of Manasseh,"], ["ua oo i le aso o le tafeaga o le nuu.", "he and his sons were priests to the tribe of Dan until the day of the captivity of the land."]]},
  {num:31,words:[["Ua latou faatuina mo i latou le tupua ua ta a Mika,", "And they set them up Micah's graven image,"], ["na ia faia,", "which he made,"], ["i aso uma sa i ai le malumalu o le Atua i Sailo.", "all the time that the house of God was in Shiloh."]]},
];
renderVerseSet(jdg_ch_18_Verses, 'jdg-ch18-verses');

var jdg_ch_19_Verses = [
  {num:1,words:[["O ia ona aso sa leai se tupu ia Isaraelu,", "And it came to pass in those days,"], ["ua āumau le tagata sa Levī i le itu o le mauga o Efaraima;", "when there was no king in Israel,"], ["sa fai avā o ia, o le palake foi,", "that there was a certain Levite sojourning on the side of mount Ephraim,"], ["mai Peteleema o Iuta.", "who took to him a concubine out of Beth-lehem-judah."]]},
  {num:2,words:[["Ua mulilua lana palake,", "And his concubine played the whore against him,"], ["ua alu ese ia te ia i le aiga o lona tamā i Peteleema o Iuta,", "and went away from him unto her father's house to Beth-lehem-judah,"], ["sa i ai i masina e fa.", "and was there four whole months."]]},
  {num:3,words:[["Ona tulai lea o lana tane,", "And her husband arose, and went after her,"], ["ua alu atu ia te ia e tautala lelei ma ia,", "to speak friendly unto her,"], ["ma toe aumaia o ia;", "and to bring her again,"], ["sa ia te ia lana auauna ma asini e lua. Ona aumaia lea o ia e le fafine i le fale o lona tamā;", "having his servant with him, and a couple of asses:"], ["ua vaai mai le tamā o le teine,", "and she brought him into her father's house: and when the father of the damsel saw him,"], ["ona fiafia lea ina ua feiloai ma ia.", "he rejoiced to meet him."]]},
  {num:4,words:[["Ona taofia lea o ia e le tamā o lana avā,", "And his father in law,"], ["o le tamā o le teine,", "the damsel's father,"], ["ua la nonofo ma ia i aso e tolu;", "retained him; and he abode with him three days:"], ["ua latou aai ma inu,", "so they did eat and drink,"], ["ma latou momoe ai.", "and lodged there."]]},
  {num:5,words:[["Ona oo lea i le aso fa,", "And it came to pass on the fourth day,"], ["ua vave ala lava ia i le taeao,", "when they arose early in the morning,"], ["ua tulai a alu. Ona fai mai lea o le tamā o le teine i le tane o lona afafine,", "that he rose up to depart: and the damsel's father said unto his son in law,"], ["Ia e faamalosi lou loto i sina mea e 'ai,", "Comfort thine heart with a morsel of bread,"], ["ona lua o ai lea.", "and afterward go your way."]]},
  {num:6,words:[["Ona la nonofo ai lea,", "And they sat down,"], ["ua aai ma inu faatasi i laua,", "and did eat and drink both of them together: for the damsel's father had said unto the man,"], ["auā na fai atu le tamā o le teine i le tagata,", "Be content,"], ["Ia e loto mai ona tatou momoe,", "I pray thee, and tarry all night,"], ["ma e faafiafia lou loto.", "and let thine heart be merry."]]},
  {num:7,words:[["Ona tulai lea o le tagata e alu;", "And when the man rose up to depart,"], ["ona pulunaunau lea ia te ia o le tamā o lana avā, ona nofo ai lea,", "his father in law urged him:"], ["ua toe moe ai.", "therefore he lodged there again."]]},
  {num:8,words:[["Ona vave ala lea o ia i le taeao o le aso lima,", "And he arose early in the morning on the fifth day to depart:"], ["o le a alu; ona fai mai lea le tamā o le teine,", "and the damsel's father said,"], ["Ia e faamalosi lou loto;", "Comfort thine heart,"], ["ona faatuatuai lea o i laua, ua oo i le faliu o le la;", "I pray thee. And they tarried until afternoon,"], ["sa la aai faatasi.", "and they did eat both of them."]]},
  {num:9,words:[["Ona tulai lea o le tagata,", "And when the man rose up to depart,"], ["a latou o ma lana palake ma lana auauna;", "he,"], ["ua fai mai ia te ia le tamā o lana avā,", "and his concubine, and his servant,"], ["ole tamā o le teine. Faauta ea,", "his father in law,"], ["o le a po lenei aso,", "the damsel's father,"], ["o le a afiafi,", "said unto him,"], ["se'i tatou momoe;", "Behold, now the day draweth toward evening,"], ["faauta,", "I pray you tarry all night:"], ["ua tāli po,", "behold,"], ["ina moe ia iinei,", "the day groweth to an end,"], ["ma faafiafia lou loto,", "lodge here, that thine heart may be merry;"], ["a e usuusu outou taeao i la outou malaga,", "and to morrow get you early on your way,"], ["ma e alu i lou aiga.", "that thou mayest go home."]]},
  {num:10,words:[["E le mafai le tagata ona latou momoe,", "But the man would not tarry that night,"], ["ua tulai ma savali;", "but he rose up and departed,"], ["ona oo atu lava lea e feagai ma Iepuse,", "and came over against Jebus,"], ["(o Ierusalema foi lea;", "which is Jerusalem;"], [") sa ia te ia asini e lua ua faanofoaina,", "and there were with him two asses saddled,"], ["ua ia te ia foi lana palake.", "his concubine also was with him."]]},
  {num:11,words:[["Ua latalata i latou i Iepuse,", "And when they were by Jebus,"], ["ua matuā maulalo ifo le la;", "the day was far spent;"], ["ona fai mai lea o le auauna i lona alii,", "and the servant said unto his master, Come,"], ["Se'i tatou o,", "I pray thee,"], ["ma tatou afe ane i lenei aai o Iepuse,", "and let us turn in into this city of the Jebusites,"], ["ma tatou momoe ai.", "and lodge in it."]]},
  {num:12,words:[["A ua fai atu lona alii ia te ia,", "And his master said unto him,"], ["Aua tatou te afe i le aai o tagata ese,", "We will not turn aside hither into the city of a stranger,"], ["e le o le fanauga a Isaraelu i latou,", "that is not of the children of Israel;"], ["a e tatou o atu ia i Kipea.", "we will pass over to Gibeah."]]},
  {num:13,words:[["Ua fai atu foi i lana auauna,", "And he said unto his servant,"], ["Sau ia,", "Come,"], ["ina tatou faalatalata atu i so ia nuu,", "and let us draw near to one of these places to lodge all night,"], ["ma tatou momoe i Kipea,", "in Gibeah,"], ["po o Rama.", "or in Ramah."]]},
  {num:14,words:[["Ona latou o loa lea,", "And they passed on and went their way;"], ["ua savavali;", "and the sun went down upon them when they were by Gibeah,"], ["ua goto le la a o latalata i latou i Kipea o Peniamina.", "which belongeth to Benjamin."]]},
  {num:15,words:[["Ona latou afe atu ai lea,", "And they turned aside thither,"], ["ma ulu atu e momoe i Kipea;", "to go in and to lodge in Gibeah:"], ["ua oo i ai,", "and when he went in,"], ["ona latou nonofo lea i le malae o le aai,", "he sat him down in a street of the city:"], ["a ua leai se tagata na talia i latou i lona fale e momoe ai.", "for there was no man that took them into his house to lodging."]]},
  {num:16,words:[["Faauta,", "And,"], ["o le toeaina ua sau mai lana galuega i le vao i le afiafi,", "behold,"], ["o ia foi le tagata mai le mauga o Efaraima,", "there came an old man from his work out of the field at even, which was also of mount Ephraim;"], ["sa āumau o ia i Kipea;", "and he sojourned in Gibeah:"], ["a o tagata o le nuu o sa Peniaminā i latou .", "but the men of the place were Benjamites."]]},
  {num:17,words:[["Ua tepa ae o ia,", "And when he had lifted up his eyes,"], ["ua na iloa le malaga i le malae o le aai. Ona fai mai lea o le toeaina,", "he saw a wayfaring man in the street of the city: and the old man said,"], ["Po o fea e te alu i ai? Mai fea foi na e sau ai?", "Whither goest thou? and whence comest thou?"]]},
  {num:18,words:[["Ua tali atu o ia ia te ia,", "And he said unto him,"], ["Na matou o mai i Peteleema o Iuta,", "We are passing from Beth-lehem-judah toward the side of mount Ephraim;"], ["o le a o atu i le itu o le mauga o Efaraima, na ou sau ai i lea mea,", "from thence am I:"], ["na ou alu i Peteleema o Iuta,", "and I went to Beth-lehem-judah,"], ["a ou te alu nei i le fale o Ieova,", "but I am now going to the house of the LORD;"], ["ua le talia a'u e se tasi i lona fale;", "and there is no man that receiveth me to house."]]},
  {num:19,words:[["a o i ai lava 'au o saito ma mea e 'ai a matou asini,", "Yet there is both straw and provender for our asses;"], ["atoa ma mea e 'ai ma uaina ma'u,", "and there is bread and wine also for me,"], ["ma lau auauna fafine,", "and for thy handmaid,"], ["ma le taulealea o loo i lau auauna,", "and for the young man which is with thy servants:"], ["e leai lava se mativa i se mea e tasi.", "there is no want of any thing."]]},
  {num:20,words:[["Ua fai mai le toeaina,", "And the old man said,"], ["Ia manuia oe,", "Peace be with thee;"], ["tuu mai pea, faitalia a'u i mea uma e te mativa ai,", "howsoever let all thy wants lie upon me;"], ["tau lava ina ne'i e moe i le malae.", "only lodge not in the street."]]},
  {num:21,words:[["Ona ia avatu lea o i latou i lona fale,", "So he brought him into his house,"], ["ua fafaga i asini;", "and gave provender unto the asses:"], ["ua latou mulumulu i o latou vae,", "and they washed their feet,"], ["ma latou aai ma inu.", "and did eat and drink."]]},
  {num:22,words:[["Sa faafiafia e i latou o latou loto,", "Now as they were making their hearts merry,"], ["faauta o tagata o le nuu,", "behold,"], ["o tagata ulavavale,", "the men of the city, certain sons of Belial,"], ["ua latou siomia le fale o loo patu'i i le puipui;", "beset the house round about,"], ["ua latou fai mai i le tagata e ona le fale,", "and beat at the door,"], ["o le toeaina lea,", "and spake to the master of the house,"], ["o loo faapea mai,", "the old man, saying,"], ["Tuu mai ia le tagata na alu atu i lou fale,", "Bring forth the man that came into thine house,"], ["ina ia matou iloa o ia.", "that we may know him."]]},
  {num:23,words:[["Ona alu atu lea ia te i latou o le tagata e ona le fale,", "And the man, the master of the house,"], ["ua fai atu ia te i latou,", "went out unto them,"], ["Aua,", "and said unto them, Nay,"], ["o'u uso e,", "my brethren,"], ["aua lava ne'i outou agaleaga,", "nay, I pray you,"], ["ina ua ulu mai lenei tagata i lo'u fale,", "do not so wickedly;"], ["aua tou te faia lenei mea leaga;", "seeing that this man is come into mine house, do not this folly."]]},
  {num:24,words:[["faauta,", "Behold,"], ["o lo'u afafine o le taupou,", "here is my daughter a maiden,"], ["atoa ma lana palake,", "and his concubine;"], ["se'i ou aumaia i laua, tou te faaleaga ia i laua,", "them I will bring out now,"], ["ma ia faia e outou mea tou te loto i ai ia i laua;", "and humble ye them,"], ["a o lenei tagata,", "and do with them what seemeth good unto you:"], ["aua tou te faia lena mea leaga ia te ia.", "but unto this man do not so vile a thing."]]},
  {num:25,words:[["A e le mafafai tagata ona faalogo ia te ia,", "But the men would not hearken to him:"], ["ona pue atu lea e le tagata i lana palake,", "so the man took his concubine,"], ["ua na tuu atu ai o ia ia te i latou i fafo;", "and brought her forth unto them;"], ["ua latou iloa o ia,", "and they knew her,"], ["ma latou faaleaga ia te ia ua atoa lava le po;", "and abused her all the night until the morning:"], ["ua oo i le taeao,", "and when the day began to spring,"], ["ona latou tuu atu lea ia te ia e alu ina a malama ae le taeao.", "they let her go."]]},
  {num:26,words:[["Onā sau ai lea o le fafine i le vave ao,", "Then came the woman in the dawning of the day,"], ["ua paū i le faitotoa o le fale o le tagata sa i ai lona alii,", "and fell down at the door of the man's house where her lord was,"], ["ua oo i le malama aee ae o le taeao .", "till it was light."]]},
  {num:27,words:[["Ua tulai lona alii i le taeao,", "And her lord rose up in the morning,"], ["ma tatala puipui o le fale,", "and opened the doors of the house,"], ["ua ulufafo atu o le a alu lana malaga;", "and went out to go his way:"], ["faauta i le fafine,", "and,"], ["o lana palake,", "behold,"], ["ua paū i le faitotoa o le fale,", "the woman his concubine was fallen down at the door of the house,"], ["ma ona lima ua i le faitotoa.", "and her hands were upon the threshold."]]},
  {num:28,words:[["Ona fai mai lea o ia ia te ia, Tulai ia,", "And he said unto her,"], ["ina tatou o;", "Up,"], ["a e leai se tali; ona tago ai lea o ia ia te ia,", "and let us be going. But none answered. Then the man took her up upon an ass,"], ["ma faaee i le asini,", "and the man rose up,"], ["ua tulai le tagata, ua alu i lona nuu.", "and gat him unto his place."]]},
  {num:29,words:[["Ona oo lea o ia i lona fale,", "And when he was come into his house,"], ["ua tago i le polo,", "he took a knife, and laid hold on his concubine,"], ["ona 'u'u atu lea i lana palake,", "and divided her,"], ["ua pena ia te ia atoa ma ona ivi i tufaaga e sefulu ma le lua,", "together with her bones, into twelve pieces,"], ["ona avatu ai lea i itu uma o Isaraelu.", "and sent her into all the coasts of Israel."]]},
  {num:30,words:[["O i latou uma e na vaai i ai ua faapea ane i latou ,", "And it was so,"], ["E lei faia,", "that all that saw it said,"], ["e lei iloa foi se mea faapena talu le aso na o mai ai le fanauga a Isaraelu mai le nuu o Aikupito e oo i lenei aso;", "There was no such deed done nor seen from the day that the children of Israel came up out of the land of Egypt unto this day:"], ["ia outou manatunatu i lenei mea,", "consider of it,"], ["ia outou filifili,", "take advice,"], ["ma fai mai so outou loto .", "and speak your minds."]]},
];
renderVerseSet(jdg_ch_19_Verses, 'jdg-ch19-verses');

var jdg_ch_20_Verses = [
  {num:1,words:[["Ona o atu lea o le fanauga uma a Isaraelu,", "Then all the children of Israel went out,"], ["ma ua faapotopotoina le faapotopotoga ia Ieova, i Mesepa,", "and the congregation was gathered together as one man,"], ["e pei se tagata e toatasi,", "from Dan even to Beer-sheba,"], ["e pau mai i Tanu, e pau mai i Peresepa,", "with the land of Gilead,"], ["atoa ma le nuu o Kiliata.", "unto the LORD in Mizpeh."]]},
  {num:2,words:[["Ua tutū ai alii o le nuu uma,", "And the chief of all the people,"], ["o itu aiga uma o Isaraelu i le faapotopotoga o le nuu o le Atua,", "even of all the tribes of Israel,"], ["e fa selau o afe o tagata,", "presented themselves in the assembly of the people of God,"], ["o 'au e savavali e ua fai pelu.", "four hundred thousand footmen that drew sword."]]},
  {num:3,words:[["(Ua faalogo le fanauga a Peniamina, ua o ae le fanauga a Isaraelu,", "(Now the children of Benjamin heard that the children of Israel were gone up to Mizpeh.) Then said the children of Israel,"], ["i Mesepa.) Ona fai atu lea o le fanauga a Isaraelu,", "Tell us,"], ["Fai mai ia, pe na faapefea ona faia o lenei mea leaga?", "how was this wickedness?"]]},
  {num:4,words:[["Ua tali mai le tagata sa Levī,", "And the Levite, the husband of the woman that was slain,"], ["le tane a le fafine na fasia,", "answered and said,"], ["ua faapea mai,", "I came into Gibeah that belongeth to Benjamin,"], ["Na alu atu i maua ma la'u palake i Kipea o Peniamina e moe ai;", "I and my concubine, to lodge."]]},
  {num:5,words:[["ona tulai mai lea ia te au o tagata o Kipea,", "And the men of Gibeah rose against me,"], ["ma latou siosio mai ia te au i le fale i le po;", "and beset the house round about upon me by night,"], ["na latou manatu e fasioti ia te au,", "and thought to have slain me:"], ["a o la'u palake ua latou faaleaga ia te ia,", "and my concubine have they forced,"], ["ua oti ai.", "that she is dead."]]},
  {num:6,words:[["Ona ou tago atu lea i la'u palake,", "And I took my concubine,"], ["ma ou pena ia te ia,", "and cut her in pieces,"], ["ma avatu i nuu uma o le tofi o Isaraelu;", "and sent her throughout all the country of the inheritance of Israel:"], ["auā ua latou faia le mea leaga ma faivale i Isaraelu.", "for they have committed lewdness and folly in Israel."]]},
  {num:7,words:[["Faauta,", "Behold,"], ["o outou uma o le fanauga a Isaraelu,", "ye are all children of Israel;"], ["ina filifili ia outou iinei so outou manatu.", "give here your advice and counsel."]]},
  {num:8,words:[["Ona tulai lea o le nuu uma pei se tagata e toatasi,", "And all the people arose as one man,"], ["o loo faapea,", "saying,"], ["E le alu so tatou i lona fale ie,", "We will not any of us go to his tent,"], ["e le foi atu so tatou i lona fale;", "neither will we any of us turn into his house."]]},
  {num:9,words:[["a o lenei, tatou te faia le mea nei i Kipea;", "But now this shall be the thing which we will do to Gibeah;"], ["tatou te fai le vili i nisi e o ae ai;", "we will go up by lot against it;"]]},
  {num:10,words:[["tatou te fa'ifa'i tagata e toasefulu ai le toaselau i itu aiga uma o Isaraelu,", "And we will take ten men of an hundred throughout all the tribes of Israel,"], ["ma le toaselau i le afe,", "and an hundred of a thousand, and a thousand out of ten thousand,"], ["ma le afe ai le sefulu o afe,", "to fetch victual for the people,"], ["e fai mea e 'ai mā le nuu;", "that they may do, when they come to Gibeah of Benjamin,"], ["ina ia faia pe a oo i latou i Kipea o Peniamina e tusa ma le faivale uma ua latou faia i Isaraelu.", "according to all the folly that they have wrought in Israel."]]},
  {num:11,words:[["Sa faapotopoto tagata uma o Isaraelu e tau ma le aai;", "So all the men of Israel were gathered against the city,"], ["o loo loto gatasi i latou pei se tagata e toatasi.", "knit together as one man."]]},
  {num:12,words:[["Ona aauina atu lea e itu aiga o Isaraelu nisi tagata i aiga uma o Peniamina,", "And the tribes of Israel sent men through all the tribe of Benjamin,"], ["o loo faapea,", "saying,"], ["O le a lenei mea leaga ua faia e outou?", "What wickedness is this that is done among you?"]]},
  {num:13,words:[["O lenei,", "Now therefore deliver us the men,"], ["ina tuu mai ia o na tagata,", "the children of Belial,"], ["o tagata ulavavale o loo i Kipea,", "which are in Gibeah,"], ["ina ia matou fasioti ia i latou,", "that we may put them to death,"], ["ma tuu ese ai le leaga ia Isaraelu. A e le mafafai le fanauga a Peniamina ona faalogo i le upu a o latou uso le fanauga a Isaraelu;", "and put away evil from Israel. But the children of Benjamin would not hearken to the voice of their brethren the children of Israel:"]]},
  {num:14,words:[["a ua faapotopoto le fanauga a Peniamina i Kipea mai o latou aai,", "But the children of Benjamin gathered themselves together out of the cities unto Gibeah,"], ["ina ia latou o atu e tau ma le fanauga a Isaraelu.", "to go out to battle against the children of Israel."]]},
  {num:15,words:[["Ona faitauina lea o le fanauga a Peniamina i lea aso ai o latou aai,", "And the children of Benjamin were numbered at that time out of the cities twenty and six thousand men that drew sword,"], ["o afe e luafulu ma le ono gaafe o tagata ua fai pelu,", "beside the inhabitants of Gibeah,"], ["atoa ma tagata o Kipea e toafitu selau o tagata sili.", "which were numbered seven hundred chosen men."]]},
  {num:16,words:[["Sa i ai i nei tagata uma o tagata tauagavale ua sili,", "Among all this people there were seven hundred chosen men lefthanded;"], ["e toafitu selau; o i latou uma nei e sasau le maa i le maatā i le lauulu,", "every one could sling stones at an hair breadth,"], ["a e le sese.", "and not miss."]]},
  {num:17,words:[["Ua latou faitauina foi tagata o Isaraelu,", "And the men of Israel,"], ["e aunoa ma Peniamina,", "beside Benjamin,"], ["e fa selau afe o tagata e ua fai pelu;", "were numbered four hundred thousand men that drew sword:"], ["o i latou uma nei o le 'au tau.", "all these were men of war."]]},
  {num:18,words:[["Ona latou tulai lea,", "And the children of Israel arose,"], ["ma o ae i Peteli e fesili atu i le Atua;", "and went up to the house of God,"], ["ua fai atu ai le fanauga a Isaraelu,", "and asked counsel of God, and said,"], ["O ai ea e muamua ona alu ae mo i matou e tau ma le fanauga a Peniamina? Ona fetalai mai lea o Ieova,", "Which of us shall go up first to the battle against the children of Benjamin? And the LORD said,"], ["E muamua atu Iuta.", "Judah shall go up first."]]},
  {num:19,words:[["Ona tulai atu lea o le fanauga a Isaraelu i le taeao,", "And the children of Israel rose up in the morning,"], ["ua to lauapi e feagai ma Kipea.", "and encamped against Gibeah."]]},
  {num:20,words:[["Ona o atu lea o tagata o Isaraelu e tau ma Peniamina;", "And the men of Israel went out to battle against Benjamin;"], ["ona pae tau atu ai lea e tagata o Isaraelu e tau ma Kipea.", "and the men of Israel put themselves in array to fight against them at Gibeah."]]},
  {num:21,words:[["Ona o atu ai lea o le fanauga a Peniamina mai Kipea; ua latou fasiotia Isaraelu i lea aso,", "And the children of Benjamin came forth out of Gibeah,"], ["o tagata e luafulu o afe ma afe e lua.", "and destroyed down to the ground of the Israelites that day twenty and two thousand men."]]},
  {num:22,words:[["Ua faamalosi le nuu, o tagata o Isaraelu,", "And the people the men of Israel encouraged themselves,"], ["ua latou toe pae tau le taua i le mea na latou pae tau ai i le luai aso.", "and set their battle again in array in the place where they put themselves in array the first day."]]},
  {num:23,words:[["Ona o ae lea o le fanauga a Isaraelu,", "(And the children of Israel went up and wept before the LORD until even,"], ["ma latou fetagisi i luma o Ieova, ua oo i le afiafi,", "and asked counsel of the LORD,"], ["ma latou fesili ia Ieova,", "saying,"], ["o loo faapea, Ou te toe faalatalata ea e tau ma le fanauga a Peniamina lo'u uso? Ua fatalai mai Ieova,", "Shall I go up again to battle against the children of Benjamin my brother? And the LORD said,"], ["Tou te o ae ia te ia.", "Go up against him.)"]]},
  {num:24,words:[["Ona faalatalata lea o le fanauga a Isaraelu i le fanauga a Peniamina i le aso e lua.", "And the children of Israel came near against the children of Benjamin the second day."]]},
  {num:25,words:[["Ona alu atu lea o Peniamina mai Kipea e faafetaiai ia te i latou i le aso lua;", "And Benjamin went forth against them out of Gibeah the second day,"], ["ona toe fasiotia lea o le fanauga a Isaraelu, e sefulu afe ma afe e valu;", "and destroyed down to the ground of the children of Israel again eighteen thousand men;"], ["o i latou uma nei na fai pelu.", "all these drew the sword."]]},
  {num:26,words:[["Ona o ae lea o le fanauga uma a Isaraelu ma le nuu uma,", "Then all the children of Israel,"], ["ua latou oo atu i Peteli,", "and all the people, went up,"], ["ma latou fetagisi,", "and came unto the house of God,"], ["ma nonofo ai i luma o Ieova,", "and wept,"], ["ma latou anapopogi i lea aso e oo i le afiafi;", "and sat there before the LORD, and fasted that day until even,"], ["ua latou faia foi o taulaga mu atoa ma taulaga faafetai i luma o Ieova.", "and offered burnt offerings and peace offerings before the LORD."]]},
  {num:27,words:[["Ona fesili lea o le fanauga a Isaraelu ia Ieova;", "And the children of Israel enquired of the LORD,"], ["(auā sa i ai le atolaau o le feagaiga a le Atua i ia ona aso;", "(for the ark of the covenant of God was there in those days,"]]},
  {num:28,words:[["o Fineaso le atalii o Eleasaro,", "And Phinehas,"], ["le atalii ia o Arona,", "the son of Eleazar, the son of Aaron,"], ["o ia na tu i ona luma i ia ona aso;", "stood before it in those days,"], [") o loo faapea i latou . Ou te toe alu atu ea e tau ma le fanauga a Peniamina lo'u uso,", ") saying,"], ["pe soia? Ua fetalai mai Ieova,", "Shall I yet again go out to battle against the children of Benjamin my brother,"], ["O ae ia outou,", "or shall I cease? And the LORD said, Go up;"], ["auā a taeao ou te tuuina atu ai i latou i lou lima.", "for to morrow I will deliver them into thine hand."]]},
  {num:29,words:[["Ona tanu lea o 'au a Isaraelu e siosio ai i Kipea.", "And Israel set liers in wait round about Gibeah."]]},
  {num:30,words:[["Ona o ae lea o le fanauga a Isaraelu i le fanauga a Peniamina i le aso tolu,", "And the children of Israel went up against the children of Benjamin on the third day,"], ["ua pae tau atu le taua ia Kipea,", "and put themselves in array against Gibeah,"], ["e pei ona uluai faia.", "as at other times."]]},
  {num:31,words:[["Ona o atu lea o le fanauga a Peniamina e faafetaiai i le nuu,", "And the children of Benjamin went out against the people,"], ["na tosina i latou nai le aai;", "and were drawn away from the city; and they began to smite of the people,"], ["ua amata ona latou taia le nuu,", "and kill,"], ["ua manunua e pei o isi aso,", "as at other times,"], ["pe atoa le toatolugafulu o tagata o Isaraelu i ala tele,", "in the highways,"], ["(e alu ae ai le tasi i Peteli,", "of which one goeth up to the house of God, and the other to Gibeah in the field,"], ["a o le tasi e alu atu ai i Kipea i le vao.)", "about thirty men of Israel."]]},
  {num:32,words:[["Ona fai ane lea o le fanauga a Peniamina,", "And the children of Benjamin said,"], ["Ua fasia i latou i o tatou luma e pei o le amataga;", "They are smitten down before us,"], ["a ua fai ane le fanauga a Isaraelu,", "as at the first. But the children of Israel said,"], ["Tatou sosola ia,", "Let us flee,"], ["ia tosina ai i latou nai le aai i ala tele.", "and draw them from the city unto the highways."]]},
  {num:33,words:[["Ona tulai lea o tagata uma o Isaraelu ai le mea sa i ai,", "And all the men of Israel rose up out of their place,"], ["ua latou pae tau le taua i Paalatamara,", "and put themselves in array at Baal-tamar: and the liers in wait of Israel came forth out of their places,"], ["ma 'au a Isaraelu sa tanu ua feosofi mai i latou ai le mea sa i ai i le fanua o Kipea.", "even out of the meadows of Gibeah."]]},
  {num:34,words:[["Ona o ane lea e tau ma Kipea o tagata sili mai Isaraelu uma e sefulu afe,", "And there came against Gibeah ten thousand chosen men out of all Israel,"], ["ua tele lava le taua;", "and the battle was sore:"], ["a ua latou le iloa ua oo mai le malaia ia te i latou.", "but they knew not that evil was near them."]]},
  {num:35,words:[["Ua fasia Peniamina e Ieova i luma o Isaraelu;", "And the LORD smote Benjamin before Israel:"], ["ua faaumatia Peniamina e le fanauga a Isaraelu i lea aso, o tagata e luafulu o afe ma afe e lima ma le toaselau;", "and the children of Israel destroyed of the Benjamites that day twenty and five thousand and an hundred men:"], ["o i latou uma ia na fai pelu.", "all these drew the sword."]]},
  {num:36,words:[["Ona iloa lea e le fanauga a Peniamina ua fasia i latou;", "So the children of Benjamin saw that they were smitten:"], ["a ua tuumuli tagata o Isaraelu ia Peniamina,", "for the men of Israel gave place to the Benjamites,"], ["auā sa latou faalagolago i 'au na tanu i tala ane o Kipea.", "because they trusted unto the liers in wait which they had set beside Gibeah."]]},
  {num:37,words:[["Ona faataalise lea o 'au na tanu,", "And the liers in wait hasted,"], ["ua feosofi atu i Kipea;", "and rushed upon Gibeah;"], ["ua faasalalau 'au na tanu,", "and the liers in wait drew themselves along,"], ["ma latou fasia le aai uma i le pelu.", "and smote all the city with the edge of the sword."]]},
  {num:38,words:[["Sa fai le faailoga i tagata o Isaraelu ma e na tanu 'au;", "Now there was an appointed sign between the men of Israel and the liers in wait,"], ["latou te faamu ae le mu tele ma le asu nai le aai.", "that they should make a great flame with smoke rise up out of the city."]]},
  {num:39,words:[["Ua liu tua mai tagata o Isaraelu i le taua;", "And when the men of Israel retired in the battle,"], ["ona amata mai lea o Peniamina ona fafasi; ua manunua tagata o Isaraelu,", "Benjamin began to smite and kill of the men of Israel about thirty persons:"], ["pe atoa le toatolugafulu o tagata;", "for they said,"], ["auā na faapea ane i latou, E moni lava ua matuā fasia i latou i o tatou luma,", "Surely they are smitten down before us,"], ["e pei o le luai taua.", "as in the first battle."]]},
  {num:40,words:[["A ua amata ona alu ae le mumū o le afi nai le aai,", "But when the flame began to arise up out of the city with a pillar of smoke,"], ["o le asu faaniutu,", "the Benjamites looked behind them,"], ["ona fāliu atu lea i tua o Peniamina,", "and,"], ["faauta,", "behold,"], ["ua alu ae i le lagi le mu o le aai uma.", "the flame of the city ascended up to heaven."]]},
  {num:41,words:[["Ua toe liliu mai tagata o Isaraelu,", "And when the men of Israel turned again,"], ["ona faaatuatuvaleina lea o tagata o Peniamina; auā ua latou iloa,", "the men of Benjamin were amazed:"], ["ua oo ia i latou le malaia.", "for they saw that evil was come upon them."]]},
  {num:42,words:[["Ona liliu lea o i latou i luma o tagata o Isaraelu i le ala i le vao;", "Therefore they turned their backs before the men of Israel unto the way of the wilderness;"], ["a ua pipii atu le tuli ia te i latou;", "but the battle overtook them;"], ["o e sa i aai ua latou fafasi ia te i latou i o latou va.", "and them which came out of the cities they destroyed in the midst of them."]]},
  {num:43,words:[["Ua siomia Peniamina,", "Thus they inclosed the Benjamites round about,"], ["ma latou tulituliloa ia te i latou, ma soli ia i latou ma le faigofie,", "and chased them,"], ["e oo lava i Kipea i le itu e alu ae ai le la.", "and trode them down with ease over against Gibeah toward the sunrising."]]},
  {num:44,words:[["Ua fasia Peniamina e sefulu afe o tagata ma afe e valu;", "And there fell of Benjamin eighteen thousand men;"], ["o i latou nei o tagata totoa uma.", "all these were men of valour."]]},
  {num:45,words:[["Ona liliu lea ma sosola i latou i le vao i le papa o Rimoni;", "And they turned and fled toward the wilderness unto the rock of Rimmon:"], ["ua aoao i latou i ala tele e lima gaafe o tagata;", "and they gleaned of them in the highways five thousand men;"], ["ua tulituliloa ia i latou i Kitoma,", "and pursued hard after them unto Gidom,"], ["ma fafasi ai tagata e lua afe.", "and slew two thousand men of them."]]},
  {num:46,words:[["O i latou uma o Peniamina na fasia i lea lava aso, e luafulu o afe ma afe e lima,", "So that all which fell that day of Benjamin were twenty and five thousand men that drew the sword;"], ["o tagata na fai pelu; o i latou nei o tagata totoa uma.", "all these were men of valour."]]},
  {num:47,words:[["A o tagata e toaono galau na liliu i latou, ma sosola i le vao i le papa o Rimoni;", "But six hundred men turned and fled to the wilderness unto the rock Rimmon,"], ["ua latou nonofo i le papa o Rimoni i masina e fa.", "and abode in the rock Rimmon four months."]]},
  {num:48,words:[["Ua toe foi atu tagata o Isaraelu i le fanauga a Peniamina,", "And the men of Israel turned again upon the children of Benjamin,"], ["ma latou fasia i le pelu o tagata i aai,", "and smote them with the edge of the sword,"], ["atoa ma manu,", "as well the men of every city,"], ["ma mea uma na latou maua;", "as the beast,"], ["o aai uma foi ua latou oo i ai,", "and all that came to hand:"], ["ua latou faamuina i le afi.", "also they set on fire all the cities that they came to."]]},
];
renderVerseSet(jdg_ch_20_Verses, 'jdg-ch20-verses');

var jdg_ch_21_Verses = [
  {num:1,words:[["Na fai le tauto e tagata o Isaraelu i Mesepa,", "Now the men of Israel had sworn in Mizpeh,"], ["o loo faapea,", "saying,"], ["E leai so tatou e avatu lona afafine e fai ma avā i so sa Peniaminā.", "There shall not any of us give his daughter unto Benjamin to wife."]]},
  {num:2,words:[["Ona oo atu lea o le nuu i Peteli,", "And the people came to the house of God,"], ["ua latou nonofo ai i luma o le Atua,", "and abode there till even before God, and lifted up their voices,"], ["ua oo i le afiafi. Ona leo tetele ai lea i latou ma fetagisi i le tagi tele.", "and wept sore;"]]},
  {num:3,words:[["Ua latou fai atu,", "And said,"], ["Ieova e,", "O LORD God of Israel,"], ["le Atua o Isaraelu, pe se a le mea ua oo mai ai lenei mea ia Isaraelu,", "why is this come to pass in Israel,"], ["ina ua mavae atu le tasi itu aiga o Isaraelu i lenei aso?", "that there should be to day one tribe lacking in Israel?"]]},
  {num:4,words:[["Ona oo lea i le taeao ua ala usu le nuu,", "And it came to pass on the morrow,"], ["ua latou faia i lea mea le fata faitaulaga,", "that the people rose early, and built there an altar,"], ["ma avatu ai taulaga mu ma taulaga faafetai.", "and offered burnt offerings and peace offerings."]]},
  {num:5,words:[["Ua fai ane le fanauga a Isaraelu,", "And the children of Israel said,"], ["O ai ea so le au ituaiga uma o Isaraelu na le o ae ia Ieova i le faapotopotoga? Auā sa latou faia le tautoga mamafa i se na te le alu ae ia Ieova i Mesepa,", "Who is there among all the tribes of Israel that came not up with the congregation unto the LORD? For they had made a great oath concerning him that came not up to the LORD to Mizpeh,"], ["sa faapea,", "saying,"], ["E matuā fasiotia lava o ia.", "He shall surely be put to death."]]},
  {num:6,words:[["Ua salamo foi le fanauga a Isaraelu ona o Peniamina lo latou uso,", "And the children of Israel repented them for Benjamin their brother,"], ["ua latou faapea ane,", "and said,"], ["Ua vavaeeseina i lenei aso le tasi itu aiga nai ia Isaraelu;", "There is one tribe cut off from Israel this day."]]},
  {num:7,words:[["se a se mea tatou te faia ia maua avā mā e ua totoe? Auā ua tauto i tatou ia Ieova,", "How shall we do for wives for them that remain,"], ["e le avatu lava o tatou afafine e fai ma latou avā.", "seeing we have sworn by the LORD that we will not give them of our daughters to wives?"]]},
  {num:8,words:[["Ona fai ane ai lea o i latou,", "And they said,"], ["O ai so le au itu aiga o Isaraelu na le alu ae ia Ieova i Mesepa? Faauta foi,", "What one is there of the tribes of Israel that came not up to Mizpeh to the LORD? And, behold,"], ["e lei sau se tasi i le toagālauapi i le faapotopotoga mai Iapese-Kiliata.", "there came none to the camp from Jabesh-gilead to the assembly."]]},
  {num:9,words:[["Ona latou faitaulia lea o le nuu;", "For the people were numbered,"], ["faauta,", "and, behold,"], ["ua le i ai se tagata o e nonofo i Iapese-Kiliata.", "there were none of the inhabitants of Jabesh-gilead there."]]},
  {num:10,words:[["Ona aauina ai lea e le faapotopotoga o tagata e sefulu afe ma afe e lua o e totoa;", "And the congregation sent thither twelve thousand men of the valiantest,"], ["ua fai atu ia te i latou,", "and commanded them,"], ["o loo faapea, O ia,", "saying,"], ["ina outou fafasi i le pelu o e nonofo i Iapese-Kiliata,", "Go and smite the inhabitants of Jabesh-gilead with the edge of the sword,"], ["o fafine atoa ma tama iti;", "with the women and the children."]]},
  {num:11,words:[["a o lenei le mea tou te faia,", "And this is the thing that ye shall do,"], ["O tane uma,", "Ye shall utterly destroy every male,"], ["ma fafine uma ua tanea ia faaumatia i latou.", "and every woman that hath lain by man."]]},
  {num:12,words:[["Ua latou maua i e na nonofo i Iapese-Kiliata o teine taupou e toafa selau,", "And they found among the inhabitants of Jabesh-gilead four hundred young virgins,"], ["o e na le tanea;", "that had known no man by lying with any male: and they brought them unto the camp to Shiloh,"], ["ua latou aumaia i latou i le toagālauapi i Sailo i le nuu o Kanana.", "which is in the land of Canaan."]]},
  {num:13,words:[["Ona aau atu lea nisi e le faapotopotoga uma, ua tautalatala ma le fanauga a Peniamina,", "And the whole congregation sent some to speak to the children of Benjamin that were in the rock Rimmon,"], ["sa i le papa o Rimoni; na valaau ia i latou, ua ola le taua.", "and to call peaceably unto them."]]},
  {num:14,words:[["Ua toe foi Peniamina i ia ona aso,", "And Benjamin came again at that time;"], ["ona latou avatu lea o avā ia i latou e na faasaoina mai fafine o Iapese-Kiliata;", "and they gave them wives which they had saved alive of the women of Jabesh-gilead:"], ["a e lei tofu ai i latou.", "and yet so they sufficed them not."]]},
  {num:15,words:[["Ua salamo le nuu ona o Peniamina; auā ua lepetia e Ieova itu aiga o Isaraelu,", "And the people repented them for Benjamin,"], ["ua leai se tasi.", "because that the LORD had made a breach in the tribes of Israel."]]},
  {num:16,words:[["Ua fai ane toeaina o le faapotopotoga,", "Then the elders of the congregation said,"], ["Se a sa tatou mea e fai mo e totoe, ia maua avā,", "How shall we do for wives for them that remain,"], ["auā ua faaumatia fafine o Peniamina?", "seeing the women are destroyed out of Benjamin?"]]},
  {num:17,words:[["Ua fai ane,", "And they said,"], ["Ia faia lava le tofi mo e ua sao o Peniamina,", "There must be an inheritance for them that be escaped of Benjamin,"], ["ina ia le tineia se itu aiga o Isaraelu.", "that a tribe be not destroyed out of Israel."]]},
  {num:18,words:[["A o i tatou,", "Howbeit we may not give them wives of our daughters:"], ["tatou te le mafaia ona avatu ni o tatou afafine e fai mā latou avā,", "for the children of Israel have sworn,"], ["auā ua tauto le fanauga a Isaraelu, o loo faapea,", "saying,"], ["Ia malaia se na te avatu se avā ia Peniamina.", "Cursed be he that giveth a wife to Benjamin."]]},
  {num:19,words:[["Ona latou fai atu lea,", "Then they said,"], ["Faauta,", "Behold,"], ["o le tausamiga ia Ieova e faia i Sailo i lea tausaga ma lea tausaga, o loo i le itu i matu o Peteli,", "there is a feast of the LORD in Shiloh yearly in a place which is on the north side of Beth-el,"], ["i gagae o le ala tele e alu ae nai Peteli i Sekema,", "on the east side of the highway that goeth up from Beth-el to Shechem,"], ["ma le itu i toga o Lepona.", "and on the south of Lebonah."]]},
  {num:20,words:[["Ua latou fai atu i le fanauga a Peniamina,", "Therefore they commanded the children of Benjamin, saying,"], ["o loo faapea,", "Go and lie in wait in the vineyards;"]]},
  {num:21,words:[["O ia,", "And see,"], ["ina lamalama i tovine,", "and,"], ["ma outou vaavaai;", "behold,"], ["faauta foi, afai e o atu teine o Sailo e fai le siva,", "if the daughters of Shiloh come out to dance in dances,"], ["ona outou o atu lea ai tovine,", "then come ye out of the vineyards,"], ["ma outou toso mā outou ia taitasi ma lana avā ai teine o Sailo;", "and catch you every man his wife of the daughters of Shiloh,"], ["ona outou o lea i le nuu o Peniamina;", "and go to the land of Benjamin."]]},
  {num:22,words:[["afai foi e o mai ia te i matou o latou tamā,", "And it shall be,"], ["po o latou tuagane, e tagi mai ia te i matou,", "when their fathers or their brethren come unto us to complain,"], ["ona matou fai atu lea ia te i latou,", "that we will say unto them,"], ["Ia alofa ia i latou ona o i matou,", "Be favourable unto them for our sakes:"], ["auā na matou le faasao ni fafine i le taua,", "because we reserved not to each man his wife in the war:"], ["ia tofu le tagata ma lana avā; auā e le o outou na foai atu ai ia te i latou i nei ona po,", "for ye did not give unto them at this time,"], ["ina ne'i nofo sala ai outou.", "that ye should be guilty."]]},
  {num:23,words:[["Ua faia faapea le fanauga a Peniamina,", "And the children of Benjamin did so,"], ["ua latou fai mā latou avā e na sisiva,", "and took them wives,"], ["na latou toso e faatatau ma i latou;", "according to their number,"], ["ona latou o lea,", "of them that danced, whom they caught:"], ["ma foi atu i o latou lava nuu,", "and they went and returned unto their inheritance,"], ["ma latou faia o latou aai,", "and repaired the cities,"], ["ma latou nonofo ai.", "and dwelt in them."]]},
  {num:24,words:[["Ona o ai lea i ia ona aso o le fanauga a Isaraelu ai lea mea,", "And the children of Israel departed thence at that time,"], ["e taitasi i lona itu aiga ma lona aiga;", "every man to his tribe and to his family,"], ["ua latou o ese i lea mea e taitasi i lona tofi.", "and they went out from thence every man to his inheritance."]]},
  {num:25,words:[["O ia ona aso sa leai se tupu ia Isaraelu,", "In those days there was no king in Israel:"], ["ua taitasi ma fai le mea e tusa i lona lava manatu.", "every man did that which was right in his own eyes."]]},
];
renderVerseSet(jdg_ch_21_Verses, 'jdg-ch21-verses');

})();